/* techniques q14 (102 mục) — R6 sửa lỗi */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q14"]=window.__LIBQ["tien-nghich"]["q14"]||{};window.__LIBQ["tien-nghich"]["q14"]["techniques"]={"updatedAt":"2026-07-14","count":102,"techniques":[{"id":"vien-co-tien-thuat","name":"Viễn cổ tiên thuật","cn":"远古仙术","aliases":[],"loai":"than-thong","loaiLabel":"Tiên thuật","phamCap":"Không rõ (tiên thuật viễn cổ)","hePhai":"","soHuu":["Thanh Lâm"],"blurb":"Viễn cổ tiên thuật là tiên thuật do tiên đế Thanh Lâm thi triển, gọi tới ánh sáng viễn cổ có sức hủy diệt cực lớn, giết hàng loạt tu sĩ giới ngoại đồng thời phong kín Thất Thải Giới cùng vùng lân cận, ngăn thông hành giữa giới nội và giới ngoại.","detail":"Viễn cổ tiên thuật được tiên đế Thanh Lâm thi triển tại mốc @c1453, gọi tới ánh sáng viễn cổ nhắm vào tu sĩ giới ngoại. Ánh sáng này mang sức mạnh hủy diệt ở quy mô lớn, giết hàng loạt tu sĩ bước thứ ba đến từ giới ngoại. Ngoài tác dụng sát thương, tiên thuật còn phong kín nhiều Thất Thải Giới, khiến giới nội và giới ngoại tạm thời không thể thông hành. Tuy nhiên, ánh sáng viễn cổ không tồn tại vĩnh viễn — theo ghi nhận, giới ngoại sắp phá vỡ được lớp phong ấn này sau chín năm.","congNang":["Gọi ánh sáng viễn cổ giết tu sĩ giới ngoại hàng loạt, bao gồm tu sĩ bước thứ ba @c1453","Phong kín Thất Thải Giới và vùng lân cận, ngăn thông hành giữa giới nội và giới ngoại @c1453"],"nguoiTu":[{"ten":"Thanh Lâm","tuChuong":"@c1453","tangDatToi":"đại thành","trangThai":""}],"tabs":{"tienTrinh":[{"chuong":"@c1453","loai":"thi triển","importance":"major","giaiDoan":"Đại chiến thứ hai","text":"Tiên đế Thanh Lâm thi triển viễn cổ tiên thuật gọi ánh sáng viễn cổ, giết tu sĩ giới ngoại và phong kín Thất Thải Giới, cứu giới nội. Hiện ánh sáng sắp bị phá vỡ sau chín năm.","anchor":"tiên đế Thanh Lâm thi triển ra viễn cổ tiên thuật, gọi tới ánh sáng viễn cổ"}]},"nguon":["@c1453"],"uyLuc":"Ánh sáng viễn cổ hủy diệt hàng loạt tu sĩ bước thứ ba giới ngoại và phong kín nhiều Thất Thải Giới chỉ trong một lần thi triển."},{"id":"dong-xoay-phong-an-tu-chan-lien-minh","name":"Dòng xoáy phong ấn Tu Chân Liên Minh","cn":"","loai":"khac","loaiLabel":"Trận pháp cấm chế","phamCap":"Cấm chế truyền thừa thượng cổ","hePhai":"Tu Chân Liên Minh","soHuu":["Tu Chân Liên Minh"],"blurb":"Đạo phong ấn thứ nhất bảo vệ tổng bộ Tu Chân Liên Minh, trận pháp cấm chế truyền thừa từ thượng cổ có nguồn gốc Vũ Tiên giới, được hậu nhân không ngừng bổ sung thêm. Dòng xoáy khổng lồ liên tục hấp thu thiên địa nguyên lực tự cường hóa, năm xưa tu sĩ bước thứ ba liên thủ cũng chỉ làm chậm chứ không phá nổi, song cuối cùng bị Vương Lâm chỉ điểm một ngón tay dừng hẳn rồi xé nát.","detail":"Đạo phong ấn thứ nhất, cũng là đại môn thứ nhất của tổng bộ Tu Chân Liên Minh. Nguồn gốc truyền thừa từ thượng cổ, người của Tu Chân Liên Minh năm đó đạt được từ Vũ Tiên giới, qua nhiều đời hậu nhân không ngừng bổ sung hoàn thiện. Dòng xoáy phong ấn này mang hình thái dòng xoáy khổng lồ, một khi đã vận chuyển thì không thể đình chỉ, vì nó không ngừng hấp thu thiên địa nguyên lực để tự cường hóa. Năm xưa Lỗ Phu Tử cùng tu sĩ bước thứ ba Triệu Hà đồng thời ra tay cũng chỉ làm chậm được tốc độ xoáy chứ không thể phá vỡ, đủ thấy uy lực cấm chế cực cường của đạo phong ấn này. Tuy nhiên khi Vương Lâm tới tổng bộ Tu Chân Liên Minh, dòng xoáy phong ấn bị y chỉ điểm một ngón tay liền dừng hẳn, sau đó bị xé nát hoàn toàn. @c1454","thuocTinh":"Phong ấn, hấp thu nguyên lực","nguonGoc":"Truyền thừa từ thượng cổ, đạt được từ Vũ Tiên giới, hậu nhân bổ sung","uyLuc":"Năm xưa Lỗ Phu Tử cùng tu sĩ bước thứ ba Triệu Hà đồng thời ra tay cũng chỉ làm chậm chứ không thể phá vỡ; cuối cùng bị Vương Lâm chỉ điểm một ngón tay dừng hẳn rồi xé nát. @c1454","dacDiem":"Mang hình thái dòng xoáy khổng lồ, một khi đã vận chuyển thì không thể đình chỉ, không ngừng hấp thu thiên địa nguyên lực mà tự cường; nguồn gốc từ Vũ Tiên giới, qua nhiều đời hậu nhân bổ sung hoàn thiện.","congNang":["Phong ấn bảo vệ tổng bộ Tu Chân Liên Minh, đóng vai trò đại môn thứ nhất ngăn cản kẻ xâm nhập @c1454","Liên tục hấp thu thiên địa nguyên lực để tự cường hóa, một khi vận chuyển thì không thể đình chỉ @c1454"],"trangThai":"Đã bị Vương Lâm phá hủy","capNhatToi":"@c1454","tabs":{"tienTrinh":[{"chuong":"@c1454","loai":"xuất hiện","importance":"major","giaiDoan":"Bị phá hủy","text":"Dòng xoáy phong ấn tổng bộ Tu Chân Liên Minh bị Vương Lâm chỉ điểm một ngón tay dừng hẳn rồi xé nát, trận pháp cấm chế mà Lỗ Phu Tử cùng tu sĩ bước ba liên thủ không phá nổi bị phá vỡ hoàn toàn.","anchor":"là người của Tu Chân Liên Minh năm đó đạt được từ Vũ Tiên giới, sau đó hậu nhân còn không ngừng bổ xung"}]},"nguon":["@c1454"]},{"id":"thuat-than-ba-hac-long","name":"Thuật thần ba hắc long","cn":"","aliases":["Hương hỏa long"],"loai":"than-thong","loaiLabel":"Thần thông Không Linh","phamCap":"Nổi danh trong Thái Cổ Tinh Thần","hePhai":"","soHuu":["Thiên Triệu Thượng Sư"],"blurb":"Đòn sát thủ nổi danh của Thiên Triệu Thượng Sư, ngưng tụ hương hỏa lực thành ba con hắc long vạn trượng chứa hương hỏa giới, biến thành hương hỏa long.","detail":"Đòn sát thủ nổi danh của Thiên Triệu Thượng Sư trong Thái Cổ Tinh Thần. Ngưng tụ hương hỏa lực thành ba con hắc long dài vạn trượng, toàn thân gai nhọn, trán có sừng. Trong miệng mỗi con hắc long chứa một hương hỏa giới với vô số hương hỏa môn đồ ngồi dâng hương hỏa lực, biến chúng thành ba con hương hỏa long. Ba con hắc long là long thú thật bắt được từ nơi kỳ dị, tế luyện ngàn năm mới cúng bái hắn.","thuocTinh":"Hương hỏa lực","uyLuc":"Thuật thần tiếng tăm hiển hách trong Thái Cổ Tinh Thần, kết hợp long thú thật với hương hỏa lực","dacDiem":"Ba con hắc long thật sự được bắt từ nơi kỳ dị, tế luyện ngàn năm mới cúng bái, trong miệng chứa hương hỏa giới","congNang":["Đòn sát thủ kết hợp long thú thật + hương hỏa lực"],"nguoiTu":[{"ten":"Thiên Triệu Thượng Sư","tuChuong":"@c1454","tangDatToi":"","trangThai":"đang dùng"}],"capNhatToi":"@c1454","tabs":{"tienTrinh":[{"chuong":"@c1454","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Thiên Triệu Thượng Sư thi triển đòn sát thủ ba hắc long nghênh chiến Vương Lâm tại tổng bộ Tu Chân Liên Minh.","anchor":"là thuật thần tiếng tăm hiển hách trong Thái Cổ Tinh Thần"}]},"nguon":["@c1454"]},{"id":"kim-quang-tien-luc","name":"Kim quang (Tiên lực chính tông)","cn":"金光（仙力）","aliases":["Tiên lực"],"loai":"than-thong","loaiLabel":"Thần thông / Huyết mạch","phamCap":"Không rõ (tiên lực chính tông)","hePhai":"Tiên","soHuu":["Vương Lâm"],"blurb":"Kim quang là tiên lực chính tông nhất phát ra từ huyết mạch cao quý trên người Vương Lâm, biểu hiện dưới dạng kim quang tràn ngập tinh không qua đôi mắt. Mang uy áp linh hồn cấp chủng tộc, kim quang này khiến linh thú bái lạy và tu sĩ quỳ phục không thể phản kháng.","detail":"Kim quang nảy sinh từ huyết mạch cao quý tới cực điểm trên người Vương Lâm, là loại tiên lực được xác nhận chính tông nhất. Khi kích phát, hai mắt Vương Lâm lóe kim quang tràn ngập tinh không, kèm theo khí tức khiến thiên địa kinh hãi. Trong truyền thừa linh hồn của tộc hắc long, người sở hữu kim quang này đều là bá chủ thế giới chúng. Tại chương @c1455, Vương Lâm thi triển kim quang tiên lực từ hai mắt, khiến ba hương hỏa hắc long bái lạy, đồng thời hơn vạn tu sĩ giới ngoại bị uy áp linh hồn không chịu nổi, đồng loạt phun máu quỳ xuống. Đây là biểu hiện của uy áp linh hồn cấp chủng tộc, tác động trực tiếp lên bản năng nguyên thủy của linh thú lẫn tu sĩ.","congNang":["Uy áp linh hồn cấp chủng tộc, khiến linh thú (hắc long) bái lạy không dám phản kháng @c1455","Uy áp khiến hơn vạn tu sĩ giới ngoại đồng loạt phun máu quỳ xuống, không chịu nổi @c1455"],"thuocTinh":"Kim / Tiên","nguonGoc":"Huyết mạch cao quý trên người Vương Lâm","dacDiem":"Tiên lực chính tông nhất, phát ra qua hai mắt dưới dạng kim quang tràn ngập tinh không, nảy sinh từ huyết mạch cao quý tới cực điểm trên người Vương Lâm","tabs":{"tienTrinh":[{"chuong":"@c1455","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển toàn lực","text":"Vương Lâm phóng kim quang tiên lực từ hai mắt, tràn ngập tinh không, khiến ba hương hỏa hắc long bái lạy và hơn vạn tu sĩ giới ngoại quỳ phục.","anchor":"Đây chính là tiên lực chính tông nhất!"}]},"nguon":["@c1455"],"uyLuc":"Hơn vạn tu sĩ giới ngoại bị uy áp linh hồn không chịu nổi, đồng loạt phun máu quỳ xuống; ba hương hỏa hắc long bái lạy, khí tức khiến thiên địa kinh hãi @c1455"},{"id":"thien-hoang-lo","name":"Thiên Hoàng Lô","cn":"天凰爐","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông / Pháp bảo biến hóa","phamCap":"Tiên cấp","hePhai":"Tiên / Hỏa","soHuu":["Vương Lâm"],"blurb":"Ngọn lửa màu vàng từ mắt trái Vương Lâm hóa biển lửa, Thiên Hoàng Lô biến ảo ra rồi thiêu hủy nguyên thần đối thủ, uy lực đủ diệt tu sĩ Không Linh.","detail":"Ngọn lửa màu vàng từ mắt trái Vương Lâm bừng bừng thiêu đốt, hóa thành biển lửa bao phủ Thiên Triệu Thượng Sư. Thiên Hoàng Lô biến ảo ra, lóe lên rồi tan thành mây khói, thiêu hủy nguyên thần đối thủ.","congNang":["Thiêu hủy nguyên thần, diệt tu sĩ Không Linh"],"tabs":{"tienTrinh":[{"chuong":"@c1455","loai":"thi triển","importance":"normal","giaiDoan":"Thiêu hủy Thiên Triệu Thượng Sư","text":"Vương Lâm phóng ngọn lửa màu vàng từ mắt trái, Thiên Hoàng Lô biến ảo ra rồi tan thành mây khói, thiêu hủy nguyên thần Thiên Triệu Thượng Sư.","anchor":"Thiên Hoàng Lô liền biến ảo ra, lóe lên rồi tan thành mây khói!"}]},"nguon":["@c1455"]},{"id":"tran-phap-tu-chan-tinh","name":"Trận pháp tu chân tinh (cửa lớn thứ hai Tu Chân Liên Minh)","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Tu Chân Liên Minh","soHuu":["Long Bàn Tử"],"blurb":"Trận pháp tu chân tinh là cửa lớn thứ hai của Tu Chân Liên Minh, do Long Bàn Tử sáng tạo, lấy tu chân tinh tổng bộ kết hợp mấy chục tinh cầu nhỏ xung quanh tạo thành trận pháp tương trợ. Uy lực của trận pháp này vượt qua cả cơn lốc xoáy vạn cổ — cửa lớn thứ nhất của Liên Minh.","detail":"Long Bàn Tử năm đó thi triển thần thông, biến tu chân tinh tổng bộ thành trận pháp thứ hai của Tu Chân Liên Minh. Cấm chế cực kỳ xảo diệu, lấy mấy chục tinh cầu nhỏ xung quanh tạo thành trận pháp tương trợ lẫn nhau, khiến tu chân tinh có thể tu hành. Khi kích hoạt, các tinh cầu nhỏ xếp hai hàng tạo thành hình người khổng lồ, phát ra lực tấn công khuếch tán. Uy lực vượt qua cả cơn lốc xoáy vạn cổ (cửa lớn thứ nhất). Long Bàn Tử dung hợp nguyên thần làm tinh hồn để điều khiển toàn bộ trận pháp. Vương Lâm phát hiện sự tồn tại của cửa lớn thứ hai này khi tiếp cận tu chân tinh tổng bộ @c1456.","nguonGoc":"Long Bàn Tử sáng tạo","congNang":["Phòng thủ tổng bộ Tu Chân Liên Minh, đóng vai trò cửa lớn thứ hai @c1456","Mấy chục tinh cầu nhỏ xung quanh tương trợ tạo thành trận pháp, uy lực vượt cơn lốc xoáy vạn cổ (cửa lớn thứ nhất)","Tinh cầu nhờ trận pháp mà có thể tu hành","Khi kích hoạt, các tinh cầu nhỏ xếp hai hàng tạo thành hình người khổng lồ, phát ra lực tấn công khuếch tán","Long Bàn Tử dung hợp nguyên thần làm tinh hồn điều khiển toàn bộ trận pháp"],"nguoiTu":[{"ten":"Long Bàn Tử","tuChuong":"@c1456","tangDatToi":"Đại thành","trangThai":"tinh-hon"}],"tabs":{"tienTrinh":[{"chuong":"@c1456","loai":"xuat-hien","importance":"major","giaiDoan":"Lộ diện và bị tấn công","text":"Vương Lâm phát hiện cửa lớn thứ hai của Tu Chân Liên Minh — tu chân tinh rất lớn kết hợp mấy chục tinh cầu nhỏ tạo trận pháp. Sai con hắc long thứ ba lao vào phá trận, gây nứt vỡ tu chân tinh, khiến Long Bàn Tử (tinh hồn) thức tỉnh.","anchor":"Cấm chế này cực kỳ xảo diệu, nó lấy mấy chục tinh cầu nhỏ xung quanh để tạo thành trận pháp"}]},"nguon":["@c1456"],"uyLuc":"Uy lực vượt qua cả cơn lốc xoáy vạn cổ — cửa lớn thứ nhất của Tu Chân Liên Minh.","dacDiem":"Cấm chế cực kỳ xảo diệu, lấy tu chân tinh tổng bộ làm trung tâm, kết hợp mấy chục tinh cầu nhỏ xung quanh thành trận pháp tương trợ; khi kích hoạt các tinh cầu xếp thành hình người khổng lồ; do Long Bàn Tử dung hợp nguyên thần làm tinh hồn trực tiếp điều khiển."},{"id":"nguyen-than-dung-hop-tu-chan-tinh","name":"Nguyên thần dung hợp tu chân tinh (phương pháp của Long Bàn Tử)","cn":"","loai":"bi-thuat","loaiLabel":"Bí pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Long Bàn Tử"],"blurb":"Nguyên thần dung hợp tu chân tinh là phương pháp do Long Bàn Tử thực hiện khi tuổi thọ sắp hết, đem nguyên thần dung hợp cùng tu chân tinh tổng bộ Tu Chân Liên Minh để tế luyện, biến bản thân thành tinh hồn vạn cổ bất diệt. Vương Lâm nhận định đây là phương pháp đoạt tạo hóa thiên địa, cần trí tuệ cực lớn và sự táo bạo phi thường.","detail":"Khi tuổi thọ sắp cạn kiệt, Long Bàn Tử đã đem nguyên thần của mình dung hợp với tu chân tinh — tinh cầu tổng bộ của Tu Chân Liên Minh — để cùng tế luyện, thực chất là chiếm cứ thân xác tinh cầu, biến mình thành tinh hồn của nó. Nhờ vậy, Long Bàn Tử đạt được trạng thái hồn phách vạn cổ bất diệt ở một mức độ nhất định. Vương Lâm khi đoán ra phương pháp này đã nhận định rằng đây là cách đoạt tạo hóa thiên địa, đòi hỏi trí tuệ cực lớn và sự táo bạo phi thường mới dám nghĩ tới và thực hiện. Sự kiện này được hé lộ tại @c1456.","congNang":["Biến bản thân thành tinh hồn vạn cổ bất diệt thông qua dung hợp nguyên thần với tu chân tinh @c1456","Đoạt tạo hóa thiên địa, chiếm cứ thân xác tinh cầu làm thể xác cho mình @c1456"],"nguoiTu":[{"ten":"Long Bàn Tử","tuChuong":"@c1456","tangDatToi":"Đại thành","trangThai":"tinh-hon"}],"tabs":{"tienTrinh":[{"chuong":"@c1456","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Vương Lâm đoán ra bản chất","text":"Vương Lâm đoán ra Long Bàn Tử đã dung hợp nguyên thần với tu chân tinh khi tuổi thọ hết, trở thành tinh hồn vạn cổ bất diệt, trong lòng nổi lên kính nể trước trí tuệ và sự táo bạo.","anchor":"Đem nguyên thần của bản thân dung hợp với tu chân tinh để cùng tế luyện, giống như là chiếm cứ"}]},"nguon":["@c1456"]},{"id":"huyet-mach-than-thong-hoang-toc-tien","name":"Huyết mạch thần thông (hoàng tộc tiên)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Tiên nhân","soHuu":[],"blurb":"Tiên nhân huyết mạch tinh thuần khiến người ngoài chỉ cảm nhận được tiên khí nhưng không tìm được vị trí cụ thể. Huyết mạch càng tinh thuần càng khó bị phát hiện.","detail":"Huyết mạch hoàng tộc tiên La Huyền Thiên Địa có màu vàng, tu vi tương đương thất phẩm tiên nhân phát ra tiên khí rất tinh thuần.","congNang":["Ẩn giấu vị trí, người ngoài chỉ cảm nhận tiên khí mà không định vị được"],"dacDiem":"Tiên nhân cửu phẩm, La Huyền Thiên Địa có màu vàng","tabs":{"tienTrinh":[{"chuong":"@c1458","loai":"xuất hiện","importance":"normal","giaiDoan":"Chiến lão quỷ cảm nhận tiên khí","text":"Chiến lão quỷ cảm nhận tiên khí hoàng tộc tiên La Huyền Thiên Địa màu vàng, nhận định tu vi tương đương thất phẩm tiên nhân.","anchor":"Tiên nhân có huyết mạch càng tinh thuần, thì càng khó bị người khác tìm được"}]},"nguon":["@c1458"]},{"id":"tran-phap-muoi-van-ngon-nui","name":"Trận pháp mười vạn ngọn núi","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Trận pháp khổng lồ bên trong Thất Thải Giới do gần mười vạn ngọn núi tạo thành, thực chất là những cái gai trên lưng Huyền Vũ hóa đá. Trên mỗi đỉnh núi giam cầm một tu sĩ bị đá nhọn xuyên thân, máu chảy bốc thành khói hồng truyền về ngọn núi trung tâm.","detail":"Gần mười vạn ngọn núi lớn bên trong Thất Thải Giới được bố trí thành trận pháp, càng vào sâu núi càng hùng tráng, chỗ sâu nhất là ngọn núi cao tới trời bị mây mù bảy màu bao quanh. Bản chất các ngọn núi này là gai trên lưng Huyền Vũ hóa đá. Mỗi đỉnh núi giam cầm một tu sĩ bị đá nhọn xuyên thân, ngẩng đầu rên la thống khổ, máu tươi chảy theo đá xuống chân núi rồi bốc thành khói hồng bay về ngọn núi sâu nhất. Khi có người sống bước vào, cấm chế tự động kích hoạt, mười vạn tu sĩ dồn ánh mắt oán khí rít gào rồi đồng loạt phun máu tạo sương máu tràn ngập.","congNang":["Giam cầm tu sĩ trên mỗi đỉnh núi bằng đá nhọn xuyên thân, hút máu dung hợp thành khí truyền về ngọn núi trung tâm của trận pháp @c1460","Cấm chế tự động kích hoạt khi có người sống xâm nhập: mười vạn tu sĩ đồng loạt phun máu tạo sương máu tràn ngập @c1460"],"tabs":{"tienTrinh":[{"chuong":"@c1460","loai":"xuất hiện","importance":"major","giaiDoan":"Vương Lâm phát hiện trận pháp khi vào Thất Thải Giới lần hai","text":"Gần mười vạn ngọn núi tạo thành trận pháp khổng lồ, thực chất là gai trên lưng Huyền Vũ hóa đá. Mười vạn tu sĩ bị giam trên đỉnh núi, máu chảy bốc khói hồng truyền về trung tâm. Cấm chế kích hoạt khi Vương Lâm bước vào.","anchor":"mỗi một ngọn núi đều lả một phẩn của trận pháp kia càng vào chỗ sâu những ngọn núi này lại càng hùng tráng đến cực điểm"}]},"nguon":["@c1460"]},{"id":"tran-phap-huyen-vu-tran-hon","name":"Trận pháp Huyền Vũ trấn hồn","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Trận pháp Huyền Vũ trấn hồn lấy Huyền Vũ hóa đá làm mấu chốt, dùng mười cây cọc xuyên qua gai Huyền Vũ để trấn áp hồn phách Thanh Thủy, đồng thời vận hành vòng lặp ký ức tuần hoàn tàn khốc nhằm kích thích sát lục bổn nguyên trong cơ thể hắn dần thực chất hóa.","detail":"Trận pháp được Vương Lâm nhận diện khi quan sát Huyền Vũ hóa đá — trung tâm vận hành toàn bộ trận. Mười cây cọc xuyên qua gai trên thân Huyền Vũ hóa đá, ghim trấn mười vạn tu sĩ; nếu không phá hủy được Huyền Vũ thì không thể gỡ cọc. Trận pháp đồng thời sở hữu một sức mạnh mờ ám, liên tục tuần hoàn những ký ức đau thương quá khứ của Thanh Thủy, khiến hắn vĩnh viễn chìm trong trạng thái chém giết, điên cuồng và bi ai. Mục đích cuối cùng của vòng lặp ký ức này là kích thích sát lục bổn nguyên bên trong cơ thể Thanh Thủy, thúc đẩy nó thực chất hóa. @c1462","congNang":["Trấn áp hồn phách Thanh Thủy thông qua Huyền Vũ hóa đá làm mấu chốt, mười cây cọc xuyên gai Huyền Vũ ghim mười vạn tu sĩ; không phá Huyền Vũ thì không gỡ được cọc @c1462","Tuần hoàn ký ức tàn khốc quá khứ của Thanh Thủy, khiến hắn vĩnh viễn chìm trong chém giết, điên cuồng và bi ai, nhằm kích thích sát lục bổn nguyên trong cơ thể hắn dần thực chất hóa @c1462"],"tabs":{"tienTrinh":[{"chuong":"@c1462","loai":"xuất hiện","importance":"major","giaiDoan":"Bản chất được Vương Lâm nhận ra","text":"Vương Lâm nhận ra Huyền Vũ hóa đá là mấu chốt trận pháp trấn áp hồn phách Thanh Thủy. Sức mạnh mờ ám dùng vòng lặp ký ức tuần hoàn kích thích sát lục bổn nguyên dần thực chất hóa.","anchor":"muốn khiến cho hắn vĩnh viễn bị bao phủ bởi sự chém giết, điên cuồng, và bi ai"}]},"nguon":["@c1462"]},{"id":"kim-hoa-tien-hoa","name":"Kim hỏa tiên hóa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Tiên hóa","hePhai":"Hư hỏa","soHuu":["Vương Lâm"],"blurb":"Kim hỏa của Vương Lâm đã tiên hóa thành màu vàng, uy lực so với trận Vân Hải năm xưa mạnh vô số lần. Tuy nhiên không hiệu quả đốt tử thi vì hư hỏa cần người sống mới bùng lên trong cơ thể.","detail":"Ngọn lửa đã thành màu vàng sau khi tiên hóa, uy lực cháy rất lớn. Đặc điểm cốt lõi của hư hỏa là cần người sống để bùng lên từ bên trong cơ thể, do đó không có tác dụng đặc biệt với tử thi bị thao túng.","congNang":["Hỏa công tiên hóa, uy lực gấp bội so với trước @c1462","Không hiệu quả với tử thi vì hư hỏa cần người sống @c1462"],"tabs":{"tienTrinh":[{"chuong":"@c1462","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển chống mười vạn tu sĩ tử thi","text":"Vương Lâm thi triển kim hỏa đã tiên hóa màu vàng, uy lực so với trận Vân Hải mạnh vô số lần, nhưng không hiệu quả đốt tử thi bị thao túng.","anchor":"uy lực ngọn lửa đã trở thành tiên hóa kia của Vương Lâm so với năm đó trên chiến trường ở Vân Hải đã hùng mạnh hơn vô số lần"}]},"nguon":["@c1462"]},{"id":"ba-dao-bon-nguyen-vuong-lam","name":"Ba đạo bổn nguyên của Vương Lâm","cn":"","loai":"cong-phap","loaiLabel":"Bổn nguyên","phamCap":"Bước thứ ba (chưa đại thành)","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ba đạo bổn nguyên sinh tử, nhân quả, thật giả mà Vương Lâm phải đại thành để bước thứ ba. Hiện đã có hai đạo quả, cần thêm một đạo nữa.","detail":"Vương Lâm tự nhận ba đạo bổn nguyên sinh tử, nhân quả, thật giả phải đại thành mới có thể bước thứ ba. Tính tới chương 1467, hắn đã có hai đạo quả, chỉ cần thêm một đạo quả nữa là nắm chắc khả năng thành công.","congNang":["Ba đạo bổn nguyên đại thành là điều kiện đột phá bước thứ ba"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1467","tangDatToi":"2/3 đạo quả","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1467","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Vương Lâm tự nhận tiến trình hai đạo quả","text":"Vương Lâm tự nhận ba đạo bổn nguyên sinh tử, nhân quả, thật giả phải đại thành, hiện đã có hai đạo quả, cần thêm một đạo nữa để bước thứ ba.","anchor":"Sinh tử, nhân quả, thật giả, ba đạo bổn nguyên của ta phải đại thành"}]},"capNhatToi":"@c1467","nguon":["@c1467"]},{"id":"bach-pham-thuat-am-nguyet","name":"Bạch Phàm Thuật — Âm Nguyệt","cn":"白凡术·阴月","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Bạch Phàm Thuật (tam trọng lục đạo thuật)","soHuu":["Thanh Thủy"],"blurb":"Âm Nguyệt là thần thông thuộc tam trọng lục đạo thuật do Bạch Phàm sáng tạo, được Thanh Thủy thi triển trong Thất Thải Giới. Thuật này điểm chỉ từ xa khiến khuôn mặt đối phương xuất hiện biểu tượng vầng trăng, phối hợp cùng Hữu Tình để gây sát thương nội ngoại.","detail":"Âm Nguyệt là một trong các chiêu thức thuộc hệ thống tam trọng lục đạo thuật do Bạch Phàm sáng tạo. Tại Thất Thải Giới, Thanh Thủy đã thi triển thuật này nhắm vào Điện chủ Thiên Phạt Điện: điểm chỉ từ xa khiến trên khuôn mặt đối phương xuất hiện biểu tượng hình tròn — một vầng trăng bao phủ bởi âm vân dày đặc. Âm Nguyệt không phải chiêu thức đơn lẻ mà là bước mở đầu trong tổ hợp Âm Nguyệt – Hữu Tình: vầng trăng tạo ra mục tiêu cố định trên thân đối phương, để Hữu Tình dùng ánh mặt trời phá sụp, gây sát thương nặng nề. @c1469","thuocTinh":"Âm","nguonGoc":"Bạch Phàm sáng tạo, thuộc tam trọng lục đạo thuật","nguoiTu":[{"ten":"Thanh Thủy","tuChuong":"@c1469","trangThai":"dang-tu"}],"congNang":["Điểm chỉ từ xa khiến khuôn mặt đối phương xuất hiện biểu tượng vầng trăng bao phủ bởi âm vân dày đặc @c1469","Phối hợp cùng Hữu Tình tạo tổ hợp tấn công: vầng trăng làm mục tiêu cố định để Hữu Tình dùng ánh mặt trời phá hủy, gây sát thương nội ngoại @c1469"],"tabs":{"tienTrinh":[{"chuong":"@c1469","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Thanh Thủy thi triển Âm Nguyệt trong Thất Thải Giới, điểm chỉ khiến khuôn mặt Điện chủ Thiên Phạt Điện xuất hiện biểu tượng vầng trăng, phối hợp với Hữu Tình đánh trọng thương Điện chủ.","anchor":"trong nháy mắt khi nó xuất hiện, trên mặt lão già mặc hắc y không ngờ lại xuất hiện một biểu tượng hình tròn"}]},"nguon":["@c1469"]},{"id":"bach-pham-thuat-huu-tinh","name":"Bạch Phàm Thuật — Hữu Tình","cn":"白凡术·有情","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Bạch Phàm Thuật (tam trọng lục đạo thuật)","soHuu":["Thanh Thủy"],"blurb":"Hữu Tình là thần thông thuộc tam trọng lục đạo thuật do Bạch Phàm sáng tạo, được thi triển nối tiếp sau Âm Nguyệt. Thuật này dùng ánh mặt trời phá hủy vầng trăng đã tạo trên mặt đối phương, gây sát thương nội ngoại cực kỳ nghiêm trọng.","detail":"Hữu Tình là chiêu thức thứ hai trong cặp phối hợp với Âm Nguyệt, đều nằm trong hệ thống tam trọng lục đạo thuật của Bạch Phàm. Sau khi Âm Nguyệt tạo ra vầng trăng trên khuôn mặt đối phương, Hữu Tình được thi triển tiếp để triệu ánh sáng vạn trượng tựa mặt trời bùng lên, phá sụp vầng trăng ấy. Thanh Thủy từng sử dụng liên hoàn hai thuật này đánh vào Điện chủ Thiên Phạt Điện, khiến khuôn mặt hắn xuất hiện năm vết rách sâu, ánh mặt trời từ bên trong các vết rách lóe ra rồi lan tràn khắp thân thể, gây sát thương kinh khủng.","thuocTinh":"Dương","nguonGoc":"Bạch Phàm sáng tạo, thuộc tam trọng lục đạo thuật","nguoiTu":[{"ten":"Thanh Thủy","tuChuong":"@c1469","trangThai":"dang-tu"}],"congNang":["Triệu ánh sáng vạn trượng như mặt trời bùng lên, phá sụp vầng trăng do Âm Nguyệt tạo trên mặt đối phương @c1469","Gây vết rách sâu trên khuôn mặt mục tiêu, ánh mặt trời từ bên trong vết rách lóe ra lan tràn khắp thân thể, tạo sát thương nội ngoại nghiêm trọng @c1469"],"tabs":{"tienTrinh":[{"chuong":"@c1469","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Thanh Thủy thi triển Hữu Tình sau Âm Nguyệt, ánh mặt trời bùng lên phá sụp vầng trăng trên mặt Điện chủ, gây năm vết rách sâu với ánh mặt trời lóe ra bên trong.","anchor":"Bạch Phàm Thuật! Đây là tam trọng lục đạo thuật của Bạch Phàm"}]},"nguon":["@c1469"],"uyLuc":"Thi triển lên Điện chủ Thiên Phạt Điện, gây năm vết rách sâu trên khuôn mặt, ánh mặt trời từ bên trong lóe ra lan tràn khắp thân thể, sát thương kinh khủng.","dacDiem":"Phải thi triển nối tiếp sau Âm Nguyệt; lấy ánh mặt trời khắc chế vầng trăng, hình thành cặp chiêu thức âm dương tương phá."},{"id":"tran-phap-bao-ve-chu-tuoc-tinh","name":"Trận pháp bảo vệ Chu Tước Tinh","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Trận pháp mênh mông bao quanh Chu Tước Tinh, tràn ngập tám phương, luôn vận chuyển tạo gợn sóng rung động truyền khắp tinh không. Được bố trí vài thập niên gần đây.","detail":"Trận pháp bảo vệ bên ngoài Chu Tước Tinh, bao phủ tám phương, luôn vận chuyển tạo gợn sóng rung động lan truyền trong tinh không. Được bố trí chưa lâu (vài thập niên), lúc Vương Lâm ra đi chưa có. Có hai hư ảnh lão già canh giữ, kiểm soát ra vào, mở cầu thang mây cho tu sĩ đã tuân thủ quy củ (không mang đi, không phá hủy, chỉ thăm thú).","congNang":["Bảo vệ Chu Tước Tinh, kiểm soát ra vào, tạo gợn sóng rung động truyền khắp tinh không"],"tabs":{"tienTrinh":[{"chuong":"@c1475","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm phát hiện khi trở về","text":"Vương Lâm trở về phát hiện trận pháp mênh mông bao quanh Chu Tước Tinh, tràn ngập tám phương, lúc hắn ra đi chưa có.","anchor":"bên ngoài tu chân tinh này còn có một trận pháp mênh mông, tràn ngập tám phương, lúc nào cũng vận chuyển"}]},"nguon":["@c1475"]},{"id":"tran-phap-hao-quang-bao-ve-trieu-quoc","name":"Trận pháp hào quang bảo vệ Triệu Quốc","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":["Chu Vũ Thái"],"blurb":"Hào quang hình tròn bao quanh toàn bộ Triệu Quốc, ngăn cản mọi tu sĩ bên ngoài tiến vào, do Chu Vũ Thái yêu cầu thiết lập khi cải tạo Chu Tước Tinh.","detail":"Trận pháp tạo thành vòng hào quang hình tròn tràn ngập khắp bốn phía Triệu Quốc, biến nơi đây thành khu vực duy nhất trên Chu Tước Tinh không ai được phép bước vào — không được động tới một cây cỏ. Đây là yêu cầu kiên quyết do Chu Vũ Thái đưa ra với tư cách người đứng đầu Chu Tước Tinh. Toàn bộ tu sĩ đại thần thông và cửu đại tông môn trên Chu Tước Tinh đều có thể cảm ứng khi trận pháp bị xâm phạm. Vương Lâm dùng lực vô hình như hai bàn tay tách trận pháp mở lỗ hổng lớn bước vào, kinh động toàn bộ cường giả trên tinh cầu.","nguon":["@c1476"]},{"id":"hon-truyen-tong-tran","name":"Hồn Truyền Tống Trận","cn":"魂传送阵","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Cần tu sĩ Tịnh Niết hậu kỳ đại viên mãn trở lên mới bố trí","hePhai":"","soHuu":["Sư tôn Hồng Điệp"],"blurb":"Hồn Truyền Tống Trận là trận pháp truyền tống phần hồn phách, được phát hiện tại vùng Tuyết Vực Quốc đã tiêu tan. Rộng mười trượng, bao phủ hàn băng màu lam, trung tâm chứa đám tóc đen của Hồng Điệp đóng băng, hiện được Chu Vũ Thái na di về động phủ pho tượng Chu Tước bảo quản.","detail":"Trận pháp bí ẩn do sư tôn Hồng Điệp phong ấn tại vùng Tuyết Vực Quốc, nhưng người thực sự bố trí không rõ — bởi tu vi của Hồng Điệp không đủ để lập nên trận pháp cấp độ này, nguồn gốc thực sự vẫn còn là bí ẩn. Trận pháp đã đình trệ nhiều năm, tác dụng là từ phần hồn phách lưu trong đám tóc đen mà truyền tống phần hồn đến nơi khác, giúp Hồng Điệp lưu lại con đường sống trước khi bị mất mạng. Chu Vũ Thái dẫn Vương Lâm tới xem trận pháp trong thạch thất động phủ; khi Vương Lâm chạm vào, trận pháp loé sáng. Sau khi phân tích, Vương Lâm khẳng định cần tu sĩ Tịnh Niết hậu kỳ đại viên mãn trở lên mới bố trí được.","thuocTinh":"Truyền tống hồn phách","nguonGoc":"Được sư tôn Hồng Điệp phong ấn tại vùng Tuyết Vực Quốc, nhưng người thực sự bố trí không rõ","dacDiem":"Hàn băng màu lam bao phủ toàn bộ trận pháp, trung tâm có đám tóc đen đóng băng, diện tích rộng mười trượng.","congNang":["Truyền tống phần hồn phách từ đám tóc đen đóng băng ở trung tâm trận pháp đến nơi khác, giúp chủ nhân lưu lại con đường sống @c1478"],"uyLuc":"Cần tu sĩ Tịnh Niết hậu kỳ đại viên mãn trở lên mới có đủ khả năng bố trí, vượt xa tu vi của sư tôn Hồng Điệp.","trangThai":"Đã đình trệ nhiều năm, được Chu Vũ Thái na di bảo quản","tabs":{"tienTrinh":[{"chuong":"@c1478","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện và phân tích","text":"Chu Vũ Thái dẫn Vương Lâm tới xem trận pháp trong thạch thất động phủ. Vương Lâm chạm vào khiến loé sáng, phân tích nhận ra là Hồn Truyền Tống Trận — truyền tống phần hồn phách Hồng Điệp, kết luận nàng có thể chưa chết.","anchor":"Đây là một phần hồn truyền tống trận!"}]},"capNhatToi":"@c1478","nguon":["@c1478"]},{"id":"phuong-phap-mo-phong-an-tang-19-phu-van-toc","name":"Phương pháp mở phong ấn tầng 19 Phù Văn tộc","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Phù Văn tộc","soHuu":["Vương Lâm"],"blurb":"Cấm chế phong ấn do Phù Văn tộc đặt ra từ vạn năm trước nhằm niêm bế cánh cửa đá dẫn vào tầng 19, chỉ có thể mở bằng lực bài xích sinh ra khi tiên lực và cổ lực đối kháng trong cùng một cơ thể. Vương Lâm là người đã thi triển phương pháp này, chịu đau đớn cực hạn trong khoảng một nén nhang rưỡi để hoàn thành, phản lực tạo ra đủ mạnh phá vỡ Quang ảnh thuẫn và đẩy bật Thiên Hoàng Lô.","detail":"Ký hiệu phong ấn tầng 19 Phù Văn tộc có dạng vòng tròn, bản chất là sự dung hợp giữa tiên lực và khí tức Đạo Cổ — lực bài xích giữa hai nguồn năng lượng đối lập được chuyển hóa thành phong ấn. Phù Văn tộc thiết kế cấm chế này từ vạn năm trước với độ bền vững phi thường: dùng tiên lực hay cổ lực riêng lẻ hoàn toàn vô hiệu, thậm chí hủy diệt cả Chu Tước Tinh cũng không tổn thương được ký hiệu. Người muốn mở phong ấn phải đồng thời mang trong cơ thể cả tiên lực lẫn cổ lực, đẩy lực bài xích ra đầu ngón trỏ rồi vẽ theo hình vòng tròn lên cánh cửa đá. Quá trình thi triển cực kỳ đau đớn vì lực bài xích từ ký hiệu tràn ngược vào cơ thể người mở, xé nát kinh mạch. Tại @c1480, Vương Lâm đã chịu đựng đau đớn cực hạn trong khoảng một nén nhang rưỡi để hoàn thành phương pháp này, phản lực sinh ra khi h","thuocTinh":"Tiên lực + Đạo Cổ khí tức dung hợp","nguonGoc":"Phù Văn tộc đặt ra từ vạn năm trước","yeuCau":"Người mở phải đồng thời sở hữu tiên lực và cổ lực, sinh ra lực bài xích trong cơ thể","uyLuc":"Phản lực sinh ra khi hoàn thành phương pháp đủ sức phá vỡ Quang ảnh thuẫn và đẩy bật Thiên Hoàng Lô.","dacDiem":"Ký hiệu dạng vòng tròn, dùng tiên lực hay cổ lực riêng lẻ hoàn toàn vô hiệu, hủy diệt vật lý cũng không tổn thương được; người thi triển phải đồng thời mang cả tiên lực lẫn cổ lực trong cơ thể, quá trình mở phong ấn xé nát kinh mạch gây đau đớn cực hạn.","congNang":["Mở phong ấn cánh cửa đá dẫn vào tầng 19 Phù Văn tộc bằng cách dùng lực bài xích giữa tiên lực và cổ lực vẽ lại ký hiệu vòng tròn @c1480","Phản lực khi hoàn thành đủ mạnh phá vỡ Quang ảnh thuẫn và đẩy bật Thiên Hoàng Lô @c1480"],"trangThai":"Đã bị Vương Lâm phá giải","capNhatToi":"@c1480","tabs":{"tienTrinh":[{"chuong":"@c1480","loai":"thi triển","importance":"major","giaiDoan":"Vương Lâm phá giải phong ấn","text":"Vương Lâm dùng lực bài xích vẽ lại ký hiệu vòng tròn, chịu đau đớn cực hạn trong một nén nhang rưỡi, hoàn thành và mở cánh cửa đá sau vạn năm phong ấn.","anchor":"Nếu chỉ có dùng tiên lực thì không mở nổi, chỉ có cổ lực thì cũng không mở được"}]},"nguon":["@c1480"]},{"id":"vung-thien-dia-lam-quang","name":"Vùng thiên địa lam quang","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":["Thái Cổ Tinh Thần"],"blurb":"Vùng thiên địa lam quang là trận pháp do toàn bộ cao thủ Không Huyền Thái Cổ Tinh Thần liên thủ cùng Viễn Cổ Tiên Phi bố trí, phá vỡ hư vô tạo ra không gian riêng biệt nhằm vây khốn mục tiêu, cách ly hoàn toàn khỏi thế giới thật và áp chế tu vi kẻ bị nhốt bên trong.","detail":"Trận pháp được kích hoạt khi toàn bộ cao thủ của Không Huyền Thái Cổ Tinh Thần liên thủ cùng Viễn Cổ Tiên Phi ra tay, phá vỡ hư vô để tách mục tiêu — cụ thể là Vương Lâm — ra khỏi Chu Thiên, đưa vào một không gian riêng biệt. Bên trong vùng thiên địa lam quang, toàn bộ thiên địa nhuốm sắc lam, mặt đất là mặt nước phẳng lặng phản chiếu bầu trời, tạo nên cảnh tượng tựa cái giếng vô biên. Không gian này cách ly hoàn toàn với giới nội, không ai ở thế giới thật có thể phát hiện. Trận pháp tồn tại trong khoảng ba canh giờ và có khả năng áp chế tu vi của kẻ bị vây khốn: cao thủ cấp Không Huyền khi ở bên trong chỉ có thể phát huy được sức mạnh ngang mức Không Linh Trung Kỳ.","congNang":["Phá vỡ hư vô, tạo không gian riêng biệt tách mục tiêu ra khỏi thế giới thật để vây khốn @c1484","Cách ly hoàn toàn khỏi giới nội, khiến không ai ở thế giới thật có thể phát hiện @c1484","Áp chế tu vi kẻ bị nhốt bên trong — cao thủ Không Huyền chỉ phát huy được mức Không Linh Trung Kỳ @c1484"],"tabs":{"tienTrinh":[{"chuong":"@c1484","loai":"xuất hiện","importance":"major","giaiDoan":"Bố trí vây sát Phong Tôn tái thế","text":"Toàn bộ cao thủ Không Huyền Thái Cổ Tinh Thần liên thủ cùng Viễn Cổ Tiên Phi bố trí, tách Vương Lâm khỏi Chu Tước Tinh thật vào thiên địa lam quang tồn tại ba canh giờ.","anchor":"tất cả những cao thủ Không Huyền của Thái Cổ Tinh Thần ta liên thủ bố trí, còn có cả Viễn cổ Tiên Phi ra tay"}]},"capNhatToi":"@c1484","nguon":["@c1484"],"uyLuc":"Khiến cao thủ cấp Không Huyền bị áp chế tu vi xuống chỉ còn ngang mức Không Linh Trung Kỳ, đồng thời cách ly hoàn toàn mục tiêu khỏi thế giới thật trong ba canh giờ.","dacDiem":"Thiên địa toàn sắc lam, mặt đất là mặt nước phẳng lặng phản chiếu bầu trời, cảnh tượng tựa cái giếng vô biên; tồn tại trong khoảng ba canh giờ."},{"id":"dai-dia-bon-nguyen-tang-linh","name":"Đại địa bổn nguyên — Táng Linh","cn":"大地本源·葬灵","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Giới ngoại","soHuu":["Lão già áo xám"],"blurb":"Thần thông của lão già áo xám giới ngoại, dùng bùn đất tỏa vạn trượng bao phủ trời đất, hồn phách hương hỏa hóa hạt đất cát có thể hóa đất thân thể đối thủ.","detail":"Dùng chai bùn đất bóp vỡ, bùn đất vạn trượng bao phủ trời đất. Hồn phách hương hỏa hóa hạt đất cát bao phủ mục tiêu, có khả năng hóa đất thân thể địch. Phối hợp cùng Hồn Sát và Băng Động phá hủy hoàn toàn Dịch Linh Ấn của Vương Lâm.","congNang":["Bùn đất vạn trượng bao phủ trời đất","Hồn phách hương hỏa hóa hạt đất cát hóa đất thân thể đối thủ"],"nguoiTu":[{"ten":"Lão già áo xám","tuChuong":"@c1485","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1485","loai":"thi triển","importance":"normal","giaiDoan":"Lão già áo xám thi triển phá Dịch Linh Ấn","text":"Lão già áo xám bóp vỡ chai bùn đất, bùn đất vạn trượng bao phủ trời đất, hô khẩu quyết Đại địa bổn nguyên Táng Linh, phối hợp hai người kia phá hủy hoàn toàn Dịch Linh Ấn của Vương Lâm.","anchor":"Đại địa bổn nguyên, Táng Linh!"}]},"nguon":["@c1485"]},{"id":"bang-phong-van-co","name":"Băng Phong Vạn Cổ","cn":"冰封万古","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Nam tử áo trắng"],"blurb":"Băng Phong Vạn Cổ là thần thông lấy thọ nguyên làm đạo, lấy hồn phách băng tuyết làm bầu trời và hàn phong vô vi làm vật dẫn, có khả năng đóng băng toàn bộ thiên địa. Được nam tử bạch y — hình chiếu của Thái Cổ Tinh Thần — thi triển, thần thông này từng tạm phong ấn cả Phần Giới Cổ Tán nhưng cuối cùng bị Vương Lâm phá giải.","detail":"Băng Phong Vạn Cổ do nam tử bạch y (hình chiếu Thái Cổ Tinh Thần) thi triển. Khi kích phát, ký hiệu bông tuyết từ mi tâm được ném ra, biến toàn bộ mặt nước và bầu trời thành băng, vô số trụ băng nối liền trời đất, tạo thành phong ấn thiên địa quy mô cực lớn. Thần thông này đủ sức phong ấn cả Phần Giới Cổ Tán — một thần thông cấp diệt thế — chứng tỏ uy năng vượt khỏi phạm trù thông thường. Tuy nhiên, đại giá phải trả là tiêu hao thọ nguyên của người thi triển. Cuối cùng, Vương Lâm bơm sinh cơ vào Cổ Tán, phá vỡ toàn bộ tầng băng, hóa giải phong ấn.","congNang":["Đóng băng toàn bộ thiên địa — biến mặt nước và bầu trời thành băng, tạo vô số trụ băng nối trời đất @c1486","Phong ấn đối phương và cả thần thông cấp diệt thế, từng tạm phong ấn Phần Giới Cổ Tán @c1486"],"nguoiTu":[{"ten":"Nam tử áo trắng","tuChuong":"@c1486","tangDatToi":"","trangThai":"thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1486","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Nam tử bạch y thi triển Băng Phong Vạn Cổ đóng băng toàn bộ thiên địa và Phần Giới Cổ Tán, nhưng bị Vương Lâm bơm sinh cơ phá vỡ.","anchor":"Lấy thọ nguyên của lão phu làm đạo, lấy hồn phách băng tuyết làm bầu trời, lấy hàn phong vô vi làm vật dẫn"}]},"dinhDanh":"goc","capNhatToi":"@c1486","nguon":["@c1486"],"uyLuc":"Đủ sức đóng băng toàn bộ thiên địa và tạm phong ấn cả Phần Giới Cổ Tán — một thần thông cấp diệt thế — nhưng cuối cùng bị Vương Lâm bơm sinh cơ phá vỡ toàn bộ tầng băng.","dacDiem":"Lấy thọ nguyên làm đại giá để thi triển; ký hiệu bông tuyết phóng ra từ mi tâm là vật dẫn kích hoạt; quy mô phong ấn bao trùm cả thiên địa."},{"id":"ngu-tang-tien-dao","name":"Ngũ Tạng Tiên Đạo","cn":"五脏仙道","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Nữ tử bí ẩn (Ngũ Tạng Tiên Đạo)"],"blurb":"Ngũ Tạng Tiên Đạo là thần thông hủy diệt nội tạng đối phương, mỗi ngón tay tương ứng một trong năm tạng. Từng chiêu khiến tạng phủ héo rũ và hủy diệt, ngay cả lực khôi phục của Cổ thân cũng không thể phục hồi.","detail":"Ngũ Tạng Tiên Đạo do một nữ tử bí ẩn thi triển trong giao chiến với Vương Lâm. Thần thông gồm năm chiêu, mỗi chiêu ứng với một ngón tay và một tạng: ngón út ứng thận (thận suy nhi thương), ngón vô danh ứng phế (phế tử nhi chung), ngón giữa ứng tỳ (tỳ hội nhi hủ). Hai chiêu còn lại tương ứng can và tâm chưa được thi triển. Tại thời điểm ghi nhận, nữ tử đã sử dụng ba chiêu đầu nhắm vào thận, phế và tỳ của Vương Lâm, khiến nội tạng mục rữ theo từng bước, đồng thời phá vỡ khả năng tái sinh vốn có của Cổ thân.","congNang":["Hủy diệt nội tạng đối phương từng cái một thông qua năm ngón tay, mỗi ngón ứng một tạng @c1486","Phá vỡ khả năng tái sinh của Cổ thân, khiến tạng phủ bị hủy không thể tự phục hồi @c1486"],"nguoiTu":[{"ten":"Nữ tử bí ẩn (Ngũ Tạng Tiên Đạo)","tuChuong":"@c1486","tangDatToi":"","trangThai":"thi triển"}],"cacTang":[{"ten":"Thận (ngón út)","moTa":"Thận suy nhi thương — thận héo rũ hóa máu tiêu tan","chuong":"@c1486"},{"ten":"Phế (ngón vô danh)","moTa":"Phế tử nhi chung","chuong":"@c1486"},{"ten":"Tỳ (ngón giữa)","moTa":"Tỳ hội nhi hủ","chuong":"@c1486"}],"tabs":{"tienTrinh":[{"chuong":"@c1486","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Nữ tử bí ẩn thi triển ba trong năm chiêu Ngũ Tạng Tiên Đạo, phá hủy thận và nhắm vào phế, tỳ của Vương Lâm, lực khôi phục Cổ thân cũng bất lực.","anchor":"Ngũ tạng tiên đạo. Thứ nhất là thận. Thận suy nhi thương"}]},"dinhDanh":"goc","capNhatToi":"@c1486","nguon":["@c1486"],"uyLuc":"Khiến nội tạng đối phương héo rũ và hủy diệt từng cái một, ngay cả năng lực khôi phục đặc thù của Cổ thân cũng bị vô hiệu hóa hoàn toàn.","dacDiem":"Mỗi ngón tay tương ứng một tạng với một câu khẩu quyết riêng: ngón út — thận (thận suy nhi thương), ngón vô danh — phế (phế tử nhi chung), ngón giữa — tỳ (tỳ hội nhi hủ). Tấn công theo trình tự tuần tự, hủy diệt nội tạng từng bước."},{"id":"am-nguyet-huu-tinh","name":"Âm Nguyệt Hữu Tình","cn":"陰月有情","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Âm Nguyệt Tông","soHuu":["Vương Lâm","Thanh Thủy"],"blurb":"Thức khởi đầu trong ba thức thần thông của Âm Nguyệt Tông. Tạo vầng trăng sáng trên mặt đối thủ, gây khe nứt chảy máu hủy dung, thương tổn liên tục khuếch tán lan rộng, càng trì hoãn càng khó giải.","detail":"Âm Nguyệt Hữu Tình là thức thứ nhất trong bộ ba thần thông của Âm Nguyệt Tông, bản chất cực kỳ ác độc, không giết ngay mà gây thương tổn liên tục lan rộng trên gương mặt nạn nhân. Vương Lâm mô phỏng thần thông này từ Thanh Thủy, người từng thi triển nó trong Thất Thải Giới. Ba thức lần lượt là Âm Nguyệt Hữu Tình (khởi đầu), Âm Nguyệt Vô Vũ (thức hai), Âm Nguyệt Hàn Phong (thức ba) — phải biết cả ba thức mới có thể thoát chết. Bạch Phàm từng là phản đồ Âm Nguyệt Tông, nguồn gốc thần thông có liên quan tới tam trọng lục đạo thuật. Tại @c1487, Vương Lâm lần đầu thi triển Âm Nguyệt Hữu Tình lên một nữ tử tiên phi, vầng trăng sáng hiện trên mặt đối phương, khe nứt chảy máu xuất hiện.","thuocTinh":"Âm","nguonGoc":"Âm Nguyệt Tông","cacTang":[{"ten":"Âm Nguyệt Hữu Tình","moTa":"Thức khởi đầu, tạo vầng trăng hủy dung, thương tổn liên tục","chuong":"@c1487"},{"ten":"Âm Nguyệt Vô Vũ","moTa":"Thức thứ hai, chưa lộ chi tiết","chuong":"@c1487"},{"ten":"Âm Nguyệt Hàn Phong","moTa":"Thức thứ ba, chưa lộ chi tiết","chuong":"@c1487"}],"congNang":["Tạo vầng trăng sáng trên mặt đối thủ, gây khe nứt chảy máu hủy hoại dung mạo @c1487","Thương tổn liên tục khuếch tán lan rộng, càng trì hoãn càng khó giải @c1487"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1487","tangDatToi":"Thức 1 (khởi đầu)","trangThai":"dang-tu"},{"ten":"Thanh Thủy","tuChuong":"@c1487","tangDatToi":"Thành thục","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1487","loai":"thi triển","importance":"major","giaiDoan":"Vương Lâm lần đầu thi triển","text":"Vương Lâm lần đầu thi triển Âm Nguyệt Hữu Tình, vầng trăng sáng xuất hiện trên mặt nữ tử tiên phi, khe nứt chảy máu lan từ mặt xuống cổ, hủy dung hoàn toàn. Nữ tử nhận ra đây là thần thông Âm Nguyệt Tông, tiết lộ Bạch Phàm từng là phản đồ.","anchor":"Âm Nguyệt tông, thức thần thông khởi đầu"}]},"capNhatToi":"@c1487","nguon":["@c1487"]},{"id":"ngu-tang-ky-thuat","name":"Ngũ tạng kỳ thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Viễn Cổ Tiên Phi","soHuu":["Nữ tử tiên phi"],"blurb":"Ngũ tạng kỳ thuật là thần thông chuỗi năm thức, lần lượt phá hủy ngũ tạng đối phương (phế, tỳ, thận, can, tâm). Tại @c1487, nữ tử tiên phi hoàn tất thức thứ tư (can tạng vỡ nát) và thức thứ năm (tâm tạng hóa đá) lên Vương Lâm, khiến ngũ tạng mất bốn, sinh cơ gần như đoạn tuyệt.","detail":"Ngũ tạng kỳ thuật gồm năm thức tương ứng năm tạng theo thứ tự: Phế (phổi), Tỳ (lá lách), Thận, Can (gan), Tâm (tim). Mỗi thức khi đánh trúng sẽ phá hủy tạng phủ tương ứng bên trong cơ thể nạn nhân. Thức thứ tư — Can — khiến gan vỡ nát. Thức thứ năm — Tâm — khiến trái tim hóa đá, gọi là \"vô tâm vô đạo\". Khi hoàn tất cả năm thức, sinh cơ của đối phương bị chặt đứt hoàn toàn. Trong tiến trình, nữ tử tiên phi đã thi triển thuật này lên Vương Lâm, phá hủy can tạng và tâm tạng, đưa tổng số tạng bị mất lên bốn, sinh cơ của Vương Lâm gần như đoạn tuyệt (@c1487).","congNang":["Phá hủy lần lượt ngũ tạng đối phương theo trình tự: phế, tỳ, thận, can, tâm","Thức thứ tư Can — khiến gan vỡ nát (@c1487)","Thức thứ năm Tâm — trái tim hóa đá, trạng thái \"vô tâm vô đạo\" (@c1487)","Hoàn tất năm thức sẽ chặt đứt sinh cơ hoàn toàn"],"cacTang":[{"ten":"Thức 4 — Can","moTa":"Can hóa nhi toái, gan vỡ nát","chuong":"@c1487"},{"ten":"Thức 5 — Tâm","moTa":"Vô tâm vô đạo, trái tim hóa đá","chuong":"@c1487"}],"tabs":{"tienTrinh":[{"chuong":"@c1487","loai":"thi triển","importance":"major","giaiDoan":"Hoàn tất ngũ tạng","text":"Nữ tử tiên phi hoàn tất Ngũ tạng kỳ thuật — phá hủy can tạng và tâm tạng Vương Lâm. Ngũ tạng mất bốn, sinh cơ chặt đứt, Giới Cổ Tán tiêu tán hoàn toàn.","anchor":"Thứ năm là Tâm, vô tâm, vô đạo"}]},"capNhatToi":"@c1487","nguon":["@c1487"],"uyLuc":"Tại @c1487, ngũ tạng Vương Lâm mất bốn sau khi bị hoàn tất thức Can và thức Tâm, sinh cơ gần như đoạn tuyệt.","dacDiem":"Chuỗi năm thức đánh theo thứ tự ngũ tạng; mỗi thức phá một tạng phủ cụ thể bên trong cơ thể đối phương mà không cần tổn thương bên ngoài, thức cuối cùng — Tâm — khiến trái tim hóa đá."},{"id":"tang-hoang-tuyen","name":"Táng Hoàng Tuyền","cn":"葬黃泉","loai":"than-thong","loaiLabel":"Thần thông (khúc đàn)","phamCap":"Không rõ","hePhai":"Viễn Cổ Tiên Phi","soHuu":["Nữ tử tiên phi"],"blurb":"Khúc đàn thi triển bằng cổ cầm, tiếng đàn hóa sát khí kinh động đất trời, oanh kích tâm thần tạo ma niệm xé tan tinh thần đối thủ. Nữ tử tiên phi tuyên bố chỉ tiên tôn mới từng được nghe.","detail":"Nữ tử tiên phi biến ảo cổ cầm gảy khúc Táng Hoàng Tuyền. Tiếng đàn hóa sát khí, oanh kích tâm thần, tạo ma niệm. Uy lực đánh Vương Lâm lùi trăm trượng, thất khiếu chảy máu.","congNang":["Tiếng đàn hóa sát khí kinh động đất trời","Oanh kích tâm thần tạo ma niệm xé tan tinh thần"],"tabs":{"tienTrinh":[{"chuong":"@c1487","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển trước Vương Lâm","text":"Nữ tử tiên phi biến ảo cổ cầm gảy khúc Táng Hoàng Tuyền, tiếng đàn hóa sát khí oanh kích tâm thần Vương Lâm, đánh lùi trăm trượng thất khiếu chảy máu.","anchor":"Tiếng đàn của ta cũng chỉ có tiên tôn mới từng được nghe"}]},"capNhatToi":"@c1487","nguon":["@c1487"]},{"id":"thuat-boi-than-tien","name":"Thuật bói thần tiên","cn":"","loai":"than-thong","loaiLabel":"Thần thông (dự ngữ)","phamCap":"Không rõ","hePhai":"Viễn Cổ Tiên Phi","soHuu":["Nữ tử tử y"],"blurb":"Thuật bói thần tiên là pháp thuật bói toán của nữ tử tử y, dùng hồn làm vật dẫn để biến lời dự ngữ thành hiện thực. Được tuyên bố có thể bói cả thần tiên, tại @c1487 đã dự ngữ Vương Lâm trong ba nhịp thở phải tử vong.","detail":"Thuật bói thần tiên là bí thuật do nữ tử tử y thi triển. Cốt lõi của thuật này nằm ở chỗ lấy hồn phách làm vật dẫn, khi dự ngữ phát ra thì lời bói sẽ trở thành sự thật, mang tính cưỡng chế hiện thực hoá. Nữ tử tử y tuyên bố thuật bói này có thể bói cả thần tiên, cho thấy phạm vi hiệu lực không bị giới hạn bởi cảnh giới đối phương. Trong cuộc đối đầu tại @c1487, bà ta đã dùng thuật này dự ngữ Vương Lâm trong ba nhịp thở phải tử vong.","congNang":["Dự ngữ dùng hồn làm vật dẫn, biến lời bói thành hiện thực @c1487","Có thể bói cả thần tiên, không bị giới hạn bởi cảnh giới mục tiêu @c1487"],"tabs":{"tienTrinh":[{"chuong":"@c1487","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện, dự ngữ Vương Lâm","text":"Nữ tử tử y tuyên bố bói cả thần tiên, dự ngữ dùng hồn làm vật dẫn, đoán Vương Lâm trong ba nhịp thở phải tử vong.","anchor":"dự ngữ của ta là dùng hồn làm vật dẫn, lúc này sẽ trở thành sự thật"}]},"capNhatToi":"@c1487","nguon":["@c1487"],"uyLuc":"Dự ngữ Vương Lâm trong ba nhịp thở phải tử vong, lời bói mang tính cưỡng chế hiện thực hoá @c1487","dacDiem":"Lấy hồn phách làm vật dẫn cho dự ngữ; lời bói một khi phát ra sẽ trở thành sự thật, mang tính chất cưỡng chế định mệnh"},{"id":"son-bang-dia-liet","name":"Sơn Băng Địa Liệt","cn":"","loai":"than-thong","loaiLabel":"Thần thông (tiên thuật)","phamCap":"Không rõ","hePhai":"Bạch Phàm","soHuu":["Vương Lâm"],"blurb":"Biến thể tiên thuật của Sơn Băng kết hợp Địa Liệt thuật. Vương Lâm dung nhập tiên lực kim quang, biến ảo núi lửa khổng lồ nổ kinh thiên động địa. Vương Lâm chưa hoàn toàn nắm vững Địa Liệt nhưng bắt chước thi triển được.","detail":"Sơn Băng kết hợp Địa Liệt thuật, được dung nhập tiên lực kim quang trở thành tiên thuật. Vương Lâm chưa hoàn toàn hiểu rõ Địa Liệt thuật nhưng với tu vi hiện tại có thể bắt chước được.","congNang":["Biến ảo núi lửa khổng lồ bùng nổ kinh thiên động địa"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1487","tangDatToi":"Bắt chước (chưa nắm vững)","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1487","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển dạng tiên thuật","text":"Vương Lâm thi triển Sơn Băng Địa Liệt dưới dạng tiên thuật, biến ảo núi lửa nổ kinh thiên động địa, dù chưa hoàn toàn nắm vững Địa Liệt.","anchor":"Địa Liệt thuật Vương Lâm vẫn chưa hoàn toàn hiểu rõ nhưng lấy tu vi hắn lúc này vẫn có thể bắt chước được"}]},"capNhatToi":"@c1487","nguon":["@c1487"]},{"id":"bon-nguyen-thai-so-quy-tac","name":"Bổn nguyên Thái Sơ quy tắc","cn":"本源太初规则","loai":"than-thong","loaiLabel":"Thần thông / Quy tắc","phamCap":"Bổn nguyên quy tắc","hePhai":"","soHuu":["Chưởng Tôn"],"blurb":"Bổn nguyên Thái Sơ quy tắc là ánh sáng từ thuở sơ khai thiên địa, một trong những bổn nguyên mà Chưởng Tôn cảm ngộ được. Khi thi triển, triệu mặt trời phóng cột sáng bao phủ mục tiêu, có khả năng thiêu hủy du hồn, tiêu tan lực bài xích và tách riêng huyết mạch tiên nhân khỏi cơ thể.","detail":"Chưởng Tôn triệu một mặt trời trên không, phóng cột sáng bao phủ mục tiêu bằng bổn nguyên Thái Sơ quy tắc. Ánh sáng thái sơ thiêu hủy toàn bộ du hồn trong cơ thể mục tiêu, tiêu tan lực bài xích, rồi xâm nhập tách hoàn toàn huyết mạch tiên nhân ra khỏi cơ thể. Quy tắc này được Chưởng Tôn sử dụng lên Vương Lâm để tách huyết mạch tiên nhân, ngưng tụ thành giọt máu chứa nửa ký hiệu tiên nhân bất diệt thể. Vương Lâm không thể chống lại uy lực của quy tắc này. @c1491","congNang":["Thiêu hủy du hồn trong cơ thể mục tiêu @c1491","Tiêu tan lực bài xích @c1491","Tách Tiên và Cổ trong cơ thể, kéo riêng huyết mạch tiên nhân @c1491"],"nguoiTu":[{"ten":"Chưởng Tôn","tuChuong":"@c1491","tangDatToi":"","trangThai":"thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1491","loai":"thi triển","importance":"major","giaiDoan":"Chưởng Tôn thi triển lần đầu","text":"Chưởng Tôn triệu mặt trời dùng bổn nguyên thái sơ quy tắc phóng cột sáng bao phủ Vương Lâm, thiêu hủy du hồn, tách hoàn toàn huyết mạch tiên nhân khỏi cơ thể.","anchor":"ánh sáng này chính là một trong những bổn nguyên mà lão phu cảm ngộ được, bổn nguyên thái sơ quy tắc"}]},"nguon":["@c1491"],"uyLuc":"Vương Lâm không thể chống lại; ánh sáng thái sơ thiêu hủy toàn bộ du hồn, xâm nhập tách hoàn toàn huyết mạch tiên nhân khỏi cơ thể, ngưng tụ thành giọt máu chứa nửa ký hiệu tiên nhân bất diệt thể.","dacDiem":"Ánh sáng từ thuở sơ khai thiên địa, biểu hiện dưới dạng mặt trời phóng cột sáng bao phủ mục tiêu, mang bản chất bổn nguyên quy tắc do Chưởng Tôn cảm ngộ."},{"id":"that-thai-thuong","name":"Thất Thải Thương","cn":"七彩枪","aliases":["Cây thương tử vong"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không thuộc về thế giới này","hePhai":"","soHuu":["Người điên"],"blurb":"Thất Thải Thương là thần thông hủy thiên diệt địa, bạo phát bảy lần liên tiếp với mỗi lần uy lực gấp bội lần trước, thuộc loại thần thông không thuộc về thế giới này, được xếp cùng hạng với Phần Giới cổ Tán.","detail":"Thất Thải Thương sở hữu uy lực cực kỳ khủng khiếp, lực lượng phân thành bảy lần bạo phát, mỗi lần tăng gấp bội so với lần trước. Bảy tiếng nổ xé bầu trời, đủ sức phá hủy hoàn toàn vùng thiên địa phong tỏa do tu sĩ bước thứ ba Thái Cổ Tinh Thần liên thủ thiết lập, xé rách tinh không tạo ra hắc động. Ngay cả tiên nhân bất diệt thể hoàn chỉnh cũng bị uy lực này đánh cho tan vỡ liên tục. Thần thông này được nhận định là không thuộc về thế giới này, cùng loại với Phần Giới cổ Tán.","congNang":["Hủy thiên diệt địa, bạo phát bảy lần liên tiếp với mỗi lần uy lực gấp bội lần trước (@c1493)","Phá tan vùng thiên địa phong tỏa cấp bước thứ ba Thái Cổ Tinh Thần liên thủ thiết lập (@c1493)","Xé rách tinh không tạo hắc động (@c1493)","Khiến tiên nhân bất diệt thể hoàn chỉnh cũng bị tan vỡ liên tục (@c1493)"],"dacDiem":"Không thuộc về thế giới này, được xếp cùng loại với Phần Giới cổ Tán.","nguoiTu":[{"ten":"Người điên","tuChuong":"@c1492","tangDatToi":"","trangThai":"mat-tich"}],"tabs":{"tienTrinh":[{"chuong":"@c1493","loai":"thi triển","importance":"major","giaiDoan":"Bạo phát bảy lần phá hủy phong ấn","text":"Thất Thải Thương lao tới Vương Lâm với sức mạnh hủy thiên diệt địa, bạo phát bảy lần mỗi lần gấp bội. Phá hủy hoàn toàn vùng thiên địa phong tỏa, xé rách tinh không tạo hắc động. Ngay cả tiên nhân bất diệt thể hoàn chỉnh của người điên cũng bị tan vỡ liên tục.","anchor":"Thất Thải Thương này có uy lực hủy thiên diệt địa, giống như Phần Giới cổ Tán, đều là loại thần thông không thuộc về thế giới này"}]},"capNhatToi":"@c1493","nguon":["@c1492","@c1493"],"uyLuc":"Phá hủy hoàn toàn thiên địa phong tỏa cấp bước thứ ba, xé rách tinh không tạo hắc động, khiến ngay cả tiên nhân bất diệt thể hoàn chỉnh cũng tan vỡ liên tục."},{"id":"an-ky-hinh-tia-chop","name":"Ấn ký hình tia chớp","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi pháp","soHuu":["Vương Lâm"],"blurb":"Ấn ký hình tia chớp là dấu ấn lóe lên ở mắt phải Vương Lâm khi tiềm thức điểm chỉ trong kiếp luân hồi phàm nhân, phát ra ý chí như quân vương lôi điện, hiệu lệnh toàn bộ sấm sét trong phạm vi Triệu quốc phải rút lui tức khắc.","detail":"Trong kiếp luân hồi phàm nhân, Vương Lâm theo tiềm thức điểm một chỉ, mắt phải lóe lên ấn ký hình tia chớp. Ý chí phát ra mang khí phách quân vương lôi điện, hiệu lệnh toàn bộ sấm sét trong thiên địa Triệu quốc ngừng lại trong nháy mắt, mây đen tiêu tán, mưa gió dứt hẳn. Đây là biểu hiện tu vi chân thực của Vương Lâm bộc phát xuyên qua kiếp luân hồi, cho thấy quyền uy tuyệt đối đối với lôi điện ngay cả khi thân xác chỉ là phàm nhân.","congNang":["Hiệu lệnh toàn bộ sấm sét, lôi điện trong phạm vi cả một quốc gia (Triệu quốc) phải rút lui, mây đen tiêu tán, mưa gió dứt hẳn trong nháy mắt @c1500"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1500","tangDatToi":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1500","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu bộc phát trong kiếp luân hồi","text":"Vương Lâm tiềm thức điểm chỉ, mắt phải lóe ấn ký, ý chí quân vương lôi điện dẹp sấm sét toàn Triệu quốc.","anchor":"Giống như luồng ý chí này chính là ý chí của quân vương lôi điện trong thiên địa, có thể hiệu lệnh vô tận sấm sét"}]},"nguon":["@c1500"],"uyLuc":"Một chỉ điểm ra, ý chí quân vương lôi điện dẹp sạch toàn bộ sấm sét trong thiên địa Triệu quốc, mây đen tiêu tán tức thì @c1500","dacDiem":"Ấn ký hiện ở mắt phải Vương Lâm, được kích hoạt bởi tiềm thức chứ không phải chủ ý thi triển, biểu hiện tu vi chân thực bộc phát xuyên qua kiếp luân hồi phàm nhân"},{"id":"cuu-trung-tinh-toan","name":"Cửu trùng tính toán","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Luyện Hồn tông","soHuu":["Niệm Thiên"],"blurb":"Thuật bấm độn tính toán mệnh số, liên tục gieo quẻ chín lần để tìm con đường thông thiên cho tông phái, đại giá là hao tổn rất nhiều thọ nguyên và sinh cơ.","detail":"Niệm Thiên hao phí rất nhiều thọ nguyên và sinh cơ, liên tục tính toán chín lần, chín lần gieo quẻ đều chỉ về một thư sinh ở Triệu quốc Chu Tước Tinh. Đại giá cực lớn cho người sử dụng.","congNang":["Tìm kiếm cơ duyên/tương lai cho tông phái thông qua chín lần gieo quẻ"],"nguoiTu":[{"ten":"Niệm Thiên","tuChuong":"@c1502","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1502","loai":"thi triển","importance":"normal","giaiDoan":"Niệm Thiên thi triển tìm thông thiên lộ cho Luyện Hồn tông","text":"Niệm Thiên hao phí rất nhiều thọ nguyên và sinh cơ, chín lần tính toán đều chỉ về một thư sinh ở Triệu quốc.","anchor":"hao phí rất nhiều thọ nguyên và sinh cơ, liên tục tính toán chín lần"}]},"nguon":["@c1502"]},{"id":"tran-phap-hoa-giai-kiep-nan-hong-diep","name":"Trận pháp hóa giải kiếp nạn Hồng Điệp","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ (cực kỳ thâm áo)","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Trận pháp do Vương Lâm vẽ bằng nước mưa lên bàn đá trong đình, rút từ tri thức vô thức trong ký ức mộng cảnh của kiếp phàm nhân, nhằm hóa giải đại kiếp sinh tử cho Hồng Điệp. Đồ án trận pháp cực kỳ thâm áo, khiến ngay cả tu sĩ Tuyết Vực cũng phải biến sắc, và tự tan theo gió sau khi hoàn thành.","detail":"Trong bối cảnh Hồng Điệp đối mặt đại kiếp sinh tử, Vương Lâm — lúc này ở trạng thái kiếp phàm nhân — nói rằng trong mộng đã gặp một vật, rồi dùng nước mưa vẽ một trận pháp lên bàn đá trong đình. Nguồn gốc thực chất của trận pháp đến từ ký ức tu tiên bị phong ấn của Vương Lâm, vô thức truyền đạt qua mộng cảnh. Đồ án trận pháp này cực kỳ thâm áo, khiến nữ tu sĩ Tuyết Vực khi trông thấy phải biến sắc kinh ngạc. Trận pháp cần dùng tóc của Hồng Điệp làm vật dẫn, đặt vào bên trong để kích hoạt. Sau khi vẽ xong, đồ án tự tan theo gió, không lưu lại dấu vết.","thuocTinh":"Không rõ","nguonGoc":"Từ ký ức/mộng cảnh của Vương Lâm (kiếp phàm nhân vô thức truyền đạt tri thức tu tiên)","dacDiem":"Được vẽ bằng nước mưa lên bàn đá, đồ án cực kỳ thâm áo khiến tu sĩ Tuyết Vực biến sắc, cần tóc Hồng Điệp làm vật dẫn đặt vào trong trận, đồ án tự tan theo gió sau khi hoàn thành.","congNang":["Hóa giải đại kiếp sinh tử cho Hồng Điệp @c1512"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1512","tangDatToi":"","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1512","loai":"xuất hiện","importance":"major","giaiDoan":"Vương Lâm vẽ trận pháp từ mộng cảnh","text":"Vương Lâm dùng nước mưa vẽ trận pháp lên bàn đá trong đình, nói là trong mộng đã gặp. Trận pháp cực kỳ thâm áo khiến nữ tử Tuyết Vực biến sắc. Dặn nữ tử lấy tóc Hồng Điệp đặt vào trong, đồ án sau đó tan theo gió.","anchor":"Đồ án này là một trận pháp. Trận pháp này cực kỳ thâm ảo"}]},"nguon":["@c1512"]},{"id":"nhan-qua-an","name":"Nhân Quả ấn","cn":"因果印","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông tự sáng tạo","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Nhân Quả ấn là thần thông thứ tư do Vương Lâm tự sáng tạo, khai ngộ từ bảy mươi năm mộng đạo, ngưng tụ Nhân Quả bổn nguyên vô hình vô ảnh trên tay phải — mở tay là nhân, nắm tay là quả. Đây là thần thông dựa trên khí tức đại nho mà tu sĩ thông thường không thể có được, chỉ trong khoảnh khắc thức tỉnh từ mộng đạo mới chuyển hóa cảm ngộ thành sức mạnh khiến quỷ thần khiếp vía.","detail":"Nhân Quả ấn được Vương Lâm sáng tạo nhờ bảy mươi năm sống trọn một kiếp phàm nhân trong mộng đạo, từ đó cảm ngộ thiên địa theo cách mà tu sĩ không thể đạt tới. Ngay cả đại nho đương thời sau khi tu đạo cũng không nắm được loại khí tức này; chỉ có phương thức mộng đạo, trong khoảnh khắc thức tỉnh, mới chuyển hóa cảm ngộ ấy thành khí tức đại nho chân chính. Nhân Quả bổn nguyên vô hình vô ảnh ngưng tụ trên tay phải, vận hành theo nguyên lý: mở tay là nhân, nắm tay là quả. Đây là thần thông thứ tư trong đời Vương Lâm, tại thời điểm nhân quả bổn nguyên đại thành thì ba đạo bổn nguyên hội tụ (@c1520). Vương Lâm đã thi triển Nhân Quả ấn để phá Không Môn thứ ba, năm ngón tay xuyên vào bấu chặt, lôi hư ảnh bên trong ra khiến cửa nứt vỡ tiêu tán (@c1526).","thuocTinh":"Nhân quả","nguonGoc":"Vương Lâm tự sáng tạo từ bảy mươi năm mộng đạo","yeuCau":"Khí tức đại nho từ mộng đạo — tu sĩ thường và đại nho tu đạo đều không thể nắm","uyLuc":"Khí tức đại nho từ mộng đạo khiến quỷ thần khiếp vía; năm ngón xuyên vào Không Môn thứ ba lôi hư ảnh ra, cửa nứt vỡ tiêu tán (@c1526).","dacDiem":"Thần thông thứ tư trong đời Vương Lâm, tự sáng tạo chứ không sư thừa; dựa trên khí tức đại nho mà chỉ khoảnh khắc thức tỉnh từ bảy mươi năm mộng đạo mới chuyển hóa được, nhân quả bổn nguyên vô hình vô ảnh.","congNang":["Ngưng tụ Nhân Quả bổn nguyên vô hình vô ảnh trên tay phải — mở tay là nhân, nắm tay là quả @c1519","Nhân quả bổn nguyên đại thành, ba đạo bổn nguyên hội tụ @c1520","Ấn tay xuyên vào mục tiêu, năm ngón bấu chặt lôi hư ảnh ra phá vỡ — dùng để phá Không Môn thứ ba, khiến cửa nứt vỡ tiêu tán @c1526","Đẩy người vào nhân quả luân hồi","Định nhân quả bá đạo"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1519","tangDatToi":"Đại thành","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1519","loai":"xuat-hien","importance":"major","giaiDoan":"Sáng tạo thần thông","text":"Vương Lâm dùng khí tức đại nho từ bảy mươi năm mộng đạo ngưng tụ Nhân Quả bổn nguyên trên tay phải, sáng tạo thần thông thứ tư trong cuộc đời.","anchor":"Tay phải từ hôm nay trở đi đã trở thành thần thông thứ tư do hắn sáng tạo ra trong cuộc đời này"},{"chuong":"@c1520","loai":"xuat-hien","importance":"major","giaiDoan":"Vương Lâm ngộ Nhân Quả ấn, nhân quả bổn nguyên đại thành","text":"Vương Lâm ngộ ra Nhân Quả ấn, thức thần thông thứ tư tự sáng tạo, nhân quả bổn nguyên đại thành. Ba đạo bổn nguyên cùng vận chuyển hình thành vòng tròn biến ảo, uy lực vượt Không Niết đại viên mãn.","anchor":"Ấn này đánh ra đủ để đẩy người ta vào trong nhân quả luân hồi"},{"chuong":"@c1526","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm dùng Nhân Quả Ấn phá Không Môn thứ ba, năm ngón tay xuyên vào bấu chặt lôi hư ảnh ra, cửa nứt vỡ tiêu tan. Tu vi vọt lên Không Niết Hậu Kỳ.","anchor":"Nhân Quả Ấn, là do Vương Lâm mộng đạo hơn bảy mươi năm"}]},"capNhatToi":"@c1519","nguon":["@c1519","@c1520","@c1526"]},{"id":"sinh-tu-an","name":"Sinh Tử Ấn","cn":"生死印","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Sinh Tử Ấn là thức thần thông thứ năm do Vương Lâm tự sáng tạo, đồng thời là đạo bổn nguyên thứ tư của hắn — Sinh Tử. Tay trái Sinh (bạch khí, ý chí thiên không), tay phải Tử (hắc khí, lực đại địa), hai tay hợp nhất hóa thành Sinh Tử Ấn, dung hợp cùng ba đạo bổn nguyên Lôi, Hỏa, Nhân Quả trước đó.","detail":"Trong hư vô, Vương Lâm triệu xuất Sinh Tử bổn nguyên, tay trái tỏa bạch khí mang sinh cơ vô tận cùng ý chí thiên không, tay phải tỏa hắc khí mang tử khí cùng lực lượng đại địa. Hai tay hợp nhất, ánh sáng hắc bạch xuyên thấu hóa thành Sinh Tử Ấn — thức thần thông thứ năm hoàn toàn do Vương Lâm tự sáng tạo, không sư thừa hay truyền thụ. Đây cũng là đạo bổn nguyên thứ tư của hắn, dung hợp cùng ba đạo bổn nguyên đã lĩnh ngộ trước đó là Lôi, Hỏa và Nhân Quả. Sau khi thành hình, Sinh Tử Ấn được Vương Lâm thi triển để phá Không Môn thứ tư, bạch khí và hắc khí vặn xoáy xé toạc cửa, uy lực khó lường.","thuocTinh":"Sinh Tử","nguonGoc":"Vương Lâm tự sáng tạo","dacDiem":"Thức thần thông thứ năm, đạo bổn nguyên thứ tư, do Vương Lâm tự sáng tạo; dung hợp cùng ba đạo bổn nguyên trước (Lôi, Hỏa, Nhân Quả), mang đặc trưng hắc bạch song khí — sinh cơ của thiên không và tử khí của đại địa hợp nhất.","congNang":["Triệu xuất Sinh Tử bổn nguyên trong hư vô, hợp nhất tay trái Sinh (bạch khí) và tay phải Tử (hắc khí) hóa thành Sinh Tử Ấn @c1521","Bạch khí và hắc khí vặn xoáy, xé toạc mục tiêu bằng sức mạnh sinh tử thiên địa — dùng để phá Không Môn thứ tư @c1526","Dung hợp cùng ba đạo bổn nguyên Lôi, Hỏa, Nhân Quả, gia tăng uy lực tổng hợp @c1521"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1521","tangDatToi":"Đại thành","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1521","loai":"xuat-hien","importance":"major","giaiDoan":"Sáng tạo thành công","text":"Vương Lâm trong hư vô triệu xuất Sinh Tử bổn nguyên, hợp nhất tay trái Sinh tay phải Tử hóa thành Sinh Tử Ấn — thức thần thông thứ năm tự sáng tạo, dung hợp cùng ba đạo bổn nguyên trước đó.","anchor":"Đây chính là thức thần thông thứ năm Vương Lâm tự sáng tạo ra, Sinh Tử Ấn!"},{"chuong":"@c1526","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm dùng Sinh Tử Ấn phá Không Môn thứ tư, tay trái bạch khí tay phải hắc khí xoáy xé toạc cửa. Tu vi đạt Không Niết Đại Viên Mãn.","anchor":"Tay trái Vương Lâm có một luồng bạch khí tràn ngập"}]},"nguon":["@c1521","@c1526"],"uyLuc":"Bạch khí và hắc khí xoáy xé toạc Không Môn thứ tư, uy lực khó lường @c1526"},{"id":"that-gia-bon-nguyen","name":"Thật Giả bổn nguyên","cn":"真假本源","loai":"than-thong","loaiLabel":"Bổn nguyên","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đạo bổn nguyên thứ năm của Vương Lâm. Khi hiện ra, không môn trở nên mơ hồ, phía sau xuất hiện thêm một không môn hư ảo, hai cánh cửa lớn đứng trong tinh không khiến người nhìn khó phân biệt thật giả.","detail":"Thật Giả bổn nguyên là đạo bổn nguyên thứ năm hiện trên không môn của Vương Lâm. Khi đạo bổn nguyên này xuất hiện, không môn trở nên mơ hồ, đồng thời phía sau nảy sinh thêm một không môn hư ảo, tạo nên hai cánh cửa lớn đứng trong tinh không khiến người nhìn không thể phân biệt đâu thật đâu giả. Cùng với bốn đạo bổn nguyên trước, năm đạo bổn nguyên dẫn động không môn đủ sức đánh ngang tu sĩ Không Linh hậu kỳ.","congNang":["Khiến không môn trở nên mơ hồ, xuất hiện thêm một không môn hư ảo phía sau, hai cánh cửa lớn đứng trong tinh không khiến khó phân biệt thật giả @c1521"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1521","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1521","loai":"xuat-hien","importance":"major","giaiDoan":"Lần đầu hiện ra trên không môn","text":"Đạo bổn nguyên thứ năm xuất hiện trên không môn, hai cánh cửa lớn đứng trong tinh không khiến khó phân biệt thật giả, năm đạo bổn nguyên đủ đánh ngang Không Linh hậu kỳ.","anchor":"Hai cánh cửa lớn đứng trong tinh không, khiến người ta nhìn lại khó phân biệt nối thật giả!"}]},"nguon":["@c1521"],"uyLuc":"Năm đạo bổn nguyên cùng dẫn động không môn, đủ sức đánh ngang tu sĩ Không Linh hậu kỳ.","dacDiem":"Bản chất xoay quanh sự mơ hồ giữa thật và giả; khi hiện ra tạo phân thân hư ảo của không môn, khiến đối phương không thể phân biệt đâu là thực đâu là hư."},{"id":"chan-gia-an","name":"Chân Giả Ấn","cn":"真假印","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Bổn nguyên Thật Giả","soHuu":["Vương Lâm"],"blurb":"Chân Giả Ấn là thần thông thứ sáu của Vương Lâm, được ngưng tụ khi ấn ký bổn nguyên thứ năm Thật Giả đại thành trong hư vô (@c1522).","detail":"Chân Giả Ấn hình thành khi bổn nguyên Thật Giả của Vương Lâm đạt tới đại thành, tự ngưng tụ trong hư vô mà hóa thành một đạo thần thông. Đây là thần thông thứ sáu của Vương Lâm, bắt nguồn trực tiếp từ ấn ký bổn nguyên thứ năm — Thật Giả. Ngoài sự kiện ngưng tụ tại @c1522, tiến trình hiện chưa ghi nhận thêm chi tiết về cách vận dụng hay biểu hiện cụ thể của thần thông này.","thuocTinh":"Thật Giả bổn nguyên","nguonGoc":"Vương Lâm tự ngưng tụ khi bổn nguyên Thật Giả đại thành trong hư vô","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1522","tangDatToi":"Mới ngưng tụ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1522","loai":"xuất hiện","importance":"major","giaiDoan":"Ngưng tụ lần đầu","text":"Vương Lâm ngưng tụ thần thông thứ sáu Chân Giả Ấn từ ấn ký bổn nguyên Thật Giả đại thành.","anchor":"Ấn ký do bổn nguyên thứ năm - Thật giả ngưng tụ thành liền hóa thành đạo thần thông thứ sáu của hắn - Chân Giả Ấn"}]},"nguon":["@c1522"]},{"id":"sau-dao-bon-nguyen-buoc-thu-ba","name":"Sáu đạo bổn nguyên — Bước thứ ba toàn năng","cn":"","loai":"cong-phap","loaiLabel":"Tu luyện đại pháp","phamCap":"Siêu việt — chưa từng có từ cổ chí kim","hePhai":"Bổn nguyên","soHuu":["Vương Lâm"],"blurb":"Sáu đạo bổn nguyên là thành tựu bước thứ ba toàn năng của Vương Lâm — điều ngay cả Chưởng Tôn cũng không thể đạt được. Bằng cách hoàn thành đạo thứ sáu từ sát lục bổn nguyên của Sát Lục Kiếm, Vương Lâm dùng sáu đạo bổn nguyên đánh tan không môn, tạo nên hiện tượng chưa từng có từ cổ chí kim.","detail":"Sáu đạo bổn nguyên là cảnh giới tối thượng trong tiến trình bước thứ ba toàn năng. Vương Lâm hấp thu sát lục bổn nguyên từ Sát Lục Kiếm để hoàn thành đạo thứ sáu, từ đó tập hợp đủ sáu đạo bổn nguyên. Với sáu đạo này, Vương Lâm dẫn động không môn tạo ra hiện tượng chưa từng xuất hiện từ cổ chí kim, đánh tan không môn để thành tựu bước thứ ba toàn năng. Ngay cả Chưởng Tôn cũng không thể sở hữu sáu đạo bổn nguyên, khiến thành tựu của Vương Lâm trở thành sự kiện vô tiền khoáng hậu.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1522","tangDatToi":"Sáu đạo bổn nguyên / bước thứ ba toàn năng","trangThai":"dai-thanh"}],"tabs":{"tienTrinh":[{"chuong":"@c1522","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Hoàn thành sáu đạo bổn nguyên","text":"Vương Lâm hấp thu sát lục bổn nguyên từ Sát Lục Kiếm thành đạo thứ sáu, tuyên bố dùng sáu đạo bổn nguyên đánh tan không môn thành tựu bước thứ ba toàn năng.","anchor":"Vương Lâm ta hôm nay lợi dụng sáu đạo bổn nguyên đánh tan không môn, thành tựu bước thứ ba toàn năng!"}]},"nguon":["@c1522"],"uyLuc":"Sáu đạo bổn nguyên đánh tan không môn, tạo hiện tượng chưa từng có từ cổ chí kim — thành tựu mà ngay cả Chưởng Tôn cũng không thể làm được.","dacDiem":"Cần hội đủ cả sáu đạo bổn nguyên mới có thể thi triển; đạo thứ sáu là sát lục bổn nguyên xuất phát từ Sát Lục Kiếm.","congNang":["Hấp thu sát lục bổn nguyên từ Sát Lục Kiếm để hoàn thành đạo thứ sáu @c1522","Dùng sáu đạo bổn nguyên dẫn động không môn, đánh tan không môn để thành tựu bước thứ ba toàn năng @c1522"]},{"id":"chinh-khi-dai-nho","name":"Chính khí đại nho","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Nho đạo","soHuu":["Vương Lâm"],"blurb":"Chính khí đại nho là khí tức chính khí vô biên của bậc đại nho đương đại, minh ngộ thiên địa, không sợ quỷ thần, có thể nhập thẳng linh hồn đối phương bất chấp tu vi.","detail":"Chính khí đại nho bắt nguồn từ uy phong loài người bậc đại nho, là thứ khí tức minh ngộ thiên địa mà thiên địa lẫn quỷ thần đều kiêng kị. Khi Vương Lâm nhắm rồi mở mắt, từ dưới lông mày cuồn cuộn chính khí vô biên, chỉ bằng một câu quát đã nhập thẳng linh hồn phân thân Hư Thần Thiên Tôn — một trong Thái cổ ngũ tôn — khiến phân thân này khựng lại, lùi mấy trượng trong hoảng sợ. Nam tử áo xanh vốn từng là nho sinh cũng bị ảnh hưởng, hai chân run rẩy, đạo tâm bất ổn. Uy lực của chính khí đại nho vận hành như quy tắc thiên địa, hoàn toàn bất chấp tu vi và thân phận của đối phương.","thuocTinh":"Nho đạo chính khí","nguonGoc":"Uy phong loài người, bậc đại nho đương đại","uyLuc":"Uy lực như quy tắc thiên địa, chỉ một câu quát nhập linh hồn phân thân Thái cổ ngũ tôn Hư Thần Thiên Tôn khiến phân thân lùi mấy trượng hoảng sợ, bất chấp tu vi.","dacDiem":"Không sợ quỷ thần, thiên địa kiêng kị; khí tức cuồn cuộn từ dưới lông mày, là chính khí minh ngộ thiên địa của bậc đại nho đương đại.","congNang":["Nhập thẳng linh hồn đối phương bất chấp tu vi và thân phận, khiến đối phương hoảng sợ khựng lại @c1523","Áp chế đạo tâm đối phương, khiến đạo tâm bất ổn @c1523"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1523","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1523","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm thi triển chính khí đại nho, chỉ một câu quát nhập linh hồn phân thân Hư Thần Thiên Tôn (Thái cổ ngũ tôn), khiến hắn lùi mấy trượng hoảng sợ, nam tử áo xanh đạo tâm bất ổn.","anchor":"chính khí vô biên của bậc đại nho đương đại, là một luồng khí của minh ngộ thiên địa, không sợ quỷ thần"}]},"dinhDanh":"goc","nguon":["@c1523"]},{"id":"loi-dinh-bon-nguyen","name":"Lôi đình bổn nguyên","cn":"雷霆本源","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bổn nguyên (đại thành, chưa dung hợp)","hePhai":"Lôi tu","soHuu":["Vương Lâm"],"blurb":"Lôi đình bổn nguyên là một trong sáu đạo bổn nguyên Vương Lâm tu luyện, thuộc hệ bổn nguyên lôi tu. Khi đại thành, Vương Lâm như vua của lôi đình, một tiếng hô có thể dẫn động toàn bộ lôi đình bất diệt từ tứ đại tinh vực giới nội hội tụ về một điểm, thanh thế chưa từng có khiến Thái cổ ngũ tôn cũng phải khiếp sợ.","detail":"Lôi đình bổn nguyên là sức mạnh bổn nguyên về lôi đình mà Vương Lâm đạt được, nằm trong hệ thống sáu đạo bổn nguyên — sáu đạo đã đại thành nhưng chưa dung hợp lại với nhau. Riêng sức mạnh lôi đình so với năm xưa đã lớn hơn mấy lần. Tại trận chiến Chu Tước Tinh, Vương Lâm hô hiệu lệnh lôi đình trong thiên địa, một quyền lôi đình đánh lên Không Môn khiến nó chấn động hé mở, mấy vạn tu sĩ phun máu. Sau đó, Vương Lâm kêu một tiếng dài dẫn động toàn bộ lôi đình từ bốn đại tinh vực Côn Hư, Vân Hải, Triệu Hà, La Thiên — kể cả lôi đình bất diệt tồn tại vạn năm ở cửa Lôi Tiên Giới — đều hướng về Chu Tước Tinh hội tụ. Lôi đình không chỉ đến từ giới nội mà còn từ giới ngoại, xuyên qua lỗ hổng Vân Hải mà tập trung. Thanh thế lôi đình hội tụ từ hai giới này lớn đến mức Hư Thần Thiên Tôn, một trong Thái","thuocTinh":"Lôi","nguonGoc":"Bổn nguyên lôi tu — một trong sáu đạo bổn nguyên Vương Lâm tu luyện","uyLuc":"Dẫn động toàn bộ lôi đình tứ đại tinh vực cùng lôi đình bất diệt vạn năm từ cửa Lôi Tiên Giới, hội tụ hai giới nội ngoại, thanh thế chưa từng có khiến Thái cổ ngũ tôn Hư Thần Thiên Tôn cũng phải khiếp sợ.","dacDiem":"Lôi tu toàn năng, Vương Lâm như vua của lôi đình, có thể sai khiến lôi đình khắp thiên địa theo ý chí, bao gồm cả lôi đình bất diệt tồn tại vạn năm.","congNang":["Hô hiệu lệnh lôi đình trong thiên địa, dùng một quyền lôi đình đánh mở Không Môn, chấn động khiến mấy vạn tu sĩ phun máu @c1524","Dẫn động toàn bộ lôi đình bất diệt từ tứ đại tinh vực giới nội (Côn Hư, Vân Hải, Triệu Hà, La Thiên) hội tụ về một điểm @c1524","Dẫn động lôi đình từ cả giới nội lẫn giới ngoại, xuyên qua lỗ hổng Vân Hải hội tụ phá Không Môn @c1525"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1524","tangDatToi":"Đại thành","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1524","loai":"thi triển","importance":"major","giaiDoan":"Đại thành — dẫn động lôi đình tứ đại tinh vực","text":"Vương Lâm hô hiệu lệnh, một quyền lôi đình đánh mở Không Môn sáu đạo bổn nguyên, chấn động khiến mấy vạn tu sĩ phun máu. Kêu một tiếng dài dẫn động toàn bộ lôi đình từ Côn Hư, Vân Hải, Triệu Hà, La Thiên hướng về Chu Tước Tinh. Lôi đình bất diệt vạn năm ở cửa Lôi Tiên Giới cũng bị phá nát thoát ra. Hư Thần Thiên Tôn khiếp sợ kêu thất thanh.","anchor":"Vua của lôi đình này kêu lên một tiếng, đó chính là lời kêu gọi bọn chúng"},{"chuong":"@c1525","loai":"thi triển","importance":"major","giaiDoan":"Phá Không Môn thứ nhất","text":"Vương Lâm dùng lôi đình bổn nguyên dẫn động lôi đình từ giới nội và giới ngoại qua lỗ hổng Vân Hải, hội tụ phá vỡ hoàn toàn Không Môn thứ nhất.","anchor":"chỉ là sơ kỳ, chỉ là một đạo lôi đình bổn nguyên mà thôi"}]},"capNhatToi":"@c1524","nguon":["@c1524","@c1525"]},{"id":"hoa-bon-nguyen","name":"Hỏa bổn nguyên","cn":"火本源","loai":"cong-phap","loaiLabel":"Bổn nguyên","phamCap":"Đại thành","hePhai":"Hỏa","soHuu":["Vương Lâm"],"blurb":"Hỏa bổn nguyên là một trong sáu đạo bổn nguyên đại thành của Vương Lâm, được thi triển để thiêu hủy Không Môn thứ hai bằng biển lửa bổn nguyên hội tụ từ nhiều tinh vực.","detail":"Hỏa bổn nguyên cho phép Vương Lâm nhân danh mình gọi lửa bổn nguyên, dẫn động hỏa diễm từ nhiều tinh vực — Côn Hư, Vân Hải, La Thiên, Triệu Hà — cùng Thái cổ Tinh Thần giới ngoại hội tụ thành biển lửa. Hắn dùng sức mạnh này thiêu đốt Không Môn thứ hai thành tro bụi.","congNang":["Dẫn động hỏa diễm từ nhiều tinh vực (Côn Hư, Vân Hải, La Thiên, Triệu Hà) và Thái cổ Tinh Thần giới ngoại hội tụ thành biển lửa bổn nguyên @c1525","Thiêu hủy Không Môn thứ hai thành tro bụi bằng biển lửa bổn nguyên @c1525"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1525","tangDatToi":"Đại thành","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1525","loai":"thi triển","importance":"major","giaiDoan":"Thiêu hủy Không Môn thứ hai","text":"Vương Lâm gọi hỏa bổn nguyên nhân danh mình, dẫn lửa từ Côn Hư, Vân Hải, La Thiên, Triệu Hà và Thái cổ Tinh Thần hội tụ thành biển lửa, thiêu hủy Không Môn thứ hai thành tro bụi.","anchor":"Hỏa bổn nguyên, nhân danh Vương Lâm ta, thiêu đốt Không Môn này"}]},"nguon":["@c1525"],"uyLuc":"Thiêu đốt Không Môn thứ hai thành tro bụi bằng biển lửa hội tụ từ nhiều tinh vực."},{"id":"khong-niet","name":"Không Niết","cn":"空涅","loai":"cong-phap","loaiLabel":"Cảnh giới bước thứ ba","phamCap":"Bước thứ ba","hePhai":"Không rõ","soHuu":[],"blurb":"Không Niết là cảnh giới của bước thứ ba tu luyện, đạt được sau khi tu sĩ phá Không Môn và hấp thu sức mạnh của nó. Cảnh giới này phân chia thành sơ kỳ và trung kỳ.","detail":"Không Niết là cảnh giới thuộc bước thứ ba trong hệ thống tu luyện. Sau khi tu sĩ mở Không Môn, thông thường phải lập tức hấp thu sức mạnh Không Môn để ngưng tụ bổn nguyên, từ đó chính thức bước vào cảnh giới Không Niết. Vương Lâm sau hai lần phá Không Môn có khí thế tương đương Không Niết trung kỳ, tuy nhiên đó chưa phải tu vi thực chất do chưa thực sự hấp thu sức mạnh Không Môn @c1525.","congNang":["Cảnh giới bước thứ ba tu luyện, phân chia sơ kỳ và trung kỳ @c1525"],"cacTang":[{"ten":"Không Niết Sơ Kỳ","moTa":"Khí thế sau khi phá Không Môn thứ nhất","chuong":"@c1525"},{"ten":"Không Niết Trung Kỳ","moTa":"Khí thế sau khi phá Không Môn thứ hai","chuong":"@c1525"}],"tabs":{"tienTrinh":[{"chuong":"@c1525","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Lộ cảnh giới bước thứ ba","text":"Lộ rõ Không Niết là cảnh giới bước thứ ba, chia sơ kỳ và trung kỳ. Vương Lâm sau hai lần phá Không Môn có khí thế đạt Không Niết trung kỳ nhưng chưa phải tu vi thực chất.","anchor":"tu vi của hắn lúc này cũng đã ầm ầm bạo tăng"}]},"nguon":["@c1525"]},{"id":"sau-dao-bon-nguyen-vuong-lam","name":"Sáu đạo bổn nguyên dung hợp","loai":"cong-phap","loaiLabel":"Trạng thái bổn nguyên","phamCap":"Đại thành (từng đạo)","hePhai":"Tổng hợp","soHuu":["Vương Lâm"],"blurb":"Con đường độc nhất của Vương Lâm: lấy từng đạo trong sáu bổn nguyên đại thành mở một Không Môn, cuối cùng dung hợp tất cả để bước vào bước thứ ba toàn năng. Hư Thần Thiên Tôn nhận định nếu thành công, tu sĩ bước thứ ba này sẽ mạnh hơn người thường vô số lần.","detail":"Vương Lâm sở hữu sáu đạo bổn nguyên đại thành. Khác với thông lệ hấp thu sức mạnh Không Môn ngay lần đầu, hắn chọn cách dùng mỗi đạo bổn nguyên phá mở một Không Môn riêng biệt, tích lũy đủ sức mạnh từ sáu Không Môn rồi mới tiến hành dung hợp toàn bộ. Tại @c1525, Hư Thần Thiên Tôn nhận ra ý đồ này và đánh giá rằng nếu thành công, tu sĩ bước thứ ba được tạo ra theo phương thức này sẽ vượt trội so với bước thứ ba thông thường vô số lần. Đây là con đường chưa từng có tiền lệ, hoàn toàn do Vương Lâm tự khai sáng.","congNang":["Mỗi đạo bổn nguyên đại thành phá mở một Không Môn riêng biệt @c1525","Dung hợp sáu đạo bổn nguyên cùng sáu Không Môn để bước vào bước thứ ba toàn năng @c1525"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1525","tangDatToi":"Đang thực hiện (2/6 cửa)","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1525","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Lộ con đường sáu cửa sáu bổn nguyên","text":"Hư Thần Thiên Tôn nhận ra Vương Lâm muốn lấy mỗi đạo bổn nguyên mở ra một Không Môn, dung hợp cả sáu để thành bước thứ ba toàn năng.","anchor":"Hắn muốn lấy mỗi đạo bổn nguyên để mở ra một Không Môn"}]},"nguon":["@c1525"],"dacDiem":"Phương thức đột phá chưa từng có tiền lệ: thay vì hấp thu sức mạnh một Không Môn duy nhất theo thông lệ, dùng sáu đạo bổn nguyên mở sáu Không Môn rồi dung hợp, tạo nên tu sĩ bước thứ ba vượt xa mức bình thường."},{"id":"chan-gia-dao","name":"Chân Giả Đạo","cn":"真假道","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Chân giả bổn nguyên","soHuu":["Vương Lâm"],"blurb":"Chân Giả Đạo là thần thông do Vương Lâm tự ngộ từ chân giả bổn nguyên, lấy nhắm mắt biến vạn vật thành giả, mở mắt biến giả thành chân làm cốt lõi. Được dùng để phá Không Môn thứ năm và biến ký ức, linh hồn, oán niệm của người đã mất thành sức mạnh thực chiến.","detail":"Chân Giả Đạo là thần thông Vương Lâm tự mình ngộ ra từ chân giả bổn nguyên, không truyền thừa từ bất kỳ tông môn hay tiền bối nào. Nguyên lý cốt lõi nằm ở ranh giới giữa chân và giả: khi nhắm mắt, vạn vật xung quanh đều trở thành giả; khi mở mắt, giả lập tức biến thành chân. Thi triển chỉ cần vung tay, mục tiêu dù kiên cố đến đâu cũng tiêu tan như tro bụi. Tại Không Môn thứ năm, Vương Lâm lần đầu dùng Chân Giả Đạo phá vỡ cửa ải, khí thế Không Linh Sơ Kỳ khuếch tán. Sau đó, hắn thi triển Chân Giả Đạo ở tầng cao hơn: biến ra thân ảnh của Chu Như, Bạch Phàm, Thanh Thủy, Thác Sâm cùng vô số người oán trời, biến ký ức, linh hồn và oán niệm thành sức mạnh thực, lấy cái giả hóa chân để phản kích.","thuocTinh":"Chân giả","nguonGoc":"Vương Lâm tự ngộ từ chân giả bổn nguyên","congNang":["Nhắm mắt khiến vạn vật thành giả, mở mắt biến giả thành chân, vung tay quét vỡ mục tiêu như tro bụi @c1526","Biến thân ảnh của người đã mất (Chu Như, Bạch Phàm, Thanh Thủy, Thác Sâm cùng vô số người) từ ký ức, linh hồn và oán niệm thành sức mạnh thực @c1533","Phá Không Môn thứ năm, khuếch tán khí thế Không Linh Sơ Kỳ @c1526"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1526","tangDatToi":"Đại thành","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1526","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm dùng Chân Giả Đạo phá Không Môn thứ năm. Nhắm mắt vạn vật thành giả, mở mắt giả biến thành chân, vung tay quét vỡ cửa. Khe mi tâm hiện hoàn toàn, khí thế Không Linh Sơ Kỳ khuếch tán.","anchor":"Đây là Chân Giả Đạo, thần thông mà hắn đã ngộ ra từ chân giả bổn nguyên"},{"chuong":"@c1533","loai":"thi-trien","importance":"major","giaiDoan":"Phản kích Huyễn Chân Kiếp","text":"Vương Lâm dùng Chân Giả Đạo biến ra thân ảnh Chu Như, Bạch Phàm, Thanh Thủy, Thác Sâm cùng vô số người oán trời, tạo thiên kiếp đáp trả. Tiếp đó gom oán niệm toàn Côn Hư tinh vực đánh vào cái khe thiên kiếp, khiến cái khe lần đầu run lên.","anchor":"Chân Giả Đạo của Vương Lâm biến thành, nói thật là thật, nói giả là giả"}]},"nguon":["@c1526","@c1533"]},{"id":"van-khong-cot-mon-than-thong","name":"Vạn Không Cốt Môn (dị tượng đột phá)","cn":"万空骨门","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không Môn thứ sáu","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Vạn Không Cốt Môn là Không Môn thứ sáu, dị tượng quỷ dị xuất hiện khi Vương Lâm đột phá bước thứ ba toàn năng. Cánh cửa này cực kỳ kiên cố, chịu được huyết chưởng sát lục chỉ nứt ra chứ không sụp đổ, cuối cùng bị một quyền toàn lực kết hợp sáu đạo bổn nguyên đại thành phá vỡ.","detail":"Vạn Không Cốt Môn là Không Môn thứ sáu, một dị tượng đặc biệt vượt ngoài nhận biết của Vương Lâm, xuất hiện trong quá trình đột phá bước thứ ba toàn năng (@c1527). Cánh cửa này thể hiện độ kiên cố phi thường: khi Vương Lâm thi triển huyết chưởng sát lục, Vạn Không Cốt Môn chỉ nứt ra chứ không sụp đổ. Cuối cùng, Vương Lâm phải dồn toàn lực vào một quyền kết hợp sáu đạo bổn nguyên đại thành mới phá vỡ được cánh cửa này, mở đường bước vào bước thứ ba toàn năng.","congNang":["Không Môn thứ sáu, thử thách cuối cùng trong quá trình đột phá bước thứ ba toàn năng (@c1527)"],"tabs":{"tienTrinh":[{"chuong":"@c1527","loai":"xuất hiện","importance":"major","giaiDoan":"Xuất hiện và bị phá","text":"Vạn Không Cốt Môn xuất hiện khi Vương Lâm đột phá. Chịu được huyết chưởng sát lục chỉ nứt, sau đó bị quyền sáu đạo bổn nguyên đánh sập hoàn toàn, mở đường cho Vương Lâm thành bước thứ ba toàn năng.","anchor":"Vạn Không Cốt Môn khổng lồ kia đột nhiên run lên, những vết nứt nhanh chóng lan ra"}]},"nguon":["@c1527"],"uyLuc":"Chịu được huyết chưởng sát lục chỉ nứt mà không sụp đổ, cần quyền toàn lực kết hợp sáu đạo bổn nguyên đại thành mới có thể phá vỡ (@c1527).","dacDiem":"Dị tượng quỷ dị vượt ngoài nhận biết của Vương Lâm, độ kiên cố phi thường vượt xa các Không Môn trước đó."},{"id":"mot-chi-dao-niem","name":"Một chỉ đạo niệm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Một chỉ đạo niệm là chiêu thức Vương Lâm điểm một ngón tay phóng ra đạo niệm còn sót lại từ ba đạo quả, khiến tinh không và thời gian đình trệ, đồng thời kiềm chế nhiều địch thủ cùng lúc.","detail":"Trong lúc hấp thụ sức mạnh Không Môn và dung hợp bổn nguyên thứ sáu, Vương Lâm điểm một chỉ phóng đạo niệm bỏ đi từ ba đạo quả. Chiêu thức này khiến tinh không ngừng vận chuyển, thời gian như đình trệ, đồng thời kiềm chế Chu Cẩn và nam tử áo xanh không thể tiến tới, làm Hư Thần Thiên Tôn chậm lại. Đạo niệm trong chiêu là phần còn sót từ ba đạo quả mà Vương Lâm đã ngộ, được dồn hết vào một chỉ duy nhất.","congNang":["Đình trệ tinh không và thời gian trong phạm vi chiêu thức @c1527","Kiềm chế đồng thời nhiều đối thủ bằng đạo niệm từ ba đạo quả — khiến Chu Cẩn và nam tử áo xanh không thể tiến, làm Hư Thần Thiên Tôn chậm lại @c1527"],"tabs":{"tienTrinh":[{"chuong":"@c1527","loai":"thi triển","importance":"major","giaiDoan":"Kiềm chế ba địch thủ lúc đột phá","text":"Vương Lâm điểm một chỉ chứa đạo niệm ba đạo quả, kiềm chế Chu Cẩn và nam tử áo xanh không thể tiến, làm Hư Thần Thiên Tôn chậm lại, trong khi bản thân vẫn hấp thụ sức mạnh Không Môn.","anchor":"một chỉ này dường như khiến cho tinh không ngừng vận chuyển"}]},"nguon":["@c1527"],"uyLuc":"Một chỉ phóng ra khiến tinh không ngừng vận chuyển, thời gian đình trệ, đồng thời kiềm chế ba đối thủ cấp Thiên Tôn cùng lúc.","dacDiem":"Đạo niệm tập trung từ ba đạo quả dồn vào một ngón tay duy nhất, mang tính áp chế diện rộng cả không gian lẫn thời gian."},{"id":"van-ha-hu-than-dao","name":"Vạn Hà Hư Thần Đạo","cn":"万河虚神道","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Hư Thần Thiên Tôn","soHuu":["Hư Thần Thiên Tôn"],"blurb":"Thần thông của Hư Thần Thiên Tôn, mở khe khổng lồ phóng vô số hồn phách hương hỏa và hàng vạn pho tượng hư ảo trấn áp đối thủ vào thiên địa luân hồi.","detail":"Mở một cái khe khổng lồ phía sau, phóng ra vô số hồn phách hương hỏa và hàng vạn pho tượng khổng lồ đổ xuống đối thủ, muốn trấn áp vào thiên địa luân hồi. Các pho tượng mang tính hư ảo, xuyên qua thân thể Vương Lâm đã hóa trong suốt mà không cản được.","congNang":["Mở khe khổng lồ phóng hồn phách hương hỏa và hàng vạn pho tượng trấn áp đối thủ vào thiên địa luân hồi"],"nguoiTu":[{"ten":"Hư Thần Thiên Tôn","tuChuong":"@c1528","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1528","loai":"thi triển","importance":"normal","giaiDoan":"Phân thân Hư Thần Thiên Tôn dùng chống Vương Lâm","text":"Hư Thần Thiên Tôn mở khe khổng lồ phóng hồn phách hương hỏa và hàng vạn pho tượng vây khốn Vương Lâm, nhưng các pho tượng xuyên qua thân Vương Lâm đã hóa hư ảo mà vô hiệu.","anchor":"Trấn áp người này cho ta, trấn áp hắn vào thiên địa luân hồi"}]},"nguon":["@c1528"]},{"id":"sat-luc","name":"Sát lục","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Chiêu thức dạng đao của Vương Lâm, tay như đao chém xuống thiên linh đối thủ.","detail":"Vương Lâm thi triển sau Chân Giả Đạo, tay như đao chém xuống thiên linh Hư Thần Thiên Tôn, chia thân hắn làm hai hóa hai đám sương mù tím.","nguon":["@c1528"]},{"id":"huong-hoa-gioi-nam-tu-ao-xanh","name":"Hương hỏa giới của nam tử áo xanh","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Giới ngoại","soHuu":["Nam tử áo xanh"],"blurb":"Pháp môn hương hỏa giới của nam tử áo xanh, mở hương hỏa giới lấy toàn bộ hồn phách hương hỏa dung nhập máu tươi hóa thành tầng băng phòng hộ.","detail":"Nam tử áo xanh mở hương hỏa giới, đem toàn bộ hồn phách hương hỏa không giữ lại chút nào, dung nhập máu tươi hóa thành tầng băng lớn như tu chân tinh để tự vệ trước mũi tên Cung Lý Quảng. Tuy nhiên tầng băng vẫn bị mũi tên xuyên thủng.","congNang":["Tạo tầng băng phòng hộ bằng hồn phách hương hỏa dung nhập máu tươi"],"nguon":["@c1529"]},{"id":"ban-tinh-thon-hon","name":"Bản tính thôn hồn","cn":"","loai":"bi-thuat","loaiLabel":"Năng lực bản tính","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đặc tính bẩm sinh của Vương Lâm, có khả năng hấp thụ, thôn phệ sức mạnh bên ngoài.","detail":"Vương Lâm dùng bản tính thôn hồn để hút thêm một lượng lớn sức mạnh Không Môn vốn không thuộc về mình từ trong vòng xoáy Không Môn đang tiêu tán.","thuocTinh":"","nguonGoc":"","yeuCau":"","uyLuc":"Có thể hút lượng lớn sức mạnh Không Môn vốn không thuộc về bản thân","dacDiem":"Năng lực bẩm sinh, không phải công pháp tu luyện","congNang":["Hút thêm lượng lớn sức mạnh Không Môn không thuộc về mình"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1530","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1530","loai":"thi triển","importance":"normal","giaiDoan":"Dùng trong vòng xoáy Không Môn","text":"Vương Lâm dùng bản tính thôn hồn hút lượng lớn sức mạnh Không Môn không thuộc về mình để khôi phục bảo vật cũ.","anchor":"Với bản tính thôn hồn của hắn, hắn lại một lần nữa hút ra một lượng lớn sức mạnh Không Môn không thuộc về mình"}]},"nguon":["@c1530"]},{"id":"khong-linh-trung-ky","name":"Không Linh trung kỳ","cn":"","loai":"cong-phap","loaiLabel":"Cảnh giới bước thứ ba","phamCap":"Bước thứ ba","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Không Linh trung kỳ là cảnh giới bước thứ ba mà Vương Lâm chính thức đạt tới sau khi dung hợp sáu đạo bổn nguyên và phá vỡ Không Môn, vượt qua Không Niết. Đây là cảnh giới đưa hắn trở thành bậc toàn năng của thiên địa.","detail":"Sau khi sáu đạo bổn nguyên dung nhập thành công và phá vỡ Không Môn, Vương Lâm vượt qua Không Niết để trực tiếp tiến vào bước thứ ba Không Linh trung kỳ. Chiến lão quỷ nhận định rằng việc Vương Lâm có thể vượt Không Niết và đạt thẳng cảnh giới này là nhờ sáu đạo bổn nguyên mà hắn đã dung hợp. Tại cảnh giới Không Linh trung kỳ, Vương Lâm được xem là bậc toàn năng thiên địa.","congNang":["Trở thành bậc toàn năng thiên địa sau khi dung hợp sáu đạo bổn nguyên @c1531"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1531","tangDatToi":"Không Linh trung kỳ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1531","loai":"xuat-hien","importance":"major","giaiDoan":"Vương Lâm đột phá","text":"Vương Lâm chính thức tiến vào bước thứ ba Không Linh trung kỳ sau khi sáu đạo bổn nguyên dung nhập và phá vỡ Không Môn.","anchor":"Bước thứ ba! Lúc này hắn đã chính thức tiến vào bước thứ ba Không Linh trung kỳ"}]},"nguon":["@c1531"]},{"id":"thien-kiep-nghich-tu","name":"Thiên kiếp của nghịch tu","cn":"","loai":"khac","loaiLabel":"Thiên kiếp","phamCap":"","hePhai":"","soHuu":[],"blurb":"Thiên kiếp giáng xuống tu sĩ nghịch tu thành đạo, hóa thành sương mù vô biên cô lập người độ kiếp.","detail":"Nam Vân Tử giải thích nghịch tu vì nghịch tu thành đạo nên thiên địa giáng thiên kiếp. Sương mù thiên kiếp cuồn cuộn tới mang sức mạnh thiên địa đẩy lui mấy ngàn tu sĩ, kể cả bậc cường giả như Nam Vân Tử và Tư Đồ Nam, thậm chí đẩy Chu Tước Tinh khỏi quỹ đạo. Trong phạm vi trăm vạn trượng chỉ còn một mình người độ kiếp, người ngoài rất khó tới gần nửa bước.","nguon":["@c1531"]},{"id":"loi-kiep","name":"Lôi kiếp","cn":"","loai":"khac","loaiLabel":"Thiên kiếp / Lôi đình","phamCap":"","hePhai":"","soHuu":[],"blurb":"Kiếp nạn lôi đình trong thiên kiếp mà Vương Lâm chủ động khiêu chiến, gọi nổi lên nhân danh mình.","detail":"Vương Lâm đứng giữa vòng xoáy sương mù có ngân xà lôi đình, tuyên bố trời không có tư cách giáng kiếp xuống mình và chủ động gọi lôi kiếp nổi lên nhân danh Vương Lâm.","nguon":["@c1531"]},{"id":"loi-kiep-cua-vuong-lam","name":"Lôi kiếp của riêng Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Kiếp lực","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Vương Lâm ngưng tụ ấn ký thiểm điện đỏ thẫm như máu từ mắt phải thành lôi kiếp của riêng mình, dùng nó đối kháng trực diện lôi kiếp xanh giáng xuống từ vòng xoáy thiên kiếp. Khi thiên kiếp tăng cường vượt ngưỡng, hắn triệu hàng vạn đạo xích lôi từ quanh thân đánh tan toàn bộ vòng xoáy thiên kiếp.","detail":"Trong lúc độ thiên kiếp, Vương Lâm hóa ấn ký thiểm điện đỏ thẫm như máu thành lôi kiếp của riêng mình, lấy thiên kiếp chống thiên kiếp. Lôi kiếp đỏ xông lên đối kháng thiên lôi xanh và ban đầu áp chế được, nhưng khi thiên kiếp tăng tới chín đạo hợp nhất thì lôi kiếp đỏ bị tiêu tan. Sau đó Vương Lâm triệu hàng vạn đạo xích lôi từ quanh thân, trực tiếp phá hủy vòng xoáy thiên kiếp, hoàn thành việc vượt kiếp bằng chính sấm sét của mình. @c1532","congNang":["Tạo lôi kiếp đỏ thẫm như máu từ ấn ký mắt phải để đối kháng thiên lôi xanh, ban đầu áp chế được thiên kiếp @c1532","Triệu hàng vạn đạo xích lôi từ quanh thân phá hủy toàn bộ vòng xoáy thiên kiếp @c1532"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1532","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1532","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển trong thiên kiếp bước thứ ba","text":"Vương Lâm hóa lôi kiếp đỏ đối kháng thiên lôi xanh, rồi triệu vạn đạo xích lôi phá tan vòng xoáy thiên kiếp.","anchor":"Tia chớp màu đỏ này vừa hiện ra, lập tức tản mát ra hồng quang vô tận, hóa thành lôi kiếp của Vương Lâm."}]},"nguon":["@c1532"],"uyLuc":"Hàng vạn đạo xích lôi đồng loạt bùng phát, đánh tan vòng xoáy thiên kiếp trên không @c1532","dacDiem":"Bản chất là lấy thiên kiếp chống thiên kiếp — lôi kiếp do Vương Lâm tự ngưng tụ mang sắc đỏ thẫm như máu, đối lập với thiên lôi xanh của trời giáng xuống"},{"id":"van-dao-xich-loi","name":"Vạn đạo xích lôi trừng phạt thiên kiếp","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Lôi kiếp","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Vương Lâm gọi vô số lôi kiếp đỏ từ quanh thân, tăng lên hàng vạn đạo để đánh tan vòng xoáy thiên kiếp.","detail":"Sau khi phá thiên lôi xanh hợp nhất bằng lôi bổn nguyên, Vương Lâm chỉ tay lên trời khiến lôi kiếp đỏ bùng ra từ mười đạo lên trăm đạo rồi tới hàng vạn, biến nơi đứng thành lôi vực, cùng lao vào vòng xoáy thiên kiếp cho đến khi nó tan rã hoàn toàn.","congNang":["Triệu hàng vạn xích lôi phá hủy vòng xoáy thiên kiếp"],"tabs":{"tienTrinh":[{"chuong":"@c1532","loai":"thi triển","importance":"normal","giaiDoan":"Phá tan vòng xoáy thiên kiếp","text":"Vương Lâm triệu hàng vạn xích lôi lao vào vòng xoáy thiên kiếp cho đến khi nó tan rã.","anchor":"Từng đạo lôi đình kia từ mười đạo đã lên tới trăm đạo, cuối cùng đã thành mấy vạn, ầm ầm lao đi."}]},"nguon":["@c1532"]},{"id":"hoa-kiep-cua-vuong-lam","name":"Hỏa kiếp của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Kiếp lực","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Hỏa kiếp là giai đoạn kiếp nạn Vương Lâm tự triệu hoán sau lôi kiếp, sử dụng đồ hình ngọn lửa ở mắt trái ngưng tụ biển lửa rộng mấy vạn dặm, nuốt trọn khe nứt thiên kiếp vạn trượng cùng tế đàn bốn góc bên trong.","detail":"Sau khi vượt qua lôi kiếp, Vương Lâm chuyển sang kích phát hỏa kiếp. Ông dùng đồ hình ngọn lửa ngưng tụ tại mắt trái làm khởi nguồn, tuyên bố hỏa kiếp nổi lên thiêu hủy thiên địa. Biển lửa hình thành lan rộng tới mấy vạn dặm, nuốt lấy khe nứt vạn trượng trên bầu trời lẫn tế đàn bốn góc nằm bên trong khe nứt đó. Đây là một phần trong quá trình Vương Lâm độ kiếp, thể hiện năng lực khống chế lửa kiếp ở quy mô cực lớn.","congNang":["Tạo biển lửa rộng mấy vạn dặm từ đồ hình ngọn lửa ở mắt trái @c1532","Nuốt lấy khe nứt vạn trượng trên bầu trời cùng tế đàn bốn góc bên trong @c1532"],"tabs":{"tienTrinh":[{"chuong":"@c1532","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu phát động hỏa kiếp","text":"Vương Lâm dùng đồ hình mắt trái tạo biển lửa mấy vạn dặm nuốt lấy khe nứt và tế đàn bốn góc.","anchor":"Cái khe vạn trượng ở trên bầu trời cũng bị ngọn lửa này hoàn toàn nuốt lấy."}]},"nguon":["@c1532"],"uyLuc":"Biển lửa lan rộng mấy vạn dặm, đủ sức nuốt trọn khe nứt thiên kiếp vạn trượng và tế đàn bốn góc bên trong.","dacDiem":"Khởi phát từ đồ hình ngọn lửa ngưng tụ tại mắt trái của Vương Lâm, hỏa kiếp mang tính chủ động — do chính người độ kiếp triệu hoán và điều khiển, chứ không đơn thuần là thiên kiếp giáng xuống."},{"id":"huyen-chan-kiep","name":"Huyễn Chân Kiếp","cn":"幻真劫","loai":"khac","loaiLabel":"Thiên kiếp","phamCap":"Thiên kiếp","hePhai":"Thiên Đạo","soHuu":[],"blurb":"Huyễn Chân Kiếp là một dạng thiên kiếp biến hóa sương mù thành thân ảnh chân thật của những người từng xuất hiện trong đời người chịu kiếp, nhằm công phá tâm thần bằng cách đảo lộn nhận thức thật giả. Vương Lâm nhờ đã minh ngộ chân giả bổn nguyên mà vượt qua kiếp nạn này.","detail":"Huyễn Chân Kiếp là thiên kiếp giáng xuống, sử dụng sương mù biến ảo thành vô số quỷ ảnh mang hình dáng người từng gặp trong đời người chịu kiếp — cha mẹ, tứ thúc, Vương Trác, Trương Hổ, Liễu Mi, Lý Mộ Uyển cùng những nhân vật khác — chân thật đến mức có thể đảo lộn hoàn toàn nhận thức về thật và giả. Mục đích của kiếp nạn là công phá tâm thần, khiến người chịu kiếp hoặc chìm mê trong ảo ảnh hoặc phủ nhận mọi thứ. Vương Lâm nhờ đã minh ngộ chân giả bổn nguyên mà vượt qua được kiếp nạn này.","congNang":["Biến hóa sương mù thành thân ảnh cực kỳ chân thật của những người từng xuất hiện trong đời người chịu kiếp, bao gồm cha mẹ, bằng hữu, kẻ địch, người thân @c1533","Công phá tâm thần người chịu kiếp bằng cách đảo lộn nhận thức thật giả, khiến khó phân biệt đâu là thật đâu là giả @c1533"],"nguon":["@c1533"],"tabs":{"tienTrinh":[{"chuong":"@c1533","loai":"xuat-hien","importance":"major","giaiDoan":"Giáng xuống Vương Lâm","text":"Trời giáng Huyễn Chân Kiếp, sương mù hóa thành cha mẹ, tứ thúc, Vương Trác, Trương Hổ, Liễu Mi, Lý Mộ Uyển và nhiều người khác để công tâm Vương Lâm. Bị hắn dùng chân giả bổn nguyên vượt qua.","anchor":"Trời giáng Huyễn Chân Kiếp xuống Vương Lâm"}]},"dacDiem":"Kiếp nạn thuộc hệ tâm thần, không trực tiếp gây sát thương thể xác mà dùng ký ức và người thân quen hóa ảnh để lung lạc tâm trí, chân thật đến mức có thể đảo lộn hoàn toàn nhận thức của người chịu kiếp."},{"id":"chan-gia-bon-nguyen","name":"Chân giả bổn nguyên","cn":"真假本源","loai":"cong-phap","loaiLabel":"Bổn nguyên","phamCap":"Bổn nguyên","hePhai":"Sáu đạo bổn nguyên","soHuu":["Vương Lâm"],"blurb":"Chân giả bổn nguyên là đạo lý cốt lõi mà Vương Lâm minh ngộ, cho phép phân định và chuyển hóa ranh giới giữa thật và giả, trở thành nền tảng để thi triển Chân Giả Đạo và vượt qua Huyễn Chân Kiếp. (+) Một trong lục đại bổn nguyên, phóng ra từ mi tâm, thành phần cuối cùng trong nhóm ba bổn nguyên mi tâm tạo loa. [CAN-SOAT-GOP]","detail":"Vương Lâm đã minh ngộ chân giả bổn nguyên, thấu triệt bản chất thật giả của vạn vật. Khi đối mặt với Huyễn Chân Kiếp — kiếp nạn biến ảo thật giả để công tâm tu sĩ — hắn hoàn toàn không bị dao động. Nhờ nắm vững bổn nguyên này, Vương Lâm nhắm mắt vung tay, đưa mọi thân ảnh dù thật hay giả đều trở về nơi cũ, mọi cảnh tượng biến ảo của kiếp nạn chỉ là một hồi cảm khái. Đây là sự thể hiện rằng hắn đã hoàn toàn làm chủ ranh giới giữa thật và giả, lấy đó làm gốc rễ cho Chân Giả Đạo.","congNang":["Phân định thật giả, thấu triệt bản chất chân huyễn của vạn vật","Chuyển hóa thật giả theo ý chí, đưa mọi thân ảnh dù thật hay giả trở về nơi cũ @c1533","Miễn nhiễm sự công tâm của Huyễn Chân Kiếp nhờ đã ngộ thấu bổn nguyên @c1533"],"nguon":["@c1533","@c1607"],"tabs":{"tienTrinh":[{"chuong":"@c1533","loai":"thi-trien","importance":"major","giaiDoan":"Minh ngộ hoàn toàn, vượt Huyễn Chân Kiếp","text":"Nhờ đã minh ngộ chân giả bổn nguyên, Vương Lâm không bị Huyễn Chân Kiếp công tâm, nhắm mắt vung tay đưa mọi thân ảnh về hư vô.","anchor":"Hắn đã minh ngộ được chân giả bổn nguyên, hết thảy chuyện này đối với hắn cũng chỉ là một hồi cảm khái"}]},"uyLuc":"Nhờ minh ngộ chân giả bổn nguyên, Vương Lâm hoàn toàn không bị Huyễn Chân Kiếp công tâm, nhắm mắt vung tay khiến mọi cảnh tượng thật giả biến ảo chỉ còn là một hồi cảm khái @c1533.","dacDiem":"Là đạo lý bổn nguyên về ranh giới thật giả, không thiên về chiến đấu trực tiếp mà thiên về ngộ tính và làm chủ bản chất chân huyễn, trở thành nền tảng cốt yếu của Chân Giả Đạo."},{"id":"hoa-cau-thuat","name":"Hỏa Cầu Thuật","cn":"火球术","loai":"bi-thuat","loaiLabel":"Pháp thuật","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Pháp thuật cơ bản từ ký ức Vương Lâm, bị Tam Thiên phất trần thiên kiếp tái hiện thành một trong ba nghìn thần thông công kích hắn.","detail":"Sợi tơ thứ hai của phất trần tách ra khỏi cán và hóa thành Hỏa Cầu Thuật, cho thấy thiên kiếp tái hiện cả pháp thuật cơ bản nhất trong ký ức tu luyện của Vương Lâm.","nguon":["@c1534"]},{"id":"sat-luc-kiem-quyet","name":"Sát lục kiếm quyết","cn":"杀戮剑诀","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Kiếm quyết hóa thành sát lục kiếm khí vô tận, bị thiên kiếp mô phỏng từ ký ức Vương Lâm.","detail":"Sợi tơ thứ ba của Tam Thiên phất trần hóa thành sát lục kiếm khí vô tận do sát lục kiếm quyết sinh ra, nhập vào hệ ba nghìn thần thông thiên kiếp công kích Vương Lâm.","nguon":["@c1534"]},{"id":"ba-nghin-than-thong-tam-thien-phat-tran","name":"Ba nghìn thần thông của Tam Thiên phất trần","cn":"","loai":"than-thong","loaiLabel":"Tổ hợp thần thông (thiên kiếp)","phamCap":"Cực cao (đủ giết Không Niết đại viên mãn)","hePhai":"Thiên kiếp","soHuu":[],"blurb":"Ba nghìn thần thông của Tam Thiên phất trần là chiêu thức do Tam Thiên phất trần thi triển, dùng ba nghìn sợi tơ bạc diễn hóa toàn bộ thần thông trong ký ức của đối tượng thành ba nghìn đạo công kích tiên lực tinh thuần, đồng thời dung hợp lại để phong ấn và luyện hóa mục tiêu.","detail":"Ba nghìn sợi tơ bạc của Tam Thiên phất trần bay ra, mỗi sợi lần lượt diễn hóa thành một loại thần thông mà Vương Lâm từng chứng kiến hoặc từng biết: bao gồm Dẫn Lực Thuật, Hỏa Cầu Thuật, sát lục kiếm khí, Tịch Diệt Chỉ, Hoàng Tuyền Chỉ, Hóa Ma Chỉ, cùng thần thông của Thanh Thủy, Tư Đồ Nam, Bạch Phàm, Thanh Lâm, Thủy Đạo Tử, Lỗ Phu Tử, Thái Cổ ngũ tôn và Chu Tước đời thứ nhất, đời thứ hai. Tất cả đều mang tiên lực tinh thuần, dung hợp bao phủ tinh không rồi quấn chặt Vương Lâm như phong ấn bên trong Trấn Tiên bảo tháp.","congNang":["Diễn hóa mọi thần thông trong ký ức của đối tượng thành ba nghìn đạo thần thông công kích, mỗi sợi tơ hóa một loại thần thông khác nhau @c1534","Dung hợp tiên lực tinh thuần để phong ấn và luyện hóa mục tiêu, bao phủ tinh không quấn chặt đối phương @c1534"],"tabs":{"tienTrinh":[{"chuong":"@c1534","loai":"xuat-hien","importance":"major","giaiDoan":"Thiên kiếp bước thứ ba — khe vạn trượng","text":"Ba nghìn sợi tơ bạc của Tam Thiên phất trần bay ra từ khe, diễn hóa thành ba nghìn loại thần thông mà Vương Lâm từng biết, mang tiên lực tinh thuần công kích rồi quấn chặt phong ấn hắn bên trong Trấn Tiên bảo tháp.","anchor":"ba nghìn sợi tơ ở bên ngoài cái khe, ở trước mặt Vương Lâm bất ngờ hóa thành ba nghìn loại thần thông"}]},"nguon":["@c1534"]},{"id":"dau-lau-dao-co","name":"Đầu lâu Đạo Cổ","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Hiển hóa huyết mạch","phamCap":"","hePhai":"Đạo Cổ","soHuu":["Vương Lâm"],"blurb":"Đầu lâu Đạo Cổ hiển hóa sau lưng Vương Lâm, dung hợp uy thế vào quyền kình, tạo sức công phá rung chuyển thiên địa đủ phá bảo tháp thiên kiếp.","detail":"Vương Lâm hiển hóa đầu lâu Đạo Cổ phía sau lưng, dung hợp uy thế của nó vào quyền thứ nhất rồi liên tiếp đánh ba quyền. Quyền kình mang sức mạnh Đạo Cổ rung chuyển thiên địa, khiến bảo tháp thiên kiếp phong ấn hắn nứt vỡ rồi sụp đổ hoàn toàn.","congNang":["Gia trì quyền kình đủ sức phá phong ấn bảo tháp thiên kiếp"],"tabs":{"tienTrinh":[{"chuong":"@c1535","loai":"thi triển","importance":"normal","giaiDoan":"Hiển hóa trong thiên kiếp","text":"Vương Lâm hiển hóa đầu lâu Đạo Cổ sau lưng, dung hợp uy thế vào quyền kình đánh ba quyền phá sập bảo tháp thiên kiếp.","anchor":"đầu lâu Đạo Cổ phía sau lưng hắn càng gầm thét kịch liệt hơn"}]},"nguon":["@c1535"]},{"id":"luc-phong-an-phong-diet-toc","name":"Lực phong ấn của Phong Diệt Tộc","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật / Phong ấn","phamCap":"","hePhai":"Phong Diệt Tộc","soHuu":["Phong Diệt Tộc"],"blurb":"Lực phong ấn đặc trưng của Phong Diệt Tộc, cơ chế tương tự nhưng không hoàn toàn giống Phong Mệnh Hoàn.","detail":"Vương Lâm khi phân tích kết cấu Phong Mệnh Hoàn nhận ra cơ chế phong ấn của bảo vật cực kỳ giống với lực phong ấn của Phong Diệt Tộc, tuy vẫn có điểm khác biệt.","nguon":["@c1535"]},{"id":"bon-nga-kiep","name":"Bổn Ngã kiếp","cn":"本我劫","loai":"khac","loaiLabel":"Thiên kiếp / Kiếp nạn","phamCap":"","hePhai":"","soHuu":[],"blurb":"Bổn Ngã kiếp là một kiếp nạn trong thiên kiếp, sinh ra đối thủ đồng dạng bản ngã sở hữu toàn bộ ngoại hình, thần thông và khả năng cảm ứng suy nghĩ của người vượt kiếp. Muốn biết bí mật của thiên kiếp, người vượt kiếp buộc phải đánh bại chính bản ngã đối lập này.","detail":"Bổn Ngã kiếp tạo ra một đối thủ có ngoại hình, y phục, thần sắc, bổn nguyên và mọi thần thông giống hệt người vượt kiếp. Đối thủ này không chỉ sở hữu toàn bộ năng lực của bản thể gốc mà còn có khả năng cảm ứng suy nghĩ của người vượt kiếp, khiến mọi thần thông thi triển đều bị đối phương dùng y hệt và đối kháng ngang bằng. Đối thủ do Bổn Ngã kiếp sinh ra tự xưng là chính người vượt kiếp và tuyên bố rằng chỉ khi đánh bại hắn mới có thể biết được bí mật của thiên kiếp. @c1537","congNang":["Tạo ra đối thủ đồng dạng bản ngã có ngoại hình, y phục, thần sắc, bổn nguyên và toàn bộ thần thông giống hệt người vượt kiếp @c1537","Đối thủ có khả năng cảm ứng suy nghĩ của bản thể gốc, khiến mọi thần thông thi triển đều bị đối kháng ngang bằng @c1537"],"tabs":{"tienTrinh":[{"chuong":"@c1537","loai":"xuất hiện","importance":"major","giaiDoan":"Vương Lâm đối mặt Bổn Ngã kiếp","text":"Thanh niên tóc bạc tự xưng là Vương Lâm, gọi đây là Bổn Ngã kiếp và tuyên bố đánh bại hắn mới biết bí mật thiên kiếp. Mọi thần thông đều bị đối kháng ngang bằng.","anchor":"có thể là người thoát khói Bổn Ngã kiếp này"}]},"nguon":["@c1537"],"dacDiem":"Đối thủ do kiếp nạn sinh ra là bản sao hoàn hảo về hình dạng lẫn thần thông, đồng thời đọc được suy nghĩ của bản thể gốc, khiến người vượt kiếp không thể dùng chiến thuật hay thần thông thông thường để giành lợi thế."},{"id":"dao-lua-gat","name":"Đạo lừa gạt","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Lưu Kim Bưu","soHuu":["Vương Lâm"],"blurb":"Đạo lừa gạt là thủ đoạn liên quan tới Lưu Kim Bưu, được Vương Lâm dùng Mộng Đạo hóa thành trong trận chiến với thanh niên tóc bạc (bản ngã kiếp), nhằm tự lừa gạt chính bản thân mình để tách trạng thái điên cuồng và tỉnh táo, từ đó phá vỡ khả năng cảm ứng đồng bộ suy nghĩ của đối phương.","detail":"Trong cuộc giao chiến với thanh niên tóc bạc — vốn là bản ngã kiếp có khả năng sao chép mọi suy nghĩ của Vương Lâm — Vương Lâm âm thầm thi triển Mộng Đạo rồi trong khoảnh khắc Định Thần thuật có hiệu lực, hóa thành Đạo lừa gạt. Bằng cách tự lừa bản thân rơi vào trạng thái điên cuồng, hắn khiến phần tỉnh táo thực sự được giấu kín hoàn toàn, bản ngã kiếp dù đọc được suy nghĩ cũng chỉ cảm ứng được phần điên cuồng mà không hay biết ý đồ thật. Nhờ vậy thế cảm ứng đồng bộ giữa hai bên bị phá vỡ. Sau khi bị lừa, thanh niên tóc bạc nhận ra đây chính là Đạo lừa gạt của Lưu Kim Bưu.","congNang":["Tự lừa gạt bản thân, tách thành hai trạng thái song song: phần điên cuồng chiến đấu lộ ra bên ngoài và phần tỉnh táo chờ thời cơ ẩn bên trong @c1538","Phá vỡ khả năng cảm ứng đồng bộ suy nghĩ của đối phương (bản ngã kiếp), khiến kẻ đọc suy nghĩ chỉ sao chép được phần điên cuồng giả mà không phát hiện ý đồ thật @c1538"],"nguonGoc":"Liên quan tới Lưu Kim Bưu","tabs":{"tienTrinh":[{"chuong":"@c1538","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu sử dụng trong bổn ngã kiếp","text":"Vương Lâm dùng Mộng Đạo hóa thành Đạo lừa gạt, tự lừa bản thân để phá cảm ứng đồng bộ với thanh niên tóc bạc, từ đó tạo cơ hội đánh trúng bản ngã kiếp bằng Nhân Quả Ấn và Sinh Tử Ấn.","anchor":"Ngươi có thể lừa gạt bản thân trước.ta hiểu rồi.Đạo lừa gạt"}]},"nguon":["@c1538"]},{"id":"dinh-khong-thuat","name":"Định Không Thuật","cn":"定空术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đại thần thông cấp tiên tôn","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Định Không Thuật là đại thần thông của tiên tôn đại nhân, được Vương Lâm thi triển bằng cách điểm một ngón tay niệm chữ Định, có thể đình chỉ toàn bộ chuyển động kể cả năm tháng trong thiên địa. Thuật này trấn áp hoàn toàn tiên nhân, khiến lão già tiên nhân hộ vệ kinh hãi nhận ra nguồn gốc của nó.","detail":"Định Không Thuật được lão già tiên nhân hộ vệ của tiên tôn nhận định là đại thần thông của tiên tôn đại nhân. Vương Lâm thi triển thuật này bằng cách điểm một ngón tay và niệm chữ Định, hiệu quả phát huy tức thì: đối phương bị định thân, máu tươi đông cứng giữa không trung, toàn bộ năm tháng và mọi chuyển động trong thiên địa đều ngừng lại. Khi Vương Lâm sử dụng Định Không Thuật trấn áp hoàn toàn lão già tiên nhân hộ vệ, vị này kinh hãi nhận ra đây là đại thần thông của tiên tôn đại nhân và tự hỏi ai đã truyền cho Vương Lâm.","thuocTinh":"Không gian, Thời gian","nguonGoc":"Đại thần thông của tiên tôn đại nhân (theo nhận định của lão già tiên nhân hộ vệ)","uyLuc":"Đình chỉ toàn bộ chuyển động kể cả năm tháng trong thiên địa, trấn áp hoàn toàn tiên nhân cấp lão già hộ vệ của tiên tôn.","dacDiem":"Chỉ cần điểm một ngón tay niệm chữ Định, tác dụng phát huy tức thì, không cần thủ ấn hay nghi thức phức tạp.","congNang":["Định thân đối phương, khiến thân thể không thể chuyển động @c1542","Đông cứng mọi thứ kể cả máu tươi giữa không trung @c1542","Đình chỉ năm tháng và mọi chuyển động trong thiên địa @c1542","Trấn áp hoàn toàn tiên nhân @c1542"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1542","tangDatToi":"","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1542","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Vương Lâm điểm một ngón tay niệm Định, thi triển Định Không Thuật trấn áp hoàn toàn lão già tiên nhân hộ vệ tiên tôn. Mọi chuyển động kể cả năm tháng trong thiên địa đều ngừng lại. Lão già kinh hãi nhận ra đây là đại thần thông cấp tiên tôn.","anchor":"Định Không Thuật! Đây là đại thần thông của tiên tôn đại nhân, Định Không Thuật!"}]},"nguon":["@c1542"]},{"id":"thuat-soat-hon","name":"Thuật soát hồn","cn":"","aliases":["tra xét trí nhớ"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông dùng thần thức xâm nhập thức hải đối phương để đọc toàn bộ trí nhớ, bị phong ấn tiên tôn chặn lại.","detail":"Vương Lâm dùng thần thức tràn vào thức hải lão già sĩ tiên để thu lấy toàn bộ trí nhớ. Trong thức hải gặp phong ấn dạng sương mù che chắn, bên trong có nam tử bảy màu — phong ấn tiên tôn ngăn cản tra xét.","congNang":["Đọc toàn bộ trí nhớ đối phương thông qua thần thức xâm nhập thức hải"],"nguon":["@c1543"]},{"id":"co-toc-bat-diet-chi","name":"Cổ Tộc Bất Diệt Chỉ","cn":"古族不灭指","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cổ Tộc","soHuu":["Vương Lâm"],"blurb":"Cổ Tộc Bất Diệt Chỉ là thần thông Vương Lâm tự sáng tạo trong mộng đạo, cảm ngộ từ tiên nhân bất diệt thể, ngưng tụ toàn bộ lực lượng tam tộc cổ vào một ngón trỏ để đạt hiệu quả bất diệt thể trên một ngón tay. Lần đầu thi triển tại @c1544, thần thông này phá được phong ấn tiên tôn mà ngay cả Tứ Thánh Hoàng đỉnh cao đồng loạt ra tay cũng không phá nổi.","detail":"Trong mộng đạo, Vương Lâm cảm ngộ từ tiên nhân bất diệt thể mà tự sáng tạo nên Cổ Tộc Bất Diệt Chỉ — một thần thông hoàn toàn không dựa vào tiên lực, thay vào đó kích phát đồng thời lực lượng Cổ Thần, Cổ Ma, Cổ Yêu, tức toàn bộ truyền thừa tam tộc cổ, ngưng tụ vào một ngón trỏ duy nhất. Với tu vi hiện tại, Vương Lâm chỉ có thể khiến một ngón tay đạt trạng thái bất diệt. Khi thi triển lần đầu (@c1544), ngón tay chỉ ra phong ấn ba tấc của tiên tôn, trải qua quá trình tan rã rồi khôi phục nghìn vạn lần trong nháy mắt; cuối cùng tốc độ khôi phục vượt qua tốc độ tan rã, xuyên phá phong ấn mà Tứ Thánh Hoàng đỉnh cao hợp lực cũng không thể phá — thể hiện uy lực vượt hẳn tầm tu vi của Vương Lâm thời điểm đó. Hiệu quả của thần thông này được đánh giá là không kém bất diệt thể chân chính, dù chỉ giớ","thuocTinh":"Cổ Tộc (tam tộc cổ + Đạo Cổ)","nguonGoc":"Vương Lâm tự sáng tạo trong mộng đạo, cảm ngộ từ tiên nhân bất diệt thể","uyLuc":"Phá được phong ấn ba tấc của tiên tôn mà Tứ Thánh Hoàng đỉnh cao đồng loạt ra tay cũng không phá nổi.","dacDiem":"Không sử dụng tiên lực, hoàn toàn dùng lực tam tộc cổ; ngón tay tan rã rồi khôi phục nghìn vạn lần trong nháy mắt, đạt hiệu quả bất diệt thể ở phạm vi một ngón tay; với tu vi hiện tại của Vương Lâm chỉ giới hạn được ở một ngón tay duy nhất.","congNang":["Ngưng tụ đồng thời lực lượng Cổ Thần, Cổ Ma, Cổ Yêu vào ngón trỏ, tạo đòn công kích cực mạnh @c1544","Khôi phục bất diệt — ngón tay bị huỷ diệt lập tức tái sinh, tan rồi khôi phục nghìn vạn lần trong nháy mắt @c1544","Phá phong ấn tiên tôn bằng cách duy trì tốc độ khôi phục vượt tốc độ tan rã, xuyên thấu phong ấn @c1544"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1544","tangDatToi":"Một ngón tay bất diệt","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1544","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm lần đầu thi triển Cổ Tộc Bất Diệt Chỉ, kích phát đồng thời lực lượng Cổ Thần, Cổ Ma, Cổ Yêu cùng đầu lâu Đạo Cổ ngưng tụ vào ngón trỏ. Ngón tay tan rã-khôi phục nghìn vạn lần xuyên qua giới hạn ba tấc phong ấn của tiên tôn, phá vỡ phong ấn bảo vệ ký ức hạch tâm Thất Đạo Tông.","anchor":"Cổ Tộc Bất Diệt Chỉ ngưng tụ truyền thừa Đạo Cổ, ngưng tụ toàn bộ lực lượng của tam tộc cổ"}]},"nguon":["@c1544"]},{"id":"ho-khieu-son-ha","name":"Hổ Khiếu Sơn Hà","cn":"虎啸山河","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông bổn nguyên hung tinh Bạch Hổ","hePhai":"Hung tinh Bạch Hổ","soHuu":["Bạch Hổ Thánh Hoàng"],"blurb":"Thức thứ nhất trong ba thức thần thông bổn nguyên của Bạch Hổ Thánh Hoàng, triệu hoán hư ảnh Bạch Hổ khổng lồ cao tận trời gầm thét chấn động thiên không đại địa. Uy lực đủ cuốn tan tinh không giới nội giới ngoại, giết hàng loạt tu sĩ.","detail":"Hổ Khiếu Sơn Hà là thần thông bổn nguyên thuộc lực lượng hung tinh Bạch Hổ, do Bạch Hổ Thánh Hoàng nắm giữ, đồng thời là thức thứ nhất trong tổng cộng ba thức. Khi thi triển, hư ảnh Bạch Hổ cao tận trời hiện ra giữa thiên không, phát tiếng gầm kinh thiên động địa khiến thiên không xuất hiện sóng gợn xé ra khe hở, đại địa sụp đổ nứt vỡ, cuồng phong gào thét cuốn phá tứ phương. Tại viễn cổ tiên vực, Bạch Hổ Thánh Hoàng từng thi triển thức này để đối đầu Vương Lâm, cho thấy uy lực chấn nhiếp ở tầng cấp đỉnh phong.","thuocTinh":"Hung tinh Bạch Hổ","nguonGoc":"Thần thông bổn nguyên của Bạch Hổ Thánh Hoàng","uyLuc":"Đủ cuốn tan tinh không giới nội giới ngoại, thiên không xé khe hở, đại địa sụp đổ nứt vỡ, giết hàng loạt tu sĩ.","dacDiem":"Gồm ba thức, đây là thức thứ nhất. Tiếng hổ gầm chấn động thiên không đại địa, uy áp siêu việt.","congNang":["Triệu hoán hư ảnh Bạch Hổ khổng lồ cao tận trời gầm thét, tạo sóng âm chấn động thiên không đại địa @c1547","Cuồng phong sóng âm đủ cuốn tan tinh không giới nội giới ngoại, giết vô số tu sĩ @c1547"],"nguoiTu":[{"ten":"Bạch Hổ Thánh Hoàng","tuChuong":"@c1547","tangDatToi":"Thức thứ nhất","trangThai":"thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1547","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Bạch Hổ Thánh Hoàng thi triển thức thứ nhất đối đầu Vương Lâm trong viễn cổ tiên vực, triệu hoán hư ảnh Bạch Hổ cao tận trời gầm thét chấn động thiên không. Uy lực đủ cuốn tan tinh không giới nội giới ngoại nhưng bị Vương Lâm dùng Chân Giả bổn nguyên hóa giải hoàn toàn.","anchor":"Thức thứ nhất. Hổ khiếu sơn hà!"}]},"capNhatToi":"@c1547","nguon":["@c1547"]},{"id":"khai-thien-dao","name":"Khai thiên đao","cn":"开天刀","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Hung tinh Bạch Hổ","soHuu":["Bạch Hổ Thánh Hoàng"],"blurb":"Khai Thiên Đao là chiêu thức ngưng tụ kim quang thành thanh đao vàng dài mười trượng, chém trực tiếp vào thiên linh đối thủ. Được Bạch Hổ Thánh Hoàng thi triển trong trận chiến với Vương Lâm, đao chém liên tục hàng ngàn lần nhưng xuyên qua thân thể như hư ảnh do đối phương đã ngộ Chân Giả bổn nguyên.","detail":"Bạch Hổ Thánh Hoàng (Bạch Hổ lão giả) ngưng tụ kim quang trong tay hóa thành thanh đao khai thiên màu vàng dài mười trượng, mang uy lực trực tiếp tấn công thiên linh đối thủ thay vì nhắm vào nhục thân. Trong trận đối đầu với Vương Lâm, đao chém liên tục mấy trăm mấy ngàn lần, tuy nhiên mỗi nhát chém đều xuyên qua thân thể Vương Lâm như hư ảnh, do Vương Lâm đã lĩnh ngộ Chân Giả bổn nguyên khiến chiêu thức không thể tạo sát thương.","congNang":["Ngưng tụ kim quang thành đao vàng dài mười trượng, chém trực tiếp vào thiên linh đối thủ @c1547"],"nguoiTu":[{"ten":"Bạch Hổ Thánh Hoàng","tuChuong":"@c1547","tangDatToi":"","trangThai":"thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1547","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Bạch Hổ lão giả ngưng tụ kim quang thành thanh đao khai thiên màu vàng dài mười trượng, chém liên tục hàng ngàn lần vào Vương Lâm nhưng xuyên qua như hư ảnh do Chân Giả bổn nguyên.","anchor":"kim quang lóe lên, ngưng tụ trong tay Bạch Hổ lão giả, không ngờ lại hóa thành một thanh đao khai thiên màu vàng"}]},"capNhatToi":"@c1547","nguon":["@c1547"],"uyLuc":"Chém liên tục hàng ngàn lần vào thiên linh đối thủ, nhưng bị Chân Giả bổn nguyên của Vương Lâm hóa giải hoàn toàn, đao xuyên qua thân thể như hư ảnh.","dacDiem":"Kim quang ngưng tụ hóa đao màu vàng, kích thước mười trượng, tấn công trực chỉ thiên linh chứ không nhắm vào nhục thân."},{"id":"ky-ho-nan-ha","name":"Kỵ Hổ Nan Hạ","cn":"骑虎难下","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đại thuật thần thông cấp tiên nhân","hePhai":"Bộ tộc Bạch Hổ (tiên cương đại lục)","soHuu":["Bạch Hổ Thánh Hoàng"],"blurb":"Kỵ Hổ Nan Hạ là đại thuật thần thông của bộ tộc Bạch Hổ tại tiên cương đại lục, vừa mang tính chất thần thông vừa là thuật phong ấn. Thuật này ngưng bạch quang thành Bạch Hổ khổng lồ dưới chân đối thủ, phong ấn thiên địa rồi phóng hổ linh bản mệnh nuốt thiên linh đối phương để trấn áp thần hồn dưới thiên sơn tiên cương đại lục.","detail":"Kỵ Hổ Nan Hạ xuất phát từ bộ tộc Bạch Hổ trên tiên cương đại lục, do Bạch Hổ chiến tướng bắt quyết ngưng tụ bạch quang thành Bạch Hổ khổng lồ dưới chân mục tiêu, uy áp bộc phát phong ấn thiên địa khiến đối thủ bị trói trên lưng hổ không thể rời đi — đúng nghĩa \"cưỡi hổ khó xuống\". Bạch Hổ sau đó biến thành dòng xoáy trắng khổng lồ chứa vô số ký hiệu phong ấn chạy vòng tròn. Tiếp theo, thí thuật giả hô \"Bạch Hổ linh khởi\", từ dòng xoáy xuất hiện hổ linh — tức linh hồn bản mệnh, tương tự nguyên thần của tu sĩ — cao mười trượng, thu nhỏ lao về quấn quanh đối thủ, mở hổ khẩu muốn nuốt thiên linh rồi mang vào dòng xoáy trấn áp thần hồn dưới sáu mươi bảy đạo thiên sơn trên tiên cương đại lục. Thuật này được Bạch Hổ lão giả thi triển trong trận đấu với Vương Lâm tại viễn cổ tiên vực, nhưng bị Vươ","thuocTinh":"Kim (Bạch Hổ — kim tinh trong vạn vật)","nguonGoc":"Bộ tộc Bạch Hổ, tiên cương đại lục","dacDiem":"Vừa là thần thông vừa là thuật phong ấn, cần phóng hổ linh bản mệnh để thi triển; tên gọi ẩn dụ \"cưỡi hổ khó xuống\" — đối thủ một khi bị trói trên lưng Bạch Hổ thì không thể thoát, thiên linh bị nuốt sẽ bị trấn áp vĩnh viễn dưới thiên sơn.","congNang":["Ngưng tụ bạch quang thành Bạch Hổ khổng lồ dưới chân đối thủ, phong ấn thiên địa xung quanh khiến đối thủ bị trói trên lưng hổ không thể rời đi @c1548","Bạch Hổ biến thành dòng xoáy trắng khổng lồ chứa vô số ký hiệu phong ấn chạy vòng tròn @c1548","Phóng hổ linh bản mệnh (linh hồn bản mệnh, tương tự nguyên thần tu sĩ) mười trượng, thu nhỏ lao về quấn quanh đối thủ, mở hổ khẩu nuốt thiên linh đối phương @c1548","Trấn áp thần hồn đối thủ dưới sáu mươi bảy đạo thiên sơn trên tiên cương đại lục @c1548"],"nguoiTu":[{"ten":"Bạch Hổ Thánh Hoàng","tuChuong":"@c1548","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1548","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Bạch Hổ lão giả thi triển Kỵ Hổ Nan Hạ trong trận đấu với Vương Lâm tại viễn cổ tiên vực, phong ấn thiên địa trói Vương Lâm trên lưng hổ rồi phóng hổ linh mưu nuốt thiên linh. Hổ linh bị khí thế đại nho của Vương Lâm trấn áp, cúi đầu quy phục.","anchor":"Đây là đại thuật thần thông của Bạch Hổ chiến tướng - Kỵ Hổ Nan Hạ!"}]},"nguon":["@c1548"]},{"id":"sau-chuong-an-lien-hoan","name":"Sáu chưởng ấn liên hoàn","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Tổ hợp chiêu thức","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Sáu chưởng ấn liên hoàn là tổ hợp sáu chưởng ấn liên tục do Vương Lâm thi triển, gồm lửa chín màu, sấm sét, nhân quả bổn nguyên, sinh tử bổn nguyên, chân giả bổn nguyên và sát lục khí, tạo thành chuỗi tàn ảnh. Uy lực đủ sức phá vỡ khai thiên đao và trọng thương tàn tiên Bạch Hổ chiến tướng.","detail":"Vương Lâm thi triển sáu chưởng ấn liên tục tạo thành chuỗi như tàn ảnh, mỗi chưởng mang một lực lượng bổn nguyên hoặc nguyên tố khác nhau: (1) lửa chín màu, (2) sấm sét, (3) nhân quả bổn nguyên, (4) sinh tử bổn nguyên, (5) chân giả bổn nguyên, (6) sát lục khí. Sáu chưởng ấn nối tiếp nhau không ngừng, kết hợp nhiều loại đại đạo bổn nguyên cùng các thần thông sở trường, tạo nên sức công kích cộng hưởng cực mạnh. Trong trận chiến với Bạch Hổ chiến tướng — một tàn tiên, chuỗi sáu chưởng này đã phá tan khai thiên đao và gây trọng thương đối phương.","congNang":["Sáu chưởng liên hoàn phá vỡ khai thiên đao @c1549","Trọng thương tàn tiên Bạch Hổ chiến tướng @c1549"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1549","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1549","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm thi triển sáu chưởng ấn liên tục (lửa chín màu, sấm sét, nhân quả bổn nguyên, sinh tử bổn nguyên, chân giả bổn nguyên, sát lục khí) phá tan khai thiên đao và trọng thương Bạch Hổ chiến tướng.","anchor":"thanh khai thiên đao trong tay Bạch Hổ chiến tướng chấn động mãnh liệt, trực tiếp tan nát"}]},"nguon":["@c1549"],"uyLuc":"Phá vỡ khai thiên đao và trọng thương tàn tiên Bạch Hổ chiến tướng.","dacDiem":"Sáu chưởng ấn thi triển liên tục tạo thành chuỗi tàn ảnh, mỗi chưởng mang một loại lực lượng khác nhau gồm lửa chín màu, sấm sét, nhân quả bổn nguyên, sinh tử bổn nguyên, chân giả bổn nguyên và sát lục khí."},{"id":"dai-tran-ha-gioi","name":"Đại trận hạ giới","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Tiên nhân cấp","hePhai":"Tứ đại chiến tướng / hạ giới","soHuu":[],"blurb":"Đại trận phòng thủ hạ giới được tứ đại chiến tướng hỗ trợ bằng pháp bảo tiên nhân, có thể chống cự giới ngoại 100 năm.","detail":"Trước đó có người hạ giới kêu gọi chống giới ngoại, tứ đại chiến tướng đưa một loại pháp bảo tiên nhân dung nhập vào đại trận hạ giới. Trận này chống cự được 100 năm để tranh thủ thời gian trị thương. Đã qua hơn 90 năm, còn 3 năm nữa. Cần sức mạnh đại lục Tiên Cương hoặc tu sĩ hạ giới mới mở ra được.","congNang":["Phòng thủ chống giới ngoại trong 100 năm nhờ pháp bảo tiên nhân dung nhập"],"nguon":["@c1550"],"tabs":{"tienTrinh":[{"chuong":"@c1550","loai":"nhắc tới","importance":"normal","giaiDoan":"Thanh Long tiết lộ cơ chế phòng thủ","text":"Thanh Long chiến tướng tiết lộ tứ đại chiến tướng đã giao pháp bảo tiên nhân cho một người hạ giới dung nhập vào đại trận, chống cự giới ngoại 100 năm. Đã qua hơn 90 năm, còn 3 năm nữa thương thế hồi phục hoàn toàn.","anchor":"Chúng ta đã đưa cho hắn một loại pháp bảo của tiên nhân dung nhập vào trong một đại trận của hạ giới"}]}},{"id":"sanh-tu-chan-gia-nhan-qua-tran","name":"Sanh Tử Chân Giả Nhân Quả trận","cn":null,"aliases":["Trận pháp Tam Đại Bổn Nguyên","Sinh Tử Nhân Quả Chân Giả đại trận"],"loai":"bi-thuat","loaiLabel":"Trận pháp bổn nguyên","phamCap":"Không rõ","hePhai":"Tam đại bổn nguyên","soHuu":["Vương Lâm"],"blurb":"Sanh Tử Chân Giả Nhân Quả trận là trận pháp bổn nguyên do Vương Lâm dung hợp tam đại hư bổn nguyên (sinh, tử, nhân quả) mà minh ngộ, lần đầu thi triển tại Triệu Hà tinh vực. Trận pháp vây khốn nguyên thần trong đầu lâu, khiến chúng trải qua thống khổ sinh tử chân giả nhân quả vô tận, là bước đầu tiên gieo trồng mầm mống sát lục.","detail":"Sanh Tử Chân Giả Nhân Quả trận là trận pháp bổn nguyên do Vương Lâm dung hợp tam đại bổn nguyên — sinh bổn nguyên, tử bổn nguyên và nhân quả bổn nguyên, cả ba đều ở dạng hư bổn nguyên — mà minh ngộ. Trận pháp được thi triển lần đầu tại Triệu Hà tinh vực (@c1554). Cơ chế vận hành của trận là dùng tam đại hư bổn nguyên vây khốn nguyên thần cùng hồn phách của tu sĩ tử vong bên trong đầu lâu, khiến họ liên tục trải qua sinh tử luân hồi, chân giả lẫn lộn, nhân quả xoay chuyển trong thống khổ vô tận, không thể thoát ra. Trận pháp này đóng vai trò là bước đầu tiên trong tiến trình gieo trồng mầm mống sát lục của Vương Lâm.","thuocTinh":"Sinh tử, chân giả, nhân quả","nguonGoc":"Vương Lâm dung hợp tam đại bổn nguyên minh ngộ","congNang":["Dùng tam đại hư bổn nguyên (sinh, tử, nhân quả) vây khốn nguyên thần và hồn phách tu sĩ tử vong bên trong đầu lâu, khiến chúng trải qua thống khổ sinh tử chân giả nhân quả vô tận (@c1554)","Là bước đầu tiên gieo trồng mầm mống sát lục (@c1554)"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1554","tangDatToi":"Lần đầu thi triển","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1554","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm lần đầu thi triển Sanh Tử Chân Giả Nhân Quả trận tại Triệu Hà tinh vực, dùng tam đại hư bổn nguyên vây khốn nguyên thần trong mấy trăm đầu lâu, khiến chúng trải qua thống khổ sinh tử chân giả nhân quả vô tận, là bước đầu gieo trồng mầm mống sát lục.","anchor":"Trận pháp này là trận pháp bổn nguyên!"}]},"capNhatToi":"@c1554","nguon":["@c1554"]},{"id":"minh-phe-cuc-lac","name":"Minh phệ cực lạc","cn":"冥噬极乐","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Minh Linh tộc","soHuu":["Tộc trưởng Minh Linh tộc"],"blurb":"Thần thông độc môn của Minh Linh tộc, rút sinh cơ từ thất khiếu nạn nhân ngưng tụ thành hư ảnh nguyên thần rồi thôn phệ.","detail":"Tộc trưởng Minh Linh tộc thi triển trên ba trăm nữ tu Triệu Hà, rút sinh cơ từ thất khiếu khiến thân thể khô héo, nguyên thần bị kéo ra bay về phía hắn chuẩn bị nuốt. Bị Vương Lâm phá ngang trước khi hoàn thành.","congNang":["Rút sinh cơ từ thất khiếu nạn nhân, ngưng tụ thành hư ảnh nguyên thần rồi thôn phệ"],"nguoiTu":[{"ten":"Tộc trưởng Minh Linh tộc","tuChuong":"@c1555","tangDatToi":"","trangThai":"tu-vong"}],"tabs":{"tienTrinh":[{"chuong":"@c1555","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển trên nữ tu Triệu Hà, bị phá ngang","text":"Tộc trưởng Minh Linh tộc dùng Minh phệ cực lạc rút sinh cơ ba trăm nữ tu Triệu Hà nhưng bị Vương Lâm hừ lạnh phá ngang trước khi hoàn thành.","anchor":"Minh phệ cực lạc!"}]},"nguon":["@c1555"]},{"id":"sinh-tu-tran","name":"Sinh tử trận","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Trận pháp có thể tạo thành từ năm vạn đầu lâu. Vương Lâm nhận ra khả năng bày trận này sau khi tích lũy đủ đầu lâu tu sĩ giới ngoại.","detail":"Vương Lâm nhận ra năm vạn đầu lâu thu được từ tu sĩ giới ngoại có thể tạo thành sinh tử trận. Chi tiết cụ thể về uy lực và cách vận hành chưa được hé lộ.","nguon":["@c1556"]},{"id":"phuong-phap-nuoi-dan-huong-hoa","name":"Phương pháp nuôi dân hương hỏa để sinh hư bổn nguyên","cn":"","loai":"cong-phap","loaiLabel":"Phương pháp tu luyện","phamCap":"Bước thứ ba","hePhai":"","soHuu":[],"blurb":"Phương pháp do kỳ nhân bước thứ ba sáng tạo, lợi dụng dân hương hỏa tu luyện bên trong hương hỏa giới hư ảo để sinh ra hư bổn nguyên, rồi chủ nhân thôn phệ lấy nhằm từ Không Linh viên mãn tiến lên Không Huyền. Nguyên lý hoàn chỉnh của phương pháp này được hé lộ qua ký ức trong đầu lâu một tu sĩ bước thứ ba.","detail":"Tu sĩ bước thứ ba ở cảnh giới Không Niết thôn phệ đạo linh ngưng cố hương hỏa giới; đến Không Linh thì hương hỏa giới hòa hợp với thân thể, lấy thân mình làm thiên địa. Từ Không Linh viên mãn muốn đột phá lên Không Huyền, tu sĩ cần hư bổn nguyên — loại bổn nguyên vô hình thuộc phạm trù nhân quả, sinh tử, chân giả, chỉ có thể cảm ngộ chứ không thể nắm bắt trực tiếp, rất khó đại thành. Một kỳ nhân đã nghĩ ra phương pháp: bên trong hương hỏa giới của mình, huyễn hóa sông núi luân hồi, khiến dân hương hỏa tu luyện mà không hề hay biết thế giới họ đang sống chỉ là hư ảo. Khi dân hương hỏa sinh ra hư bổn nguyên, chủ nhân lập tức thôn phệ lấy. Dân hương hỏa một khi rời khỏi hương hỏa giới sẽ mất hết tu vi, trở thành phàm nhân. Phương pháp này dẫn đến một nghi vấn triết học sâu xa: liệu thế giới m","nguon":["@c1556"],"congNang":["Khiến dân hương hỏa tu luyện bên trong hương hỏa giới hư ảo, huyễn hóa sông núi luân hồi, dân hương hỏa không biết thế giới mình là hư @c1556","Khi dân hương hỏa sinh ra hư bổn nguyên thì chủ nhân thôn phệ, thu hoạch hư bổn nguyên để từ Không Linh viên mãn tiến lên Không Huyền @c1556","Dân hương hỏa rời khỏi hương hỏa giới sẽ mất hết tu vi, trở thành phàm nhân @c1556"],"tabs":{"tienTrinh":[{"chuong":"@c1556","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Hé lộ nguyên lý","text":"Ký ức từ đầu lâu tu sĩ bước thứ ba hé lộ toàn bộ nguyên lý: nuôi dân hương hỏa tu luyện trong hương hỏa giới hư ảo, thôn phệ hư bổn nguyên họ sinh ra. Đặt ra câu hỏi liệu thế giới thật cũng là hương hỏa giới.","anchor":"Phương pháp của bọn họ là ở bên trong hương hỏa giới của mình khiến cho dân hương hỏa của họ tu luyện"}]},"dacDiem":"Phương pháp mang bản chất nuôi trồng — biến dân hương hỏa thành nguồn cung cấp hư bổn nguyên một cách thụ động; đồng thời đặt ra nghi vấn triết học về tính chân thực của thiên địa mà chính tu sĩ đang tồn tại."},{"id":"sinh-tu-tran-vuong-lam","name":"Sinh Tử trận","cn":"生死阵","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Cực mạnh (cấp tinh vực)","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Sinh Tử trận là trận pháp cấp tinh vực do Vương Lâm sáng tạo từ năm vạn đầu lâu và nguyên thần tu sĩ giới ngoại, ngưng kết bằng tâm thần huyết bước thứ ba thành hình bánh xe khổng lồ mười vạn trượng — không chuyển thì chúng sinh tồn, chuyển thì diệt vong.","detail":"Vương Lâm thu thập năm vạn đầu lâu tu sĩ giới ngoại làm nguyên liệu, chia thành hai dòng xoáy: tay trái đại biểu sinh, tay phải đại biểu tử. Sau đó bắt quyết đưa cấm chế vào, hai dòng xoáy xếp chồng dung hợp thành một thể khuếch tán tới mười vạn trượng. Cuối cùng phun tâm thần huyết bước thứ ba vào khiến dòng xoáy ngưng kết thành hình bánh xe khổng lồ lơ lửng trên không, hoàn thành trận pháp. Trận pháp này có thể dùng làm vũ khí tấn công phóng thẳng vào đại lục, đạt cấp uy lực tinh vực.","congNang":["Trận pháp tấn công cấp tinh vực, dùng đầu lâu và nguyên thần tu sĩ làm nguyên liệu @c1557","Phân năm vạn đầu lâu thành hai dòng xoáy sinh tử, dung hợp thành hình bánh xe mười vạn trượng @c1557","Không chuyển thì chúng sinh tồn, chuyển thì diệt vong @c1557","Cần tâm thần huyết bước thứ ba để ngưng kết thành hình @c1557","Có thể phóng thẳng vào đại lục làm vũ khí tấn công @c1557"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1557","tangDatToi":"Đại thành","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1557","loai":"xuất hiện","importance":"major","giaiDoan":"Bố trận thành công","text":"Vương Lâm dùng năm vạn đầu lâu tu sĩ giới ngoại, phân sinh tử hai dòng xoáy rồi dung hợp, phun tâm thần huyết bước thứ ba ngưng kết thành bánh xe khổng lồ mười vạn trượng. Phóng bánh xe đánh thẳng vào đại lục đang chạy trốn.","anchor":"Sinh tử trận, thành!"}]},"nguon":["@c1557"],"uyLuc":"Đạt cấp tinh vực, có thể phóng thẳng vào đại lục gây hủy diệt; bánh xe chuyển động tức diệt vong giáng xuống.","dacDiem":"Hình dạng bánh xe khổng lồ mười vạn trượng lơ lửng trên không, lấy hai dòng xoáy sinh tử dung hợp làm cốt lõi, ngưng kết bằng tâm thần huyết bước thứ ba."},{"id":"nhan-qua-dai-tran","name":"Nhân Quả đại trận","cn":"因果大阵","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Chưa rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Trận pháp thứ hai mà Vương Lâm định tạo sau Sinh Tử trận, cũng dùng đầu lâu và nguyên thần tu sĩ giới ngoại làm nguyên liệu. Chưa hoàn thành.","detail":"Vương Lâm sau khi hoàn thành Sinh Tử trận tiếp tục tàn sát thu thập đầu lâu để tạo trận pháp thứ hai — Nhân Quả đại trận. Số đầu lâu đợt hai đã đạt tới mấy vạn nhưng trận chưa hoàn thành.","congNang":["Trận pháp thứ hai trong kế hoạch tổng lực của Vương Lâm"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1557","tangDatToi":"Đang thu thập nguyên liệu","trangThai":"chua-hoan-thanh"}],"tabs":{"tienTrinh":[{"chuong":"@c1557","loai":"xuất hiện","importance":"normal","giaiDoan":"Đang thu thập nguyên liệu","text":"Vương Lâm đang tiếp tục tàn sát thu đầu lâu để tạo trận thứ hai Nhân Quả đại trận, số đầu lâu đã đạt mấy vạn nhưng chưa hoàn thành.","anchor":"tạo thành trận thứ hai, nhân quả đại trận!"}]},"nguon":["@c1557"]},{"id":"tinh-tran-gioi-noi","name":"Tinh trận giới nội (La Thiên)","cn":"","loai":"bi-thuat","loaiLabel":"Đại trận","phamCap":"Không rõ","hePhai":"Giới nội","soHuu":["Giới nội"],"blurb":"Đại trận phòng thủ do 990 tu chân tinh tuyển chọn từ tứ đại tinh vực tạo thành, là căn cơ cuối cùng bảo vệ giới nội tại La Thiên. Tới thời điểm ghi nhận, tu chân tinh giảm xuống chưa tới 300, đại trận đang trên bờ sụp đổ hoàn toàn.","detail":"Tinh trận giới nội là đại trận phòng thủ quy mô cực lớn tại La Thiên, được cấu thành bởi chín trăm chín mươi tu chân tinh lựa chọn từ tứ đại tinh vực, đóng vai trò là tuyến phòng ngự tối hậu của giới nội. Trong cuộc đối kháng với giới ngoại, tu sĩ giới nội nhiều lần định hủy tinh trận để đồng quy vu tận, kéo giới ngoại cùng chết, nhưng bị năm bậc toàn năng Không Huyền của giới ngoại ngăn cản. Tới thời điểm hiện tại, các tu chân tinh liên tục tổn hao, có tu chân tinh nổ tung ngay trước mắt, số lượng từ 990 giảm xuống chưa tới 300, khiến đại trận sắp sụp đổ hoàn toàn.","congNang":["Tạo thành đại trận phòng thủ bảo vệ giới nội tại La Thiên @c1558"],"trangThai":"sắp sụp đổ","capNhatToi":"@c1558","tabs":{"tienTrinh":[{"chuong":"@c1558","loai":"thi triển","importance":"major","giaiDoan":"Sụp đổ dần","text":"Tu chân tinh từ 990 giảm xuống chưa tới 300, một tu chân tinh nổ tung trước mắt. Tu sĩ giới nội mấy lần muốn đồng quy vu tận nhưng bị năm bậc Không Huyền giới ngoại ngăn cản.","anchor":"tu chân tinh nơi này đã không còn chín trăm chín mươi nữa mà chẳng còn tới ba trăm"}]},"nguon":["@c1558"],"uyLuc":"Là căn cơ cuối cùng của giới nội, đủ sức khiến năm bậc toàn năng Không Huyền giới ngoại phải chủ động ngăn cản việc hủy trận vì lo ngại đồng quy vu tận.","dacDiem":"Đại trận vận hành dựa trên tu chân tinh sống làm trận cơ; tu chân tinh tổn hao thì trận lực suy giảm tương ứng, khi số lượng tu chân tinh giảm quá thấp thì đại trận sẽ sụp đổ."},{"id":"thuat-song-tu-dao-phi-hu","name":"Thuật song tu của Đạo Phi Hủ","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Phi tộc giới ngoại","soHuu":["Đạo Phi Hủ"],"blurb":"Thần thông của Đạo Phi Hủ, am hiểu thuật song tu, dùng oan hồn nữ tử tạo thần thông công kích.","detail":"Đạo Phi Hủ am hiểu thuật song tu, dùng oan hồn nữ tử tạo thần thông để công kích màn sáng phòng thủ của Thần Tông.","congNang":["Dùng oan hồn nữ tử tạo thần thông công kích"],"nguoiTu":[{"ten":"Đạo Phi Hủ","tuChuong":"@c1559","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1559","loai":"thi-trien","importance":"normal","giaiDoan":"Công kích Thần Tông","text":"Đạo Phi Hủ dùng thuật song tu, dùng oan hồn nữ tử tạo thần thông công kích màn sáng tu chân tinh Thần Tông.","anchor":"am hiểu thuật song tu, tính cách tàn nhẫn"}]},"nguon":["@c1559"]},{"id":"phong-loi-than-thong-dai-han","name":"Phong lôi thần thông (đại hán toàn năng)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Giới ngoại","soHuu":["Đại hán hung tàn (bậc toàn năng giới ngoại)"],"blurb":"Thần thông phong lôi của đại hán toàn năng giới ngoại, một công kích tương đương mấy vạn tu sĩ toàn lực.","detail":"Đại hán giới ngoại ra tay phong lôi cuồn cuộn, hình thành vô số thiên lôi và cuồng phong. Uy lực cực lớn, một công kích có thể so với mấy vạn tu sĩ toàn lực đánh ra.","congNang":["Hình thành vô số thiên lôi và cuồng phong, một công kích bằng mấy vạn tu sĩ toàn lực"],"nguoiTu":[{"ten":"Đại hán hung tàn (bậc toàn năng giới ngoại)","tuChuong":"@c1559","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1559","loai":"thi-trien","importance":"normal","giaiDoan":"Phá màn sáng Côn Hư","text":"Đại hán dùng phong lôi cuồn cuộn phá tan màn sáng tu chân tinh nữ tử áo hồng.","anchor":"Một công kích của hắn có thể so với mấy vạn tu sĩ toàn lực đánh ra"}]},"nguon":["@c1559"]},{"id":"tinh-tran-chin-tram-chin-muoi","name":"Tinh trận 990 tu chân tinh","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Giới nội","soHuu":[],"blurb":"Tinh trận phòng thủ cuối cùng của giới nội, gồm 990 tu chân tinh tạo 990 tấm màn sáng dung hợp làm một.","detail":"Tinh trận vốn có 990 tu chân tinh tạo thành, mỗi tu chân tinh phát ra một tấm màn sáng, 990 tấm dung hợp tạo phản lực vô cùng đáng sợ. Khi tu chân tinh bị phá hủy, uy lực suy giảm dần.","congNang":["990 tấm màn sáng dung hợp tạo phản lực phòng thủ cực mạnh","Uy lực suy giảm khi mất tu chân tinh"],"tabs":{"tienTrinh":[{"chuong":"@c1559","loai":"thi-trien","importance":"normal","giaiDoan":"Bị giới ngoại tổng công kích","text":"Tinh trận phòng thủ cuối cùng giới nội bị đại quân giới ngoại tám hướng công kích, nhiều tu chân tinh liên tục bị phá hủy, uy lực màn sáng suy yếu.","anchor":"Tinh trận này vốn có chín trăm chín mươi tu chân tinh tạo thành"}]},"nguon":["@c1559"]},{"id":"phong-diet-toc-tam-menh-thuat","name":"Phong diệt tộc, tam mệnh thuật","cn":"封灭族三命术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Chưởng Tôn"],"blurb":"Tam mệnh thuật là thần thông bí truyền của Phong diệt tộc, cho phép người thi triển tái sinh sau khi thân thể bị hủy diệt hoàn toàn, cung điện gắn liền cũng được phục hồi theo.","detail":"Tam mệnh thuật được Chưởng Tôn của Phong diệt tộc thi triển sau khi bị mũi tên của Lý Quảng xuyên thấu, thân thể tan nát và cung điện thánh vật bị phá hủy. Thân thể hóa thành huyết nhục rồi quỷ dị ngưng tụ trở lại, cung điện cũng phục hồi nguyên trạng. Vương Lâm nhận ra thuật pháp này chính là tam mệnh thuật. @c1561","congNang":["Hồi sinh sau khi thân thể bị hủy diệt hoàn toàn, thân thể hóa huyết nhục rồi quỷ dị ngưng tụ tái sinh @c1561","Cung điện gắn liền với người thi triển cũng được phục hồi theo @c1561"],"nguoiTu":[{"ten":"Chưởng Tôn","tuChuong":"@c1561","tangDatToi":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1561","loai":"thi triển","importance":"major","giaiDoan":"Chưởng Tôn thi triển lần đầu","text":"Chưởng Tôn dùng tam mệnh thuật sau khi thân thể bị mũi tên xuyên thấu tan nát, tái sinh thành công cùng cung điện rồi lập tức bỏ trốn qua khe.","anchor":"Phong diệt tộc, tam mệnh thuật!"}]},"nguon":["@c1561"],"uyLuc":"Cho phép tái sinh ngay cả khi thân thể bị mũi tên xuyên thấu tan nát hoàn toàn, đồng thời phục hồi cả cung điện thánh vật đã bị phá hủy. @c1561"},{"id":"thai-so-quy-tac-chuong-ton","name":"Thái sơ quy tắc (Chưởng Tôn)","cn":"太初规则","loai":"than-thong","loaiLabel":"Quy tắc","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Chưởng Tôn"],"blurb":"Luồng thái sơ quy tắc bao phủ tinh vực khi Chưởng Tôn phun máu huyết mạch tiên nhân hóa mặt trời.","detail":"Khi Chưởng Tôn cắn lưỡi phun máu huyết mạch tiên nhân hóa thành mặt trời, có luồng thái sơ quy tắc bao phủ khắp tinh vực. Bị mũi tên Vương Lâm phá tan.","congNang":["Bao phủ tinh vực bằng quy tắc thái sơ cấp cao gắn liền mặt trời huyết mạch"],"tabs":{"tienTrinh":[{"chuong":"@c1561","loai":"thi triển","importance":"normal","giaiDoan":"Chưởng Tôn thi triển","text":"Chưởng Tôn phun máu huyết mạch tiên nhân hóa mặt trời tỏa thái sơ quy tắc bao phủ tinh vực, bị mũi tên Vương Lâm phá tan.","anchor":"Mặt trời này xuất hiện liền có một luồng thái sơ quy tắc bao phủ khắp tinh vực"}]},"nguon":["@c1561"]},{"id":"ngu-tang-thuat","name":"Ngũ tạng thuật","cn":"五臟術","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Thất Đạo Tông","soHuu":["Tiên phi (phi tử tông chủ Thất Đạo Tông)"],"blurb":"Thần thông thông qua cổ cầm phóng sóng âm, bắt quyết nhấn năm ngón tay ứng với tâm, can, tỳ, phế, thận khiến ngũ tạng đối phương vỡ vụn.","detail":"Tiên phi thi triển qua cổ cầm: gẩy đàn phóng sóng âm rồi bắt quyết nhấn năm ngón tay — tâm, can, tỳ, phế, thận — khiến ngũ tạng mục tiêu vỡ vụn. Từng khiến Vương Lâm thống khổ cực điểm (ngũ tạng khô héo hóa hắc thủy). Lần giao chiến tại quyết chiến, Vương Lâm dùng thân thể Cổ Thần ngạnh kháng, dù ngũ tạng vỡ vụn vẫn tiếp tục tiến công, khiến thần thông này mất hiệu quả.","nguon":["@c1563"],"tabs":{"tienTrinh":[{"chuong":"@c1563","loai":"thi triển","importance":"normal","giaiDoan":"Quyết chiến giới ngoại","text":"Tiên phi thi triển ngũ tạng thuật qua cổ cầm nhằm vào Vương Lâm nhưng bị ngạnh kháng bằng thân thể Cổ Thần, không còn hiệu quả như trước.","anchor":"Ngũ tạng thuật, tâm, can, tỳ, phế, thận!"}]}},{"id":"tran-phap-tam-dai-bon-nguyen","name":"Trận pháp Tam Đại Bổn Nguyên","cn":"三大本源阵法","aliases":["Sinh Tử Nhân Quả Chân Giả đại trận","Bánh xe tam đại bổn nguyên"],"loai":"than-thong","loaiLabel":"Thần thông / Trận pháp","phamCap":"Tối thượng (tự sáng tạo, độc nhất)","hePhai":"Tam đại hư bổn nguyên","soHuu":["Vương Lâm"],"blurb":"Trận pháp Tam Đại Bổn Nguyên là thần thông mạnh nhất do Vương Lâm tự sáng tạo, chồng ba bánh xe Sinh Tử, Chân Giả, Nhân Quả thành một trận pháp duy nhất. Cả đời chỉ ngưng tụ được một lần, cần một vạn nguyên thần làm trận linh mới phát huy toàn lực, uy lực đủ quét sạch hơn mười vạn tu sĩ trong phạm vi toàn bộ La Thiên.","detail":"Trận pháp do Vương Lâm tự sáng tạo, gồm ba đại trận chồng lên nhau: Sinh Tử trận, Nhân Quả trận và Chân Giả Đại trận, mỗi trận dùng đầu lâu tạo thành bánh xe. Khi vận hành, bánh xe bành trướng sánh ngang bầu trời, thay đổi quỹ đạo thiên địa tinh không, nhiễu loạn vận chuyển tinh thần, giết sạch mọi kẻ không thuộc giới nội trong phạm vi trận pháp. Trận pháp cần một vạn nguyên thần tọa trấn làm trận linh mới có thể vận chuyển. Khi khai trận, bánh xe quay bốn vòng, quét sạch hơn mười vạn tu sĩ giới ngoại, giết cả tu sĩ cảnh giới Không Huyền, khiến tinh không thực sự sụp đổ. Sau khi sử dụng, Vương Lâm cùng toàn bộ người hiến nguyên thần đều trọng thương. Đây là trận pháp cả đời chỉ ngưng tụ được một lần duy nhất, tuyệt đối không thể tạo ra cái thứ hai.","thuocTinh":"Sinh Tử, Chân Giả, Nhân Quả (tam đại hư bổn nguyên)","nguonGoc":"Vương Lâm tự sáng tạo","yeuCau":"Tam đại hư bổn nguyên + gần mười vạn đầu lâu + một vạn nguyên thần làm trận linh","uyLuc":"Bánh xe quay bốn vòng quét sạch hơn mười vạn tu sĩ giới ngoại trong phạm vi cả La Thiên, giết cả tu sĩ cảnh giới Không Huyền, khiến tinh không thực sự sụp đổ.","dacDiem":"Cả đời chỉ ngưng tụ được một lần duy nhất, tuyệt đối không thể có cái thứ hai; cần một vạn nguyên thần tọa trấn làm trận linh mới vận chuyển được; sau khi sử dụng, bản thân và toàn bộ người hiến nguyên thần đều trọng thương.","trangThai":"Đã dùng, không thể tái tạo","capNhatToi":"@c1565","congNang":["Thay đổi quỹ đạo thiên địa tinh không, nhiễu loạn vận chuyển tinh thần @c1565","Diệt tất cả kẻ thù trong phạm vi cực rộng, bao trùm toàn bộ La Thiên @c1565","Phá tan tinh trận, chấn vỡ thân thể tu sĩ bất kể ở đâu trong phạm vi trận pháp @c1565"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1565","tangDatToi":"Sáng tạo và thi triển","trangThai":"Đã dùng hết, trọng thương"}],"tabs":{"tienTrinh":[{"chuong":"@c1565","loai":"xuat-hien","importance":"major","giaiDoan":"Thi triển duy nhất","text":"Vương Lâm chồng ba bánh xe Sinh Tử, Chân Giả, Nhân Quả thành trận pháp tam đại bổn nguyên, một vạn tu sĩ giới nội hiến nguyên thần làm trận linh, bánh xe quay bốn vòng quét sạch hơn mười vạn tu sĩ giới ngoại trong La Thiên, tinh không sụp đổ. Sau trận toàn bộ trọng thương, bánh xe không thể tái tạo.","anchor":"Đây là thần thông mạnh nhất trong số những thần thông Vương Lâm tự nghĩ ra"}]},"nguon":["@c1565"]},{"id":"nhan-qua-tran","name":"Nhân Quả trận","cn":"因果阵","loai":"than-thong","loaiLabel":"Trận pháp","soHuu":["Vương Lâm"],"blurb":"Một trong ba thành phần của Trận pháp Tam Đại Bổn Nguyên. Năm vạn đầu lâu tạo dòng xoáy rồi trở thành bánh xe bất động.","detail":"Năm vạn đầu lâu tạo thành dòng xoáy rồi ngưng tụ thành bánh xe bất động, mang khí tức Nhân Quả bổn nguyên. Là một trong ba bánh xe được chồng lên nhau trong trận pháp tam đại bổn nguyên.","nguon":["@c1565"]},{"id":"chan-gia-dai-tran","name":"Chân Giả Đại trận","cn":"真假大阵","loai":"than-thong","loaiLabel":"Trận pháp","soHuu":["Vương Lâm"],"blurb":"Một trong ba thành phần của Trận pháp Tam Đại Bổn Nguyên. Năm vạn đầu lâu tạo dòng xoáy luôn thay đổi giữa thật và giả, tỏa khí tức Chân Giả bổn nguyên.","detail":"Năm vạn đầu lâu còn lại tạo dòng xoáy mơ hồ vặn vẹo, luôn thay đổi giữa thật và giả, như không tồn tại, tỏa khí tức Chân Giả bổn nguyên. Là một trong ba bánh xe được chồng lên nhau trong trận pháp tam đại bổn nguyên.","nguon":["@c1565"]},{"id":"nhan-qua-truu-linh","name":"Nhân Quả trừu linh","cn":"因果抽灵","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Nhân Quả","soHuu":["Vương Lâm"],"blurb":"Nhân Quả trừu linh là chiêu thức dựa trên Nhân Quả ấn, vận dụng Nhân Quả lực để rút trận linh ra khỏi trận pháp rồi hủy diệt hoàn toàn. Tại chương 1568, Vương Lâm thi triển chiêu thức này để lần lượt rút ra và hủy diệt cả bảy trận linh của Phong Giới Đại Trận, khiến đại trận sụp đổ.","detail":"Nhân Quả trừu linh là phương thức ứng dụng Nhân Quả ấn vào việc phá trận. Khi thi triển, người dùng nhấn Nhân Quả ấn, nắm quyền kéo lại, dùng Nhân Quả lực liên kết với trận linh — cốt lõi duy trì trận pháp — rồi cưỡng chế rút chúng ra ngoài và hủy diệt. Vương Lâm đã sử dụng chiêu thức này trước Phong Giới Đại Trận, lần lượt rút ra bảy trận linh; mỗi trận linh bị rút ra đều bị hủy diệt hoàn toàn, dẫn tới việc đại trận tan rã.","congNang":["Dùng Nhân Quả lực rút trận linh — cốt lõi của trận pháp — ra khỏi trận pháp @c1568","Hủy diệt hoàn toàn trận linh sau khi rút ra @c1568","Phá hủy trận pháp bằng cách loại bỏ toàn bộ trận linh duy trì nó @c1568"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1568","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1568","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm dùng Nhân Quả trừu linh lần lượt rút ra và hủy diệt bảy trận linh của Phong Giới Đại Trận, khiến trận pháp sụp đổ hoàn toàn.","anchor":"Nhân Quả trừu linh!"}]},"nguon":["@c1568"],"uyLuc":"Lần lượt rút ra và hủy diệt cả bảy trận linh của Phong Giới Đại Trận, khiến đại trận sụp đổ hoàn toàn.","dacDiem":"Chiêu thức phá trận dựa trên Nhân Quả ấn, không tấn công trực diện trận pháp mà nhắm thẳng vào trận linh — gốc rễ duy trì trận pháp — để cưỡng chế rút ra bằng Nhân Quả lực rồi hủy diệt."},{"id":"huyen-kiep","name":"Huyền kiếp","cn":"玄劫","loai":"khac","loaiLabel":"Cơ chế thăng cấp / Kiếp nạn","phamCap":"","hePhai":"","soHuu":[],"blurb":"Kiếp nạn giữa Không Huyền và Không Kiếp, chia làm chín lần. Vượt qua cả chín lần thành Không Kiếp đại tôn, đỉnh phong bước thứ ba.","detail":"Khi chín đạo bổn nguyên dung hợp thành lực lượng gọi là Không thì phải đối mặt đại kiếp thứ ba — huyền kiếp. Thành thì sinh bại thì tử, không ai ngoại lệ. Vượt qua chín lần huyền kiếp thành Không Kiếp đại tôn, nửa bước nữa có thể đạp không.","congNang":["Cửa ải bắt buộc từ Không Huyền lên Không Kiếp, chia 9 lần, thành thì sinh bại thì tử"],"nguon":["@c1568"]},{"id":"tran-phap-vo-danh","name":"Trận pháp Vô Danh","cn":"无名阵法","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Siêu cấp (thay thế Phong Giới Đại Trận)","hePhai":"Giới nội","soHuu":["Vương Lâm"],"blurb":"Trận pháp Vô Danh là đại trận do Vương Lâm đích thân kiến lập sau khi phá hủy Phong Giới Đại Trận, lấy bánh xe tam đại bổn nguyên làm cốt lõi, bao phủ toàn bộ tứ đại tinh vực giới nội. Trận pháp dung hợp linh hồn pháp bảo tan nát, tinh hồn tu chân tinh bị hủy diệt cùng thiên thạch và đại lục vỡ nát, thay thế hoàn toàn vai trò ngăn cách giới nội với giới ngoại, đồng thời mở ra thời đại mới cho tu sĩ giới nội.","detail":"Sau trăm năm chiến tranh giữa giới nội và giới ngoại, Vương Lâm phá hủy Phong Giới Đại Trận và lập nên trận pháp Vô Danh thay thế. Cốt lõi trận pháp là bánh xe do tam đại bổn nguyên biến thành, được khuếch trương tới vô tận. Khác với tiền thân, trận pháp này dung hợp linh hồn của vô số pháp bảo đã tan nát trong chiến tranh, tinh hồn của tu chân tinh bị hủy diệt, cùng thiên thạch và đại lục vỡ nát, khiến kết cấu trận pháp trở nên thực chất với uy áp vượt thiên địa. Trên trăm vạn tàn hồn tu sĩ giới ngoại bị phong ấn bên trong trận pháp, bị bắt làm nô lệ đẩy bánh xe đời đời kiếp kiếp để chuộc tội, đồng thời xử lý vấn đề oán khí từng gây tâm ma cho tu sĩ giới nội dưới hệ thống cũ. Điểm khác biệt then chốt so với Phong Giới Đại Trận là trận pháp Vô Danh không cản trở khí tức Thái Cổ Tinh Thần t","congNang":["Ngăn cách giới nội với giới ngoại, thay thế hoàn toàn chức năng của Phong Giới Đại Trận @c1570","Cho phép khí tức Thái Cổ Tinh Thần xuyên qua tràn vào giới nội, xóa bỏ vòng tuần hoàn ác tính @c1570","Phong ấn trên trăm vạn tàn hồn tu sĩ giới ngoại bên trong trận pháp, bắt làm nô lệ đẩy bánh xe vĩnh viễn để chuộc tội @c1570","Loại bỏ oán khí gây tâm ma cho tu sĩ giới nội thông qua cơ chế phong ấn tàn hồn @c1570"],"nguonGoc":"Do Vương Lâm lập sau khi phá hủy Phong Giới Đại Trận","dacDiem":"Cốt lõi là bánh xe tam đại bổn nguyên được khuếch trương tới vô tận, dung hợp linh hồn pháp bảo tan nát trong chiến tranh, tinh hồn tu chân tinh bị hủy diệt, cùng thiên thạch và đại lục vỡ nát. Khác với Phong Giới Đại Trận, không ngăn cản khí tức Thái Cổ Tinh Thần, được dự kiến tồn tại lâu dài hơn t","trangThai":"đang hoạt động","capNhatToi":"@c1570","tabs":{"tienTrinh":[{"chuong":"@c1570","loai":"xuất hiện","importance":"major","giaiDoan":"Lập trận","text":"Vương Lâm lập trận pháp Vô Danh thay thế Phong Giới Đại Trận, dùng bánh xe tam đại bổn nguyên khuếch trương vô tận bao phủ tứ đại tinh vực, dung hợp linh hồn pháp bảo và tinh hồn tu chân tinh, phong ấn trên trăm vạn tàn hồn giới ngoại đẩy bánh xe chuộc tội vĩnh viễn.","anchor":"Trận pháp này chính là một bánh xe lớn vô cùng. Nó tồn tại sẽ còn lâu hơn Phong Giới Đại Trận, mở ra một thời đại mới!"}]},"nguon":["@c1570"],"uyLuc":"Uy áp vượt thiên địa, dung hợp linh hồn pháp bảo, tinh hồn tu chân tinh, thiên thạch và đại lục vỡ nát thành kết cấu thực chất, phong ấn trên trăm vạn tàn hồn tu sĩ giới ngoại đẩy bánh xe đời đời kiếp kiếp."},{"id":"vo-danh-chuyen-luan-tran","name":"Vô Danh Chuyển Luân trận","cn":"無名轉輪陣","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Chưa rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Trận pháp do Vương Lâm khai mở, dùng tam đại bổn nguyên biến thành bánh xe, anh hồn giới nội làm trận linh, tàn hồn giới ngoại bị nô dịch đẩy bánh xe vận chuyển.","detail":"Vương Lâm dùng tam đại bổn nguyên biến thành bánh xe, vô tận anh hồn giới nội nội bái Vương Lâm rồi nhập vào bánh xe trở thành trận linh, tàn hồn tu sĩ giới ngoại bị nô dịch đẩy bánh xe. Trận pháp tỏa ánh sáng nhu hòa với giới nội nhưng chói mắt đau nhức với giới ngoại. Chức năng chính: ngăn tu sĩ có ấn ký thái cổ trên mi tâm xâm nhập giới nội, nhưng cho phép người giới nội qua trận pháp tới giới ngoại; cho phép khí tức Thái Cổ Tinh Thần tràn vào giới nội, giải phóng tu sĩ giới nội khỏi hạn chế tế luyện hương hỏa. Tu sĩ giới ngoại chậm chân bị trận pháp hút nguyên thần và linh hồn biến thành nô dịch. Giới nội ban đầu mở rộng hai phần, nhờ hồn phách phàm nhân vô tội dung nhập khuếch trương lên ba phần, rồi khi Vương Lâm tự dung nhập trận pháp làm trận linh thì mở rộng tới bốn phần. Vương Lâm ngồi trên Thiên Hoàng Lô trước lỗ hổng Vân Hải tinh vực, nhắm mắt bảo vệ trận pháp ba năm. Trận pháp cũng đưa vào giới nội nhiều tu chân tinh không chỉ có phàm nhân, tạo sinh cơ cho giới nội.","nguon":["@c1572"]},{"id":"vien-co-bi-chieu","name":"Viễn cổ bí chiếu","cn":"遠古秘詔","loai":"khac","loaiLabel":"Bí thuật","phamCap":"Chưa rõ","hePhai":"Trường Tôn hội","soHuu":["Chưởng Tôn"],"blurb":"Bí chiếu cất trong bảo khố Trường Tôn hội, cần dùng máu mười vạn tu sĩ để viết.","detail":"Chưởng Tôn ra lệnh mở bảo khố của Trường Tôn hội lấy viễn cổ bí chiếu, dùng máu mười vạn tu sĩ viết chiếu viễn cổ. Chi tiết công năng cụ thể chưa được tiết lộ, được huy động trong chiến dịch phá trận giới nội.","nguon":["@c1572"]},{"id":"tran-phap-vo-hinh-chin-dai-luc","name":"Trận pháp vô hình chín đại lục","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Trận pháp vô hình bao bọc chín đại lục trôi nổi trong Thái Cổ Tinh Thần, chỉ người có huyết mạch tiên nhân mới nhìn thấy.","detail":"Trận pháp ẩn giấu chín đại lục, ngăn thần thức phát hiện. Người không có huyết mạch tiên nhân căn bản không thể nhìn thấy chín đại lục này.","congNang":["Ẩn giấu chín đại lục khỏi mọi thần thức, chỉ người có huyết mạch tiên nhân mới phát hiện"],"tabs":{"tienTrinh":[{"chuong":"@c1573","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ diện","text":"Chưởng Tôn tới chín đại lục, trận pháp vô hình che giấu nơi này được nhắc tới — chỉ người có huyết mạch tiên nhân mới nhìn thấy.","anchor":"nếu không phải là người có huyết mạch tiên nhân thì căn bản không thể nhìn thấy"}]},"nguon":["@c1573"]},{"id":"vien-co-thuat-hop-nhat-nguyen-than","name":"Viễn cổ thuật hợp nhất nguyên thần","cn":"","aliases":["Đại kiếm vạn trượng"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Viễn cổ bí thuật","hePhai":"Trường Tôn hội","soHuu":["Lão già tóc bạc (giới ngoại)"],"blurb":"Bí thuật viễn cổ do Trường Tôn hội truyền xuống, năm toàn năng dung hợp lực lượng theo hàng chữ nhất, ngưng tụ mười vạn nguyên thần thành đại kiếm vạn trượng chém một kích.","detail":"Năm bậc toàn năng bước thứ ba sắp hàng chữ nhất, lần lượt dung hợp lực lượng truyền về phía trước. Người đứng đầu thi triển viễn cổ thuật, ngón tay hóa đại kiếm vạn trượng, mười vạn nguyên thần dung nhập vào kiếm tạo khí thế vô thượng. Tuy nhiên khi chém xuống Vô Danh Chuyển Luân trận, bị phản lực từ oan hồn quay bánh xe đánh bật vỡ tan.","nguonGoc":"Bí thuật Trường Tôn hội truyền từ viễn cổ","thuocTinh":"Dung hợp nguyên thần","uyLuc":"Khí thế vô thượng nhưng không đủ phá Vô Danh Chuyển Luân trận, bị phản lực đánh bật","congNang":["Ngưng tụ lực lượng năm toàn năng cùng mười vạn nguyên thần thành một đại kiếm chém xuống"],"nguoiTu":[{"ten":"Lão già tóc bạc (giới ngoại)","tuChuong":"@c1574","tangDatToi":"","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1574","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển lần đầu","text":"Lão già tóc bạc dẫn năm toàn năng dung hợp lực lượng, thi triển viễn cổ thuật tạo đại kiếm vạn trượng dung nhập mười vạn nguyên thần chém xuống Vô Danh Chuyển Luân trận nhưng bị phản lực đánh bật vỡ tan.","anchor":"Nhưng có mười vạn nguyên thần kia phụ trợ, có bí thuật Trường Tôn hội truyền xuống từ viễn cổ"}]},"nguon":["@c1574"]},{"id":"hien-te-tho-nguyen-trieu-hoi-anh-sang-vien-co","name":"Hiến tế thọ nguyên triệu hồi ánh sáng viễn cổ","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Viễn cổ bí thuật","hePhai":"Giới ngoại","soHuu":["Lão già tóc bạc (giới ngoại)"],"blurb":"Bí thuật viễn cổ cực đoan có liên hệ tới Tiên Cương đại lục: mười vạn tu sĩ giới ngoại hiến tế toàn bộ thọ nguyên, nguyên thần dung hợp thành hắc động, triệu hồi ánh sáng viễn cổ tiên tôn mang khí tức Tiên Cương — kim quang có thể tạo chúng sinh hoặc hủy diệt thiên linh, uy lực đủ sức uy hiếp Vô Danh Chuyển Luân trận.","detail":"Đây là bí thuật xuất xứ từ viễn cổ, có mối liên hệ với Tiên Cương đại lục. Khi thi triển, mười vạn tu sĩ đồng loạt thổ huyết hiến tế toàn bộ thọ nguyên — người trẻ lập tức già đi, người già càng thêm cỗi hạc. Mười vạn nguyên thần điên cuồng dung hợp thành sương mù dày đặc, biến thành dòng xoáy khổng lồ như hắc động thông sang thế giới khác. Từ trong hắc động xuất hiện ánh sáng màu vàng kim mang khí tức của Tiên Cương đại lục, được gọi là ánh sáng của viễn cổ tiên tôn. Ánh sáng này mang lưỡng diện tính: có thể tạo chúng sinh, cũng có thể hủy diệt thiên linh. Khi đối đầu Vô Danh Chuyển Luân trận, kim quang viễn cổ khiến bánh xe tam đại bổn nguyên sững lại, oan hồn trong trận sắp tiêu tán, Chưởng Tôn tự nhận rằng đối kháng cũng phải cố sức. Cuối cùng bị Vương Lâm dùng Phần Giới Cổ Tán kết hợp","nguonGoc":"Bí thuật viễn cổ, liên hệ Tiên Cương đại lục","thuocTinh":"Hiến tế thọ nguyên, triệu hồi ánh sáng","uyLuc":"Cực mạnh — kim quang viễn cổ suýt phá Vô Danh Chuyển Luân trận, khiến bánh xe tam đại bổn nguyên sững lại và oan hồn sắp tiêu tán; Chưởng Tôn tự nhận đối kháng cũng phải cố sức. Bị Vương Lâm dùng Phần Giới Cổ Tán kết hợp trường thương bảy màu phá giải.","dacDiem":"Đại giá cực đoan: đòi hỏi toàn bộ thọ nguyên của mười vạn tu sĩ, nguyên thần dung hợp thành hắc động làm trung gian triệu hồi; ánh sáng mang lưỡng diện tính tạo sinh và hủy diệt, khí tức thuộc về Tiên Cương đại lục viễn cổ.","congNang":["Mười vạn tu sĩ hiến tế toàn bộ thọ nguyên, nguyên thần dung hợp thành hắc động thông tới thế giới khác @c1574","Triệu hồi kim quang viễn cổ tiên tôn mang khí tức Tiên Cương đại lục từ hắc động @c1574","Ánh sáng viễn cổ có thể tạo chúng sinh hoặc hủy diệt thiên linh","Khiến bánh xe tam đại bổn nguyên của Vô Danh Chuyển Luân trận sững lại, oan hồn trong trận sắp tiêu tán"],"nguoiTu":[{"ten":"Lão già tóc bạc (giới ngoại)","tuChuong":"@c1574","tangDatToi":"","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1574","loai":"thi triển","importance":"major","giaiDoan":"Thi triển lần đầu","text":"Mười vạn tu sĩ giới ngoại hiến tế toàn bộ thọ nguyên, nguyên thần dung hợp thành hắc động triệu hồi kim quang viễn cổ từ Tiên Cương đại lục, suýt phá Vô Danh Chuyển Luân trận nhưng bị Vương Lâm dùng Phần Giới Cổ Tán và trường thương bảy màu phá giải.","anchor":"Lấy thọ nguyên của mười vạn tu sĩ này biến thành thần thông, cho dù lão phu muốn đối kháng cũng phải cố sức"}]},"nguon":["@c1574"]},{"id":"truong-thuong-bay-mau","name":"Trường thương bảy màu","cn":"","aliases":["Thất thải chỉ đạo"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Vương Lâm triệu xuất bảy sắc ánh sáng (Xích, Chanh, Hồng, Lục, Lam, Thanh, Tử) từ tinh không hư vô ngưng tụ thành trường thương, ẩn chứa biến ảo thiên địa, dùng phá nát ánh sáng viễn cổ.","detail":"Bảy sắc ánh sáng từ tinh không hư vô ngưng tụ thành trường thương bảy màu, kết hợp với Phần Giới Cổ Tán để phá tan ánh sáng viễn cổ tiên tôn và bịt kín bằng hỏa tán diệt giới.","thuocTinh":"Thất thải (bảy sắc)","uyLuc":"Phá nát được ánh sáng viễn cổ tiên tôn mang khí tức Tiên Cương đại lục","dacDiem":"Bảy sắc, ẩn chứa biến ảo của thiên địa","congNang":["Phá thiên, nổ nát ánh sáng viễn cổ khi kết hợp Phần Giới Cổ Tán"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1574","tangDatToi":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1574","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển lần đầu","text":"Vương Lâm triệu xuất bảy sắc ánh sáng từ tinh không ngưng tụ trường thương bảy màu, kết hợp Phần Giới Cổ Tán phá nát ánh sáng viễn cổ kim quang.","anchor":"Thất thải chỉ đạo, ẩn chứa biến ảo của thiên địa"}]},"nguon":["@c1574"]},{"id":"co-toc-chien-an","name":"Cổ tộc Chiến Ấn","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Chí cao vô thượng trong tam tộc cổ","hePhai":"Tam tộc cổ (Cổ quốc)","soHuu":["Nam tử trung niên (chín quan tài)","Vương Lâm"],"blurb":"Cổ tộc Chiến Ấn là ấn ký truyền thừa chí cao vô thượng trong tam tộc cổ thuộc cổ quốc, khi thi triển sẽ ép đối phương bước vào trận đấu sanh tử, kẻ thua mất toàn bộ sở hữu về tay kẻ thắng, lấy cổ tổ làm chứng. Ấn ký này không mang lực công kích mà là dấu ấn tượng trưng hiến tế lên cổ tổ, mang tính nghi thức và ràng buộc tuyệt đối.","detail":"Cổ tộc Chiến Ấn có nguồn gốc từ trí nhớ truyền thừa Đạo cổ, là ấn ký truyền thừa trong tam tộc cổ của cổ quốc. Khi một thành viên cổ tộc bắt quyết tay phải rồi ấn vào ngực mình, dấu ấn được kích hoạt và chỉ vào đối phương, buộc đối phương phải tiếp nhận trận đấu sanh tử. Kẻ thắng đoạt toàn bộ sở hữu của kẻ thua, và toàn bộ giao ước này lấy cổ tổ làm chứng giám. Nếu tu vi hai bên chênh lệch quá lớn, phía yếu hơn có thể tránh né, nhưng trong trường hợp tu vi tương đương mà không dám ứng chiến thì sẽ bị coi là kẻ yếu, mang nhục nhã lớn. Tại @c1577, một nam tử trung niên đã dùng Cổ tộc Chiến Ấn khiêu chiến Vương Lâm, ép vào thế đấu sanh tử; Vương Lâm nhận ra ấn ký này nhờ trí nhớ truyền thừa Đạo cổ.","thuocTinh":"Nghi thức chiến đấu sanh tử","nguonGoc":"Ấn ký truyền thừa trong tam tộc cổ (cổ quốc), thuộc trí nhớ truyền thừa Đạo cổ","congNang":["Ép đối phương bước vào trận đấu sanh tử, không thể từ chối khi tu vi tương đương @c1577","Kẻ thắng đoạt toàn bộ sở hữu của kẻ thua @c1577","Lấy cổ tổ làm chứng giám cho giao ước sinh tử @c1577","Bản thân ấn ký không có lực công kích, là dấu ấn tượng trưng hiến tế lên cổ tổ @c1577"],"nguoiTu":[{"ten":"Nam tử trung niên (chín quan tài)","tuChuong":"@c1577","tangDatToi":"","trangThai":"dang-dung"},{"ten":"Vương Lâm","tuChuong":"@c1577","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1577","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện và thi triển","text":"Nam tử trung niên dùng Cổ tộc Chiến Ấn khiêu chiến Vương Lâm, ép đấu sanh tử. Vương Lâm nhận ra ấn ký từ trí nhớ truyền thừa Đạo cổ, đáp lại bằng Chiến Ấn chấp nhận trận đấu.","anchor":"Nó là một ấn ký khi cổ tộc giao chiến phải hiến tế lên"}]},"nguon":["@c1577"],"dacDiem":"Thi triển bằng cách bắt quyết tay phải rồi ấn vào ngực; không mang sát thương trực tiếp mà là nghi thức ràng buộc sinh tử mang tính tuyệt đối, thuộc trí nhớ truyền thừa Đạo cổ trong tam tộc cổ."},{"id":"co-yeu-thon-thien","name":"Cổ Yêu thôn thiên","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cổ tộc (Cổ Yêu)","soHuu":["Nam tử trung niên (chín quan tài)"],"blurb":"Thần thông cổ tộc hệ Cổ Yêu, triệu hư ảnh Cổ Yêu chín yêu tinh mở miệng thôn phệ đối phương.","detail":"Nam tử trung niên thi triển: ba yêu tinh từ mắt trái hóa ba giọt máu, biến thành hư ảnh Cổ Yêu chín yêu tinh, mở miệng thôn phệ Vương Lâm.","congNang":["Triệu hư ảnh Cổ Yêu chín yêu tinh thôn phệ đối phương"],"nguoiTu":[{"ten":"Nam tử trung niên (chín quan tài)","tuChuong":"@c1578","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1578","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Nam tử trung niên triệu ba yêu tinh từ mắt trái hóa ba giọt máu, biến thành hư ảnh Cổ Yêu chín yêu tinh thôn phệ Vương Lâm.","anchor":"Mắt trái của nam tử trung niên liền lóe lên ba yêu tinh, bất ngờ hóa thành ba giọt máu"}]},"nguon":["@c1578"]},{"id":"co-ma-phe-dia","name":"Cổ Ma phệ địa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cổ tộc (Cổ Ma)","soHuu":["Nam tử trung niên (chín quan tài)"],"blurb":"Thần thông cổ tộc hệ Cổ Ma, triệu hư ảnh Cổ Ma khổng lồ bộc phát ma khí tinh thuần uy hiếp thiên địa.","detail":"Ba ma tinh từ mắt phải nam tử trung niên biến thành ba giọt máu, bộc phát ma khí tinh thuần, hóa hư ảnh Cổ Ma khổng lồ.","congNang":["Triệu hư ảnh Cổ Ma bộc phát ma khí uy hiếp thiên địa"],"nguoiTu":[{"ten":"Nam tử trung niên (chín quan tài)","tuChuong":"@c1578","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1578","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Ba ma tinh từ mắt phải nam tử trung niên biến thành ba giọt máu, bộc phát ma khí tinh thuần hóa hư ảnh Cổ Ma khổng lồ.","anchor":"Trong mắt phải của nam tử trung niên lại bay ra ba ma tinh, biến thành ba giọt máu"}]},"nguon":["@c1578"]},{"id":"co-than-noi-gian","name":"Cổ Thần nổi giận","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cổ tộc (Cổ Thần)","soHuu":["Nam tử trung niên (chín quan tài)"],"blurb":"Thần thông cổ tộc hệ Cổ Thần, triệu hồi hư ảnh Cổ Thần trong trạng thái nổi giận.","detail":"Hai tinh điểm Cổ Thần trên mi tâm nam tử trung niên lóe sáng, triệu hư ảnh Cổ Thần mang vẻ giận dữ.","congNang":["Triệu hư ảnh Cổ Thần trạng thái nổi giận"],"nguoiTu":[{"ten":"Nam tử trung niên (chín quan tài)","tuChuong":"@c1578","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1578","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Hai tinh điểm Cổ Thần trên mi tâm nam tử trung niên lóe sáng, triệu hư ảnh Cổ Thần giận dữ.","anchor":"Hai tinh điểm cổ Thần trên mi tâm của nam tử trung niên lúc này lóe lên"}]},"nguon":["@c1578"]},{"id":"phu-than-dao-co-ngung-hoa-co-anh","name":"Phụ thần Đạo cổ, ngưng hóa cổ ánh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cổ tộc (Tam tộc cổ + Đạo cổ)","soHuu":["Nam tử trung niên (chín quan tài)"],"blurb":"Đại thần thông cổ tộc do nam tử trung niên (tự xưng con trai Đạo Cổ Diệp Mịch) thi triển, hợp nhất hư ảnh tam tộc cổ (Cổ Thần, Cổ Yêu, Cổ Ma) rồi triệu hoán thêm hư ảnh Đạo Cổ Diệp Mịch khổng lồ hơn tất cả để phát động tổng công kích.","detail":"Tại @c1578, nam tử trung niên tự xưng là con trai của Đạo Cổ Diệp Mịch, kết hợp hư ảnh tam tộc cổ — Cổ Thần, Cổ Yêu, Cổ Ma — thành một thể thống nhất, sau đó triệu thêm hư ảnh Đạo Cổ Diệp Mịch có kích thước khổng lồ vượt trội tất cả hư ảnh trước đó, dùng toàn bộ lực lượng này để tổng công kích Vương Lâm. Chiêu thức mang danh nghĩa \"Phụ thần Đạo cổ, ngưng hóa cổ ánh\", thể hiện mối liên hệ huyết mạch giữa người thi triển và Đạo Cổ Diệp Mịch, đồng thời quy tụ uy thế của cả ba tộc cổ vào một đòn duy nhất.","congNang":["Hợp nhất hư ảnh tam tộc cổ (Cổ Thần, Cổ Yêu, Cổ Ma) thành một thể thống nhất @c1578","Triệu hoán hư ảnh Đạo Cổ Diệp Mịch khổng lồ vượt trội tất cả hư ảnh khác @c1578","Phát động tổng công kích bằng toàn bộ lực lượng hư ảnh đã hợp nhất @c1578"],"nguoiTu":[{"ten":"Nam tử trung niên (chín quan tài)","tuChuong":"@c1578","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1578","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Nam tử trung niên kết hợp hư ảnh tam tộc cổ rồi triệu thêm hư ảnh Đạo Cổ Diệp Mịch khổng lồ, tự xưng con trai Đạo cổ đòi thu hồi truyền thừa, dùng toàn bộ lực lượng tổng công kích Vương Lâm.","anchor":"Phụ thần Đạo cổ, ngưng hóa cổ ánh!"}]},"nguon":["@c1578"],"dacDiem":"Chiêu thức gắn liền với thân phận huyết mạch của người thi triển (con trai Đạo Cổ Diệp Mịch), quy tụ sức mạnh tam tộc cổ và hư ảnh Đạo Cổ vào một đòn tổng lực duy nhất."}]};
